-- Poems batch 463
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-88','越燕二首','李商隱','唐','御定全唐诗','yuding','','[]','上國社方見，此鄉秋不歸。為矜皇后舞，猶著羽人衣。',96,'御定全唐詩/json/539.json','["上國社方見，此鄉秋不歸。為矜皇后舞，猶著羽人衣。", "拂水斜紋亂，銜花片影微。盧家文杏好，試近莫愁飛。", "將泥紅蓼岸，得草綠楊村。命侶添新意，安巢復舊痕。", "去應逢阿母，來莫害王孫。記取丹山鳳，今為百鳥尊。"]'),
('yuding-89','杜工部蜀中離席','李商隱','唐','御定全唐诗','yuding','','[]','人生何處不離群，世路干戈惜暫分。雪嶺未歸天外使，',40,'御定全唐詩/json/539.json','["人生何處不離群，世路干戈惜暫分。雪嶺未歸天外使，", "美酒成都堪送老，當壚仍是卓文君。"]'),
('yuding-90','隋宮','李商隱','唐','御定全唐诗','yuding','','[]','紫泉宮殿鎖煙霞，欲取蕪城作帝家。玉璽不緣歸日角，',40,'御定全唐詩/json/539.json','["紫泉宮殿鎖煙霞，欲取蕪城作帝家。玉璽不緣歸日角，", "地下若逢陳後主，豈宜重問後庭花。"]'),
('yuding-91','二月二日','李商隱','唐','御定全唐诗','yuding','','[]','二月二日江上行，東風日暖聞吹笙。花須柳眼各無賴，',40,'御定全唐詩/json/539.json','["二月二日江上行，東風日暖聞吹笙。花須柳眼各無賴，", "新灘莫悟遊人意，更作風簷夜雨聲。"]'),
('yuding-92','籌筆驛','李商隱','唐','御定全唐诗','yuding','','[]','猿鳥猶疑畏簡書，風雲常為護儲胥。徒令上將揮神筆，',40,'御定全唐詩/json/539.json','["猿鳥猶疑畏簡書，風雲常為護儲胥。徒令上將揮神筆，", "他年錦裏經祠廟，梁父吟成恨有餘。"]'),
('yuding-93','屏風','李商隱','唐','御定全唐诗','yuding','','[]','六曲連環接翠帷，高樓半夜酒醒時。',32,'御定全唐詩/json/539.json','["六曲連環接翠帷，高樓半夜酒醒時。", "掩燈遮霧密如此，雨落月明俱不知。"]'),
('yuding-94','春日','李商隱','唐','御定全唐诗','yuding','','[]','欲入盧家白玉堂，新春催破舞衣裳。',32,'御定全唐詩/json/539.json','["欲入盧家白玉堂，新春催破舞衣裳。", "蝶銜紅蕊蜂銜粉，共助青樓一日忙。"]'),
('yuding-95','武侯廟古柏','李商隱','唐','御定全唐诗','yuding','','[]','蜀相階前柏，龍蛇捧閟宮。陰成外江畔，老向惠陵東。',72,'御定全唐詩/json/539.json','["蜀相階前柏，龍蛇捧閟宮。陰成外江畔，老向惠陵東。", "大樹思馮異，甘棠憶召公。葉凋湘燕雨，枝拆海鵬風。", "玉壘經綸遠，金刀歷數終。誰將出師表，一為問昭融。"]'),
('yuding-96','風','李商隱','唐','御定全唐诗','yuding','','[]','撩釵盤孔雀，惱帶拂鴛鴦。羅薦誰教近，齋時鎖洞房。',24,'御定全唐詩/json/539.json','["撩釵盤孔雀，惱帶拂鴛鴦。羅薦誰教近，齋時鎖洞房。"]'),
('yuding-97','即日','李商隱','唐','御定全唐诗','yuding','','[]','一歲林花即日休，江間亭下悵淹留。重吟細把真無奈，',40,'御定全唐詩/json/539.json','["一歲林花即日休，江間亭下悵淹留。重吟細把真無奈，", "金鞍忽散銀壺漏，更醉誰家白玉鉤。"]'),
('yuding-98','九成宮','李商隱','唐','御定全唐诗','yuding','','[]','十二層城閬苑西，平時避暑拂虹霓。雲隨夏後雙龍尾，',40,'御定全唐詩/json/539.json','["十二層城閬苑西，平時避暑拂虹霓。雲隨夏後雙龍尾，", "荔枝盧橘沾恩幸，鸞鵲天書濕紫泥。"]'),
('yuding-99','少將','李商隱','唐','御定全唐诗','yuding','','[]','族亞齊安陸，風高漢武威。煙波別墅醉，花月後門歸。',48,'御定全唐詩/json/539.json','["族亞齊安陸，風高漢武威。煙波別墅醉，花月後門歸。", "青海聞傳箭，天山報合圍。一朝攜劍起，上馬即如飛。"]'),
('yuding-100','詠史','李商隱','唐','御定全唐诗','yuding','','[]','曆覽前賢國與家，成由勤儉破由奢。何須琥珀方為枕，',40,'御定全唐詩/json/539.json','["曆覽前賢國與家，成由勤儉破由奢。何須琥珀方為枕，", "幾人曾預南熏曲，終古蒼梧哭翠華。"]'),
('yuding-101','贈白道者','李商隱','唐','御定全唐诗','yuding','','[]','十二樓前再拜辭，靈風正滿碧桃枝。',32,'御定全唐詩/json/539.json','["十二樓前再拜辭，靈風正滿碧桃枝。", "壺中若是有天地，又向壺中傷別離。"]'),
('yuding-102','無題二首','李商隱','唐','御定全唐诗','yuding','','[]','昨夜星辰昨夜風，畫樓西畔桂堂東。身無彩鳳雙飛翼，',72,'御定全唐詩/json/539.json','["昨夜星辰昨夜風，畫樓西畔桂堂東。身無彩鳳雙飛翼，", "嗟余聽鼓應官去，走馬蘭台類斷蓬。", "聞道閶門萼綠華，昔年相望抵天涯。", "豈知一夜秦樓客，偷看吳王苑內花。"]'),
('yuding-103','漢宮詞','李商隱','唐','御定全唐诗','yuding','','[]','青雀西飛竟未回，君王長在集靈台。',32,'御定全唐詩/json/539.json','["青雀西飛竟未回，君王長在集靈台。", "侍臣最有相如渴，不賜金莖露一杯。"]'),
('yuding-104','無題四首','李商隱','唐','御定全唐诗','yuding','','[]','來是空言去絕蹤，月斜樓上五更鐘。夢為遠別啼難喚，',168,'御定全唐詩/json/539.json','["來是空言去絕蹤，月斜樓上五更鐘。夢為遠別啼難喚，", "劉郎已恨蓬山遠，更隔蓬山一萬重。", "颯颯東風細雨來，芙蓉塘外有輕雷。金蟾齧鎖燒香入，", "春心莫共花爭發，一寸相思一寸灰。", "含情春晼晚，暫見夜闌幹。樓響將登怯，簾烘欲過難。", "多羞釵上燕，真愧鏡中鸞。歸去橫塘曉，華星送寶鞍。", "何處哀箏隨急管，櫻花永巷垂楊岸。東家老女嫁不售，", "歸來輾轉到五更，梁間燕子聞長歎。"]'),
('yuding-105','赴職梓潼留別畏之員外同年','李商隱','唐','御定全唐诗','yuding','','[]','佳兆聯翩遇鳳凰，雕文羽帳紫金床。桂花香處同高第，',40,'御定全唐詩/json/539.json','["佳兆聯翩遇鳳凰，雕文羽帳紫金床。桂花香處同高第，", "京華庸蜀三千里，送到咸陽見夕陽。"]'),
('yuding-106','桂林路中作','李商隱','唐','御定全唐诗','yuding','','[]','地暖無秋色，江晴有暮暉。空餘蟬嘒嘒，猶向客依依。',48,'御定全唐詩/json/539.json','["地暖無秋色，江晴有暮暉。空餘蟬嘒嘒，猶向客依依。", "村小犬相護，沙平僧獨歸。欲成西北望，又見鷓鴣飛。"]'),
('yuding-107','無題','李商隱','唐','御定全唐诗','yuding','','[]','照梁初有情，出水舊知名。裙衩芙蓉小，釵茸翡翠輕。',48,'御定全唐詩/json/539.json','["照梁初有情，出水舊知名。裙衩芙蓉小，釵茸翡翠輕。", "錦長書鄭重，眉細恨分明。莫近彈棋局，中心最不平。"]'),
('yuding-108','蝶三首','李商隱','唐','御定全唐诗','yuding','','[]','初來小苑中，稍與瑣闈通。遠恐芳塵斷，輕憂豔雪融。',112,'御定全唐詩/json/539.json','["初來小苑中，稍與瑣闈通。遠恐芳塵斷，輕憂豔雪融。", "只知防皓露，不覺逆尖風。回首雙飛燕，乘時入綺櫳。", "長眉畫了繡簾開，碧玉行收白玉台。", "為問翠釵釵上鳳，不知香頸為誰回。", "壽陽公主嫁時妝，八字宮眉捧額黃。", "見我佯羞頻照影，不知身屬冶游郎。"]'),
('yuding-109','無題二首','李商隱','唐','御定全唐诗','yuding','','[]','八歲偷照鏡，長眉已能畫。十歲去踏青，芙蓉作裙衩。',108,'御定全唐詩/json/539.json','["八歲偷照鏡，長眉已能畫。十歲去踏青，芙蓉作裙衩。", "十二學彈箏，銀甲不曾卸。十四藏六親，懸知猶未嫁。", "十五泣春風，背面秋千下。", "幽人不倦賞，秋暑貴招邀。竹碧轉悵望，池清尤寂寥。", "露花終裛濕，風蝶強嬌饒。此地如攜手，兼君不自聊。"]'),
('yuding-110','王十二兄與畏之員外相訪見招小飲時予以悼亡日近不去因寄','李商隱','唐','御定全唐诗','yuding','','[]','謝傅門庭舊末行，今朝歌管屬檀郎。更無人處簾垂地，',40,'御定全唐詩/json/539.json','["謝傅門庭舊末行，今朝歌管屬檀郎。更無人處簾垂地，", "秋霖腹疾俱難遣，萬里西風夜正長。"]'),
('yuding-111','隋宮','李商隱','唐','御定全唐诗','yuding','','[]','乘興南遊不戒嚴，九重誰省諫書函。',32,'御定全唐詩/json/539.json','["乘興南遊不戒嚴，九重誰省諫書函。", "春風舉國裁宮錦，半作障泥半作帆。"]'),
('yuding-112','落花','李商隱','唐','御定全唐诗','yuding','','[]','高閣客竟去，小園花亂飛。參差連曲陌，迢遞送斜暉。',48,'御定全唐詩/json/539.json','["高閣客竟去，小園花亂飛。參差連曲陌，迢遞送斜暉。", "腸斷未忍掃，眼穿仍欲歸。芳心向春盡，所得是沾衣。"]'),
('yuding-113','月','李商隱','唐','御定全唐诗','yuding','','[]','池上與橋邊，難忘複可憐。簾開最明夜，簟卷已涼天。',48,'御定全唐詩/json/539.json','["池上與橋邊，難忘複可憐。簾開最明夜，簟卷已涼天。", "流處水花急，吐時雲葉鮮。姮娥無粉黛，只是逞嬋娟。"]'),
('yuding-114','贈宗魯筇竹杖','李商隱','唐','御定全唐诗','yuding','','[]','大夏資輕策，全溪贈所思。靜憐穿樹遠，滑想過苔遲。',48,'御定全唐詩/json/539.json','["大夏資輕策，全溪贈所思。靜憐穿樹遠，滑想過苔遲。", "鶴怨朝還望，僧閑暮有期。風流真底事，常欲傍清羸。"]'),
('yuding-115','垂柳','李商隱','唐','御定全唐诗','yuding','','[]','娉婷小苑中，婀娜曲池東。朝佩皆垂地，仙衣盡帶風。',48,'御定全唐詩/json/539.json','["娉婷小苑中，婀娜曲池東。朝佩皆垂地，仙衣盡帶風。", "七賢寧占竹，三品且饒松。腸斷靈和殿，先皇玉座空。"]'),
('yuding-116','曲池','李商隱','唐','御定全唐诗','yuding','','[]','日下繁香不自持，月中流豔與誰期。迎憂急鼓疏鐘斷，',40,'御定全唐詩/json/539.json','["日下繁香不自持，月中流豔與誰期。迎憂急鼓疏鐘斷，", "從來此地黃昏散，未信河梁是別離。"]'),
('yuding-117','代應二首','李商隱','唐','御定全唐诗','yuding','','[]','溝水分流西複東，九秋霜月五更風。',56,'御定全唐詩/json/539.json','["溝水分流西複東，九秋霜月五更風。", "離鸞別鳳今何在，十二玉樓空更空。", "昨夜雙鉤敗，今朝百草輸。關西狂小吏，惟喝繞床盧。"]'),
('yuding-118','席上作','李商隱','唐','御定全唐诗','yuding','','[]','淡雲輕雨拂高唐，玉殿秋來夜正長。',32,'御定全唐詩/json/539.json','["淡雲輕雨拂高唐，玉殿秋來夜正長。", "料得也應憐宋玉，一生惟事楚襄王。"]'),
('yuding-119','訪隱者不遇成二絕','李商隱','唐','御定全唐诗','yuding','','[]','秋水悠悠浸墅扉，夢中來數覺來稀。',64,'御定全唐詩/json/539.json','["秋水悠悠浸墅扉，夢中來數覺來稀。", "玄蟬去盡葉黃落，一樹冬青人未歸。", "城郭休過識者稀，哀猿啼處有柴扉。", "滄江白日樵漁路，日暮歸來雨滿衣。"]'),
('yuding-120','破鏡','李商隱','唐','御定全唐诗','yuding','','[]','玉匣清光不復持，菱花散亂月輪虧。',32,'御定全唐詩/json/539.json','["玉匣清光不復持，菱花散亂月輪虧。", "秦台一照山雞後，便是孤鸞罷舞時。"]'),
('yuding-121','無題','李商隱','唐','御定全唐诗','yuding','','[]','紫府仙人號寶燈，雲漿未飲結成冰。',32,'御定全唐詩/json/539.json','["紫府仙人號寶燈，雲漿未飲結成冰。", "如何雪月交光夜，更在瑤台十二層。"]'),
('yuding-122','贈庾十二朱版','李商隱','唐','御定全唐诗','yuding','','[]','固漆投膠不可開，贈君珍重抵瓊瑰。',32,'御定全唐詩/json/539.json','["固漆投膠不可開，贈君珍重抵瓊瑰。", "君王曉坐金鑾殿，只待相如草詔來。"]'),
('yuding-123','李花','李商隱','唐','御定全唐诗','yuding','','[]','李徑獨來數，愁情相與懸。自明無月夜，強笑欲風天。',48,'御定全唐詩/json/539.json','["李徑獨來數，愁情相與懸。自明無月夜，強笑欲風天。", "減粉與園籜，分香沾渚蓮。徐妃久已嫁，猶自玉為鈿。"]'),
('yuding-124','柳','李商隱','唐','御定全唐诗','yuding','','[]','曾逐東風拂舞筵，樂游春苑斷腸天。',32,'御定全唐詩/json/539.json','["曾逐東風拂舞筵，樂游春苑斷腸天。", "如何肯到清秋日，已帶斜陽又帶蟬。"]'),
('yuding-125','三月十日流杯亭','李商隱','唐','御定全唐诗','yuding','','[]','身屬中軍少得歸，木蘭花盡失春期。',32,'御定全唐詩/json/539.json','["身屬中軍少得歸，木蘭花盡失春期。", "偷隨柳絮到城外，行過水西聞子規。"]'),
('yuding-126','過招國李家南園二首','李商隱','唐','御定全唐诗','yuding','','[]','潘岳無妻客為愁，新人來坐舊妝樓。',64,'御定全唐詩/json/539.json','["潘岳無妻客為愁，新人來坐舊妝樓。", "春風猶自疑聯句，雪絮相和飛不休。", "長亭歲盡雪如波，此去秦關路幾多。", "惟有夢中相近分，臥來無睡欲如何。"]'),
('yuding-127','留贈畏之','李商隱','唐','御定全唐诗','yuding','','[]','清時無事奏明光，不遣當關報早霜。中禁詞臣尋引領，',104,'御定全唐詩/json/539.json','["清時無事奏明光，不遣當關報早霜。中禁詞臣尋引領，", "空寄大羅天上事，眾仙同日詠霓裳。", "待得郎來月已低，寒暄不道醉如泥。", "五更又欲向何處，騎馬出門烏夜啼。", "戶外重陰黯不開，含羞迎夜複臨台。", "瀟湘浪上有煙景，安得好風吹汝來。"]'),
('yuding-128','為有','李商隱','唐','御定全唐诗','yuding','','[]','為有雲屏無限嬌，鳳城寒盡怕春宵。',32,'御定全唐詩/json/539.json','["為有雲屏無限嬌，鳳城寒盡怕春宵。", "無端嫁得金龜婿，辜負香衾事早朝。"]'),
('yuding-129','無題','李商隱','唐','御定全唐诗','yuding','','[]','相見時難別亦難，東風無力百花殘。春蠶到死絲方盡，',64,'御定全唐詩/json/539.json','["相見時難別亦難，東風無力百花殘。春蠶到死絲方盡，", "蠟炬成灰淚始幹。曉鏡但愁雲鬢改，夜吟應覺月光寒。", "蓬山此去無多路，青鳥殷勤為探看。"]'),
('yuding-130','碧城三首','李商隱','唐','御定全唐诗','yuding','','[]','碧城十二曲闌幹，犀辟塵埃玉辟寒。閬苑有書多附鶴，',120,'御定全唐詩/json/539.json','["碧城十二曲闌幹，犀辟塵埃玉辟寒。閬苑有書多附鶴，", "若是曉珠明又定，一生長對水晶盤。", "對影聞聲已可憐，玉池荷葉正田田。不逢蕭史休回首，", "鄂君悵望舟中夜，繡被焚香獨自眠。", "七夕來時先有期，洞房簾箔至今垂。玉輪顧兔初生魄，", "武皇內傳分明在，莫道人間總不知。"]'),
('yuding-131','對雪二首','李商隱','唐','御定全唐诗','yuding','','[]','寒氣先侵玉女扉，清光旋透省郎闈。梅花大庾嶺頭髮，',80,'御定全唐詩/json/539.json','["寒氣先侵玉女扉，清光旋透省郎闈。梅花大庾嶺頭髮，", "龍山萬里無多遠，留待行人二月歸。", "旋撲珠簾過粉牆，輕于柳絮重於霜。已隨江令誇瓊樹，", "關河凍合東西路，腸斷斑騅送陸郎。"]'),
('yuding-132','蜂','李商隱','唐','御定全唐诗','yuding','','[]','小苑華池爛熳通，後門前檻思無窮。宓妃腰細才勝露，',40,'御定全唐詩/json/539.json','["小苑華池爛熳通，後門前檻思無窮。宓妃腰細才勝露，", "青陵粉蝶休離恨，長定相逢二月中。"]'),
('yuding-133','公子','李商隱','唐','御定全唐诗','yuding','','[]','外戚封侯自有恩，平明通籍九華門。',32,'御定全唐詩/json/539.json','["外戚封侯自有恩，平明通籍九華門。", "金唐公主年應小，二十君王未許婚。"]'),
('yuding-134','賦得雞','李商隱','唐','御定全唐诗','yuding','','[]','稻粱猶足活諸雛，妒敵專場好自娛。',32,'御定全唐詩/json/539.json','["稻粱猶足活諸雛，妒敵專場好自娛。", "可要五更驚曉夢，不辭風雪為陽烏。"]'),
('yuding-135','明神','李商隱','唐','御定全唐诗','yuding','','[]','明神司過豈令冤，暗室由來有禍門。',32,'御定全唐詩/json/539.json','["明神司過豈令冤，暗室由來有禍門。", "莫為無人欺一物，他時須慮石能言。"]'),
('yuding-136','辛未七夕','李商隱','唐','御定全唐诗','yuding','','[]','恐是仙家好別離，故教迢遞作佳期。由來碧落銀河畔，',40,'御定全唐詩/json/539.json','["恐是仙家好別離，故教迢遞作佳期。由來碧落銀河畔，", "豈能無意酬烏鵲，惟與蜘蛛乞巧絲。"]'),
('yuding-137','壬申七夕','李商隱','唐','御定全唐诗','yuding','','[]','已駕七香車，心心待曉霞。風輕惟響佩，日薄不嫣花。',48,'御定全唐詩/json/539.json','["已駕七香車，心心待曉霞。風輕惟響佩，日薄不嫣花。", "桂嫩傳香遠，榆高送影斜。成都過卜肆，曾妒識靈槎。"]'),
('yuding-138','壬申閏秋題贈烏鵲','李商隱','唐','御定全唐诗','yuding','','[]','繞樹無依月正高，鄴城新淚濺雲袍。',32,'御定全唐詩/json/539.json','["繞樹無依月正高，鄴城新淚濺雲袍。", "幾年始得逢秋閏，兩度填河莫告勞。"]'),
('yuding-139','端居','李商隱','唐','御定全唐诗','yuding','','[]','遠書歸夢兩悠悠，只有空床敵素秋。',32,'御定全唐詩/json/539.json','["遠書歸夢兩悠悠，只有空床敵素秋。", "階下青苔與紅樹，雨中寥落月中愁。"]'),
('yuding-140','夜半','李商隱','唐','御定全唐诗','yuding','','[]','三更三點萬家眠，露欲為霜月墮煙。',32,'御定全唐詩/json/539.json','["三更三點萬家眠，露欲為霜月墮煙。", "鬥鼠上堂蝙蝠出，玉琴時動倚窗弦。"]'),
('yuding-141','玉山','李商隱','唐','御定全唐诗','yuding','','[]','玉山高與閬風齊，玉水清流不貯泥。何處更求回日馭，',40,'御定全唐詩/json/539.json','["玉山高與閬風齊，玉水清流不貯泥。何處更求回日馭，", "聞道神仙有才子，赤簫吹罷好相攜。"]'),
('yuding-142','張惡子廟','李商隱','唐','御定全唐诗','yuding','','[]','下馬捧椒漿，迎神白玉堂。如何鐵如意，獨自與姚萇。',24,'御定全唐詩/json/539.json','["下馬捧椒漿，迎神白玉堂。如何鐵如意，獨自與姚萇。"]'),
('yuding-143','雨','李商隱','唐','御定全唐诗','yuding','','[]','摵摵度瓜園，依依傍竹軒。秋池不自冷，風葉共成喧。',48,'御定全唐詩/json/539.json','["摵摵度瓜園，依依傍竹軒。秋池不自冷，風葉共成喧。", "窗迥有時見，簷高相續翻。侵宵送書雁，應為稻粱恩。"]'),
('yuding-144','菊','李商隱','唐','御定全唐诗','yuding','','[]','暗暗淡淡紫，融融冶冶黃。陶令籬邊色，羅含宅裏香。',48,'御定全唐詩/json/539.json','["暗暗淡淡紫，融融冶冶黃。陶令籬邊色，羅含宅裏香。", "幾時禁重露，實是怯殘陽。願泛金鸚鵡，升君白玉堂。"]'),
('yuding-145','牡丹','李商隱','唐','御定全唐诗','yuding','','[]','錦幃初卷衛夫人，繡被猶堆越鄂君。垂手亂翻雕玉佩，',40,'御定全唐詩/json/539.json','["錦幃初卷衛夫人，繡被猶堆越鄂君。垂手亂翻雕玉佩，", "我是夢中傳彩筆，欲書花葉寄朝雲。"]'),
('yuding-146','北樓','李商隱','唐','御定全唐诗','yuding','','[]','春物豈相干，人生只強歡。花猶曾斂夕，酒竟不知寒。',48,'御定全唐詩/json/539.json','["春物豈相干，人生只強歡。花猶曾斂夕，酒竟不知寒。", "異域東風濕，中華上象寬。此樓堪北望，輕命倚危欄。"]'),
('yuding-147','擬沈下賢','李商隱','唐','御定全唐诗','yuding','','[]','千二百輕鸞，春衫瘦著寬。倚風行稍急，含雪語應寒。',48,'御定全唐詩/json/539.json','["千二百輕鸞，春衫瘦著寬。倚風行稍急，含雪語應寒。", "帶火遺金鬥，兼珠碎玉盤。河陽看花過，曾不問潘安。"]'),
('yuding-148','蝶','李商隱','唐','御定全唐诗','yuding','','[]','飛來繡戶陰，穿過畫樓深。重傅秦台粉，輕塗漢殿金。',48,'御定全唐詩/json/539.json','["飛來繡戶陰，穿過畫樓深。重傅秦台粉，輕塗漢殿金。", "相兼惟柳絮，所得是花心。可要淩孤客，邀為子夜吟。"]'),
('yuding-149','飲席代官妓贈兩從事','李商隱','唐','御定全唐诗','yuding','','[]','新人橋上著春衫，舊主江邊側帽檐。',32,'御定全唐詩/json/539.json','["新人橋上著春衫，舊主江邊側帽檐。", "願得化為紅綬帶，許教雙鳳一時銜。"]'),
('yuding-150','代魏宮私贈','李商隱','唐','御定全唐诗','yuding','','[]','來時西館阻佳期，去後漳河隔夢思。',32,'御定全唐詩/json/539.json','["來時西館阻佳期，去後漳河隔夢思。", "知有宓妃無限意，春松秋菊可同時。"]'),
('yuding-151','代元城吳令暗為答','李商隱','唐','御定全唐诗','yuding','','[]','背闕歸藩路欲分，水邊風日半西曛。',32,'御定全唐詩/json/539.json','["背闕歸藩路欲分，水邊風日半西曛。", "荊王枕上原無夢，莫枉陽臺一片雲。"]'),
('yuding-152','牡丹','李商隱','唐','御定全唐诗','yuding','','[]','壓徑複緣溝，當窗又映樓。終銷一國破，不啻萬金求。',48,'御定全唐詩/json/539.json','["壓徑複緣溝，當窗又映樓。終銷一國破，不啻萬金求。", "鸞鳳戲三島，神仙居十洲。應憐萱草淡，卻得號忘憂。"]'),
('yuding-153','百果嘲櫻桃','李商隱','唐','御定全唐诗','yuding','','[]','珠實雖先熟，瓊莩縱早開。流鶯猶故在，爭得諱含來。',24,'御定全唐詩/json/539.json','["珠實雖先熟，瓊莩縱早開。流鶯猶故在，爭得諱含來。"]'),
('yuding-154','櫻桃答','李商隱','唐','御定全唐诗','yuding','','[]','眾果莫相誚，天生名品高。何因古樂府，惟有鄭櫻桃。',24,'御定全唐詩/json/539.json','["眾果莫相誚，天生名品高。何因古樂府，惟有鄭櫻桃。"]'),
('yuding-155','曉坐','李商隱','唐','御定全唐诗','yuding','','[]','後合罷朝眠，前墀思黯然。梅應未假雪，柳自不勝煙。',48,'御定全唐詩/json/539.json','["後合罷朝眠，前墀思黯然。梅應未假雪，柳自不勝煙。", "淚續淺深綆，腸危高下弦。紅顏無定所，得失在當年。"]'),
('yuding-156','詠史','李商隱','唐','御定全唐诗','yuding','','[]','北湖南埭水漫漫，一片降旗百尺竿。',32,'御定全唐詩/json/539.json','["北湖南埭水漫漫，一片降旗百尺竿。", "三百年間同曉夢，鐘山何處有龍盤。"]'),
('yuding-157','一片','李商隱','唐','御定全唐诗','yuding','','[]','一片非煙隔九枝，蓬巒仙仗儼雲旗。天泉水暖龍吟細，',40,'御定全唐詩/json/539.json','["一片非煙隔九枝，蓬巒仙仗儼雲旗。天泉水暖龍吟細，", "人間桑海朝朝變，莫遣佳期更後期。"]'),
('yuding-158','日射','李商隱','唐','御定全唐诗','yuding','','[]','日射紗窗風撼扉，香羅拭手春事違。',32,'御定全唐詩/json/539.json','["日射紗窗風撼扉，香羅拭手春事違。", "回廊四合掩寂寞，碧鸚鵡對紅薔薇。"]'),
('yuding-159','題鵝','李商隱','唐','御定全唐诗','yuding','','[]','眠沙臥水自成群，曲岸殘陽極浦雲。',32,'御定全唐詩/json/539.json','["眠沙臥水自成群，曲岸殘陽極浦雲。", "那解將心憐孔翠，羈雌長共故雄分。"]'),
('yuding-160','華清宮','李商隱','唐','御定全唐诗','yuding','','[]','朝元閣迥羽衣新，首按昭陽第一人。',32,'御定全唐詩/json/539.json','["朝元閣迥羽衣新，首按昭陽第一人。", "當日不來高處舞，可能天下有胡塵。"]'),
('yuding-161','梓潼望長卿山至巴西複懷譙秀','李商隱','唐','御定全唐诗','yuding','','[]','梓潼不見馬相如，更欲南行問酒壚。',32,'御定全唐詩/json/539.json','["梓潼不見馬相如，更欲南行問酒壚。", "行到巴西覓譙秀，巴西惟是有寒蕪。"]'),
('yuding-162','齊宮詞','李商隱','唐','御定全唐诗','yuding','','[]','永壽兵來夜不扃，金蓮無複印中庭。',32,'御定全唐詩/json/539.json','["永壽兵來夜不扃，金蓮無複印中庭。", "梁台歌管三更罷，猶自風搖九子鈴。"]'),
('yuding-163','十一月中旬至扶風界見梅花','李商隱','唐','御定全唐诗','yuding','','[]','匝路亭亭豔，非時裛裛香。素娥惟與月，青女不饒霜。',48,'御定全唐詩/json/539.json','["匝路亭亭豔，非時裛裛香。素娥惟與月，青女不饒霜。", "贈遠虛盈手，傷離適斷腸。為誰成早秀，不待作年芳。"]'),
('yuding-164','青陵台','李商隱','唐','御定全唐诗','yuding','','[]','青陵台畔日光斜，萬古貞魂倚暮霞。',32,'御定全唐詩/json/539.json','["青陵台畔日光斜，萬古貞魂倚暮霞。", "莫訝韓憑為蛺蝶，等閒飛上別枝花。"]'),
('yuding-165','東還','李商隱','唐','御定全唐诗','yuding','','[]','自有仙才自不知，十年長夢采華芝。',32,'御定全唐詩/json/539.json','["自有仙才自不知，十年長夢采華芝。", "秋風動地黃雲暮，歸去嵩陽尋舊師。"]'),
('yuding-166','酬崔八早梅有贈兼示之作','李商隱','唐','御定全唐诗','yuding','','[]','知訪寒梅過野塘，久留金勒為回腸。謝郎衣袖初翻雪，',40,'御定全唐詩/json/539.json','["知訪寒梅過野塘，久留金勒為回腸。謝郎衣袖初翻雪，", "維摩一室雖多病，亦要天花作道場。"]'),
('yuding-167','春風','李商隱','唐','御定全唐诗','yuding','','[]','春風雖自好，春物太昌昌。若教春有意，惟遣一枝芳。',36,'御定全唐詩/json/539.json','["春風雖自好，春物太昌昌。若教春有意，惟遣一枝芳。", "我意殊春意，先春已斷腸。"]'),
('yuding-168','蜀桐','李商隱','唐','御定全唐诗','yuding','','[]','玉壘高桐拂玉繩，上含非霧下含冰。',32,'御定全唐詩/json/539.json','["玉壘高桐拂玉繩，上含非霧下含冰。", "枉教紫鳳無棲處，斫作秋琴彈壞陵。"]'),
('yuding-169','漢宮','李商隱','唐','御定全唐诗','yuding','','[]','通靈夜醮達清晨，承露盤晞甲帳春。',32,'御定全唐詩/json/539.json','["通靈夜醮達清晨，承露盤晞甲帳春。", "王母不來方朔去，更須重見李夫人。"]'),
('yuding-170','判春','李商隱','唐','御定全唐诗','yuding','','[]','一桃複一李，井上占年芳。笑處如臨鏡，窺時不隱牆。',48,'御定全唐詩/json/539.json','["一桃複一李，井上占年芳。笑處如臨鏡，窺時不隱牆。", "敢言西子短，誰覺宓妃長。珠玉終相類，同名作夜光。"]'),
('yuding-171','促漏','李商隱','唐','御定全唐诗','yuding','','[]','促漏遙鐘動靜聞，報章重疊杳難分。舞鸞鏡匣收殘黛，',40,'御定全唐詩/json/539.json','["促漏遙鐘動靜聞，報章重疊杳難分。舞鸞鏡匣收殘黛，", "南塘漸暖蒲堪結，兩兩鴛鴦護水紋。"]'),
('yuding-172','江東','李商隱','唐','御定全唐诗','yuding','','[]','驚魚撥剌燕翩翾，獨自江東上釣船。',32,'御定全唐詩/json/539.json','["驚魚撥剌燕翩翾，獨自江東上釣船。", "今日春光太漂蕩，謝家輕絮沈郎錢。"]'),
('yuding-173','讀任彥升碑','李商隱','唐','御定全唐诗','yuding','','[]','任昉當年有美名，可憐才調最縱橫。',32,'御定全唐詩/json/539.json','["任昉當年有美名，可憐才調最縱橫。", "梁台初建應惆悵，不得蕭公作騎兵。"]'),
('yuding-174','荷花','李商隱','唐','御定全唐诗','yuding','','[]','都無色可並，不奈此香何。瑤席乘涼設，金羈落晚過。',48,'御定全唐詩/json/539.json','["都無色可並，不奈此香何。瑤席乘涼設，金羈落晚過。", "回衾燈照綺，渡襪水沾羅。預想前秋別，離居夢棹歌。"]'),
('yuding-175','五松驛','李商隱','唐','御定全唐诗','yuding','','[]','獨下長亭念過秦，五松不見見輿薪。',32,'御定全唐詩/json/539.json','["獨下長亭念過秦，五松不見見輿薪。", "只應既斬斯高後，尋被樵人用斧斤。"]'),
('yuding-176','灞岸','李商隱','唐','御定全唐诗','yuding','','[]','山東今歲點行頻，幾處冤魂哭虜塵。',32,'御定全唐詩/json/539.json','["山東今歲點行頻，幾處冤魂哭虜塵。", "灞水橋邊倚華表，平時二月有東巡。"]'),
('yuding-177','送臻師二首','李商隱','唐','御定全唐诗','yuding','','[]','昔去靈山非拂席，今來滄海欲求珠。',64,'御定全唐詩/json/539.json','["昔去靈山非拂席，今來滄海欲求珠。", "楞伽頂上清涼地，善眼仙人憶我無。", "苦海迷途去未因，東方過此幾微塵。", "何當百億蓮花上，一一蓮花見佛身。"]'),
('yuding-178','七夕','李商隱','唐','御定全唐诗','yuding','','[]','鸞扇斜分鳳幄開，星橋橫過鵲飛回。',32,'御定全唐詩/json/539.json','["鸞扇斜分鳳幄開，星橋橫過鵲飛回。", "爭將世上無期別，換得年年一度來。"]'),
('yuding-179','謝先輩防紀念拙詩甚多，異日偶有此寄','李商隱','唐','御定全唐诗','yuding','','[]','曉用雲添句，寒將雪命篇。良辰多自感，作者豈皆然。',96,'御定全唐詩/json/539.json','["曉用雲添句，寒將雪命篇。良辰多自感，作者豈皆然。", "熟寢初同鶴，含嘶欲並蟬。題時長不展，得處定應偏。", "南浦無窮樹，西樓不住煙。改成人寂寂，寄與路綿綿。", "星勢寒垂地，河聲曉上天。夫君自有恨，聊借此中傳。"]'),
('yuding-180','馬嵬二首','李商隱','唐','御定全唐诗','yuding','','[]','冀馬燕犀動地來，自埋紅粉自成灰。',72,'御定全唐詩/json/539.json','["冀馬燕犀動地來，自埋紅粉自成灰。", "君王若道能傾國，玉輦何由過馬嵬。", "海外徒聞更九州，他生未蔔此生休。空聞虎旅傳宵柝，", "如何四紀為天子，不及盧家有莫愁。"]'),
('yuding-181','可歎','李商隱','唐','御定全唐诗','yuding','','[]','幸會東城宴未回，年華憂共水相催。梁家宅裏秦宮入，',40,'御定全唐詩/json/539.json','["幸會東城宴未回，年華憂共水相催。梁家宅裏秦宮入，", "宓妃愁坐芝田館，用盡陳王八鬥才。"]'),
('yuding-182','望喜驛別嘉陵江水二絕','李商隱','唐','御定全唐诗','yuding','','[]','嘉陵江水此東流，望喜樓中憶閬州。',64,'御定全唐詩/json/539.json','["嘉陵江水此東流，望喜樓中憶閬州。", "若到閬中還赴海，閬州應更有高樓。", "千里嘉陵江水色，含煙帶月碧于藍。", "今朝相送東流後，猶自驅車更向南。"]'),
('yuding-183','別薛岩賓','李商隱','唐','御定全唐诗','yuding','','[]','曙爽行將拂，晨清坐欲淩。別離真不那，風物正相仍。',72,'御定全唐詩/json/539.json','["曙爽行將拂，晨清坐欲淩。別離真不那，風物正相仍。", "漫水任誰照，衰花淺自矜。還將兩袖淚，同向一窗燈。", "桂樹乖真隱，芸香是小懲。清規無以況，且用玉壺冰。"]'),
('yuding-184','富平少侯','李商隱','唐','御定全唐诗','yuding','','[]','七國三邊未到憂，十三身襲富平侯。不收金彈拋林外，',40,'御定全唐詩/json/539.json','["七國三邊未到憂，十三身襲富平侯。不收金彈拋林外，", "當關不報侵晨客，新得佳人字莫愁。"]'),
('yuding-185','腸','李商隱','唐','御定全唐诗','yuding','','[]','有懷非惜恨，不奈寸腸何。即席回彌久，前時斷固多。',96,'御定全唐詩/json/539.json','["有懷非惜恨，不奈寸腸何。即席回彌久，前時斷固多。", "熱應翻急燒，冷欲徹微波。隔樹澌澌雨，通池點點荷。", "倦程山向背，望國闕嵯峨。故念飛書及，新歡借夢過。", "染筠休伴淚，繞雪莫追歌。擬問陽臺事，年深楚語訛。"]'),
('yuding-186','贈宇文中丞','李商隱','唐','御定全唐诗','yuding','','[]','欲構中天正急材，自緣煙水戀平臺。',32,'御定全唐詩/json/539.json','["欲構中天正急材，自緣煙水戀平臺。", "人間只有嵇延祖，最望山公啟事來。"]'),
('yuding-187','曉起','李商隱','唐','御定全唐诗','yuding','','[]','擬杯當曉起，呵鏡可微寒。隔箔山櫻熟，褰帷桂燭殘。',48,'御定全唐詩/json/539.json','["擬杯當曉起，呵鏡可微寒。隔箔山櫻熟，褰帷桂燭殘。", "書長為報晚，夢好更尋難。影響輸雙蝶，偏過舊畹蘭。"]'),
('yuding-188','閨情','李商隱','唐','御定全唐诗','yuding','','[]','紅露花房白蜜脾，黃蜂紫蝶兩參差。',32,'御定全唐詩/json/539.json','["紅露花房白蜜脾，黃蜂紫蝶兩參差。", "春窗一覺風流夢，卻是同袍不得知。"]'),
('yuding-189','月夕','李商隱','唐','御定全唐诗','yuding','','[]','草下陰蟲葉上霜，朱欄迢遞壓湖光。',32,'御定全唐詩/json/539.json','["草下陰蟲葉上霜，朱欄迢遞壓湖光。", "兔寒蟾冷桂花白，此夜姮娥應斷腸。"]'),
('yuding-190','杏花','李商隱','唐','御定全唐诗','yuding','','[]','上國昔相值，亭亭如欲言。異鄉今暫賞，眽眽豈無恩。',120,'御定全唐詩/json/539.json','["上國昔相值，亭亭如欲言。異鄉今暫賞，眽眽豈無恩。", "援少風多力，牆高月有痕。為含無限意，遂對不勝繁。", "仙子玉京路，主人金谷園。幾時辭碧落，誰伴過黃昏。", "鏡拂鉛華膩，爐藏桂燼溫。終應催竹葉，先擬詠桃根。", "莫學啼成血，從教夢寄魂。吳王采香徑，失路入煙村。"]'),
('yuding-191','燈','李商隱','唐','御定全唐诗','yuding','','[]','皎潔終無倦，煎熬亦自求。花時隨酒遠，雨後背窗休。',96,'御定全唐詩/json/539.json','["皎潔終無倦，煎熬亦自求。花時隨酒遠，雨後背窗休。", "冷暗黃茅驛，暄明紫桂樓。錦囊名畫掩，玉局敗棋收。", "何處無佳夢，誰人不隱憂。影隨簾押轉，光信簟文流。", "客自勝潘嶽，儂今定莫愁。固應留半焰，回照下幃羞。"]'),
('yuding-192','清河','李商隱','唐','御定全唐诗','yuding','','[]','舟小回仍數，樓危憑亦頻。燕來從及社，蝶舞太侵晨。',48,'御定全唐詩/json/539.json','["舟小回仍數，樓危憑亦頻。燕來從及社，蝶舞太侵晨。", "絳雪除煩後，霜梅取味新。年華無一事，只是自傷春。"]'),
('yuding-193','襪','李商隱','唐','御定全唐诗','yuding','','[]','嘗聞宓妃襪，渡水欲生塵。好借常娥著，清秋踏月輪。',24,'御定全唐詩/json/539.json','["嘗聞宓妃襪，渡水欲生塵。好借常娥著，清秋踏月輪。"]'),
('yuding-194','追代盧家人嘲堂內','李商隱','唐','御定全唐诗','yuding','','[]','道卻橫波字，人前莫謾羞。只應同楚水，長短入淮流。',24,'御定全唐詩/json/539.json','["道卻橫波字，人前莫謾羞。只應同楚水，長短入淮流。"]'),
('yuding-195','代應','李商隱','唐','御定全唐诗','yuding','','[]','本來銀漢是紅牆，隔得盧家白玉堂。',32,'御定全唐詩/json/539.json','["本來銀漢是紅牆，隔得盧家白玉堂。", "誰與王昌報消息，盡知三十六鴛鴦。"]'),
('yuding-196','離亭賦得折楊柳二首','李商隱','唐','御定全唐诗','yuding','','[]','暫憑樽酒送無憀，莫損愁眉與細腰。',64,'御定全唐詩/json/539.json','["暫憑樽酒送無憀，莫損愁眉與細腰。", "人世死前惟有別，春風爭擬惜長條。", "含煙惹霧每依依，萬緒千條拂落暉。", "為報行人休盡折，半留相送半迎歸。"]'),
('yuding-197','寄永道士','李商隱','唐','御定全唐诗','yuding','','[]','共上雲山獨下遲，陽臺白道細如絲。',32,'御定全唐詩/json/539.json','["共上雲山獨下遲，陽臺白道細如絲。", "君今並倚三珠樹，不記人間落葉時。"]'),
('yuding-198','華州周大夫宴席','李商隱','唐','御定全唐诗','yuding','','[]','郡齋何用酒如泉，飲德先時已醉眠。',32,'御定全唐詩/json/539.json','["郡齋何用酒如泉，飲德先時已醉眠。", "若共門人推禮分，戴崇爭得及彭宣。"]'),
('yuding-199','荊山','李商隱','唐','御定全唐诗','yuding','','[]','壓河連華勢孱顏，鳥沒雲歸一望間。',32,'御定全唐詩/json/539.json','["壓河連華勢孱顏，鳥沒雲歸一望間。", "楊僕移關三百里，可能全是為荊山。"]'),
('yuding-200','次陝州先寄源從事','李商隱','唐','御定全唐诗','yuding','','[]','離思羈愁日欲晡，東周西雍此分塗。',32,'御定全唐詩/json/539.json','["離思羈愁日欲晡，東周西雍此分塗。", "回鑾佛寺高多少，望盡黃河一曲無。"]'),
('yuding-201','過鄭廣文舊居','李商隱','唐','御定全唐诗','yuding','','[]','宋玉平生恨有餘，遠循三楚吊三閭。',32,'御定全唐詩/json/539.json','["宋玉平生恨有餘，遠循三楚吊三閭。", "可憐留著臨江宅，異代應教庾信居。"]'),
('yuding-202','東下三旬苦於風土馬上戲作','李商隱','唐','御定全唐诗','yuding','','[]','路繞函關東複東，身騎征馬逐驚蓬。',32,'御定全唐詩/json/539.json','["路繞函關東複東，身騎征馬逐驚蓬。", "天池遼闊誰相待，日日虛乘九萬風。"]'),
('yuding-203','莫愁','李商隱','唐','御定全唐诗','yuding','','[]','雪中梅下與誰期，梅雪相兼一萬枝。',32,'御定全唐詩/json/539.json','["雪中梅下與誰期，梅雪相兼一萬枝。", "若是石城無艇子，莫愁還自有愁時。"]'),
('yuding-204','夢令狐學士','李商隱','唐','御定全唐诗','yuding','','[]','山驛荒涼白竹扉，殘燈向曉夢清暉。',32,'御定全唐詩/json/539.json','["山驛荒涼白竹扉，殘燈向曉夢清暉。", "右銀台路雪三尺，鳳詔裁成當直歸。"]'),
('yuding-205','涉洛川','李商隱','唐','御定全唐诗','yuding','','[]','通谷陽林不見人，我來遺恨古時春。',32,'御定全唐詩/json/539.json','["通谷陽林不見人，我來遺恨古時春。", "宓妃漫結無窮恨，不為君王殺灌均。"]'),
('yuding-206','有感','李商隱','唐','御定全唐诗','yuding','','[]','中路因循我所長，古來才命兩相妨。',32,'御定全唐詩/json/539.json','["中路因循我所長，古來才命兩相妨。", "勸君莫強安蛇足，一盞芳醪不得嘗。"]'),
('yuding-207','宮妓','李商隱','唐','御定全唐诗','yuding','','[]','珠箔輕明拂玉墀，披香新殿鬥腰支。',32,'御定全唐詩/json/539.json','["珠箔輕明拂玉墀，披香新殿鬥腰支。", "不須看盡魚龍戲，終遣君王怒偃師。"]'),
('yuding-208','宮辭','李商隱','唐','御定全唐诗','yuding','','[]','君恩如水向東流，得寵憂移失寵愁。',32,'御定全唐詩/json/539.json','["君恩如水向東流，得寵憂移失寵愁。", "莫向尊前奏花落，涼風只在殿西頭。"]'),
('yuding-209','代贈二首','李商隱','唐','御定全唐诗','yuding','','[]','樓上黃昏欲望休，玉梯橫絕月中鉤。',64,'御定全唐詩/json/539.json','["樓上黃昏欲望休，玉梯橫絕月中鉤。", "芭蕉不展丁香結，同向春風各自愁。", "東南日出照高樓，樓上離人唱石州。", "總把春山掃眉黛，不知供得幾多愁。"]'),
('yuding-210','楚吟','李商隱','唐','御定全唐诗','yuding','','[]','山上離宮宮上樓，樓前宮畔暮江流。',32,'御定全唐詩/json/539.json','["山上離宮宮上樓，樓前宮畔暮江流。", "楚天長短黃昏雨，宋玉無愁亦自愁。"]'),
('yuding-211','瑤池','李商隱','唐','御定全唐诗','yuding','','[]','瑤池阿母綺窗開，黃竹歌聲動地哀。',32,'御定全唐詩/json/539.json','["瑤池阿母綺窗開，黃竹歌聲動地哀。", "八駿日行三萬里，穆王何事不重來。"]'),
('yuding-212','柳','李商隱','唐','御定全唐诗','yuding','','[]','為有橋邊拂面香，何曾自敢占流光。',32,'御定全唐詩/json/539.json','["為有橋邊拂面香，何曾自敢占流光。", "後庭玉樹承恩澤，不信年華有斷腸。"]'),
('yuding-213','寄在朝鄭曹獨孤李四同年','李商隱','唐','御定全唐诗','yuding','','[]','昔歲陪遊舊跡多，風光今日兩蹉跎。',32,'御定全唐詩/json/539.json','["昔歲陪遊舊跡多，風光今日兩蹉跎。", "不因醉本蘭亭在，兼忘當年舊永和。"]'),
('yuding-0','南朝','李商隱','唐','御定全唐诗','yuding','','[]','地險悠悠天險長，金陵王氣應瑤光。',32,'御定全唐詩/json/540.json','["地險悠悠天險長，金陵王氣應瑤光。", "休誇此地分天下，只得徐妃半面妝。"]'),
('yuding-1','題漢祖廟','李商隱','唐','御定全唐诗','yuding','','[]','乘運應須宅八荒，男兒安在戀池隍。',32,'御定全唐詩/json/540.json','["乘運應須宅八荒，男兒安在戀池隍。", "君王自起新豐後，項羽何曾在故鄉。"]'),
('yuding-2','韓冬郎即席為詩相送一座盡驚他日余方追吟連宵侍坐裴回久之句有老成之風因成二絕寄酬兼呈畏之員外','李商隱','唐','御定全唐诗','yuding','','[]','十歲裁詩走馬成，冷灰殘燭動離情。',64,'御定全唐詩/json/540.json','["十歲裁詩走馬成，冷灰殘燭動離情。", "桐花萬里丹山路，雛鳳清於老鳳聲。", "劍棧風檣各苦辛，別時冰雪到時春。", "為憑何遜休聯句，瘦盡東陽姓沈人。"]'),
('yuding-3','評事翁寄賜餳粥走筆為答','李商隱','唐','御定全唐诗','yuding','','[]','粥香餳白杏花天，省對流鶯坐綺筵。',32,'御定全唐詩/json/540.json','["粥香餳白杏花天，省對流鶯坐綺筵。", "今日寄來春已老，鳳樓迢遞憶秋千。"]'),
('yuding-4','東阿王','李商隱','唐','御定全唐诗','yuding','','[]','國事分明屬灌均，西陵魂斷夜來人。',32,'御定全唐詩/json/540.json','["國事分明屬灌均，西陵魂斷夜來人。", "君王不得為天子，半為當時賦洛神。"]'),
('yuding-5','聖女祠','李商隱','唐','御定全唐诗','yuding','','[]','松篁台殿蕙香幃，龍護瑤窗鳳掩扉。無質易迷三裏霧，',40,'御定全唐詩/json/540.json','["松篁台殿蕙香幃，龍護瑤窗鳳掩扉。無質易迷三裏霧，", "寄問釵頭雙白燕，每朝珠館幾時歸。"]'),
('yuding-6','獨居有懷','李商隱','唐','御定全唐诗','yuding','','[]','麝重愁風逼，羅疏畏月侵。怨魂迷恐斷，嬌喘細疑沈。',96,'御定全唐詩/json/540.json','["麝重愁風逼，羅疏畏月侵。怨魂迷恐斷，嬌喘細疑沈。", "數急芙蓉帶，頻抽翡翠簪。柔情終不遠，遙妒已先深。", "浦冷鴛鴦去，園空蛺蝶尋。蠟花長遞淚，箏柱鎮移心。", "覓使嵩雲暮，回頭灞岸陰。只聞涼葉院，露井近寒砧。"]'),
('yuding-7','過景陵','李商隱','唐','御定全唐诗','yuding','','[]','武皇精魄久仙升，帳殿淒涼煙霧凝。',32,'御定全唐詩/json/540.json','["武皇精魄久仙升，帳殿淒涼煙霧凝。", "俱是蒼生留不得，鼎湖何異魏西陵。"]'),
('yuding-8','臨發崇讓宅紫薇','李商隱','唐','御定全唐诗','yuding','','[]','一樹濃姿獨看來，秋庭暮雨類輕埃。不先搖落應為有，',40,'御定全唐詩/json/540.json','["一樹濃姿獨看來，秋庭暮雨類輕埃。不先搖落應為有，", "天涯地角同榮謝，豈要移根上苑栽。"]'),
('yuding-9','及第東歸次灞上，卻寄同年','李商隱','唐','御定全唐诗','yuding','','[]','芳桂當年各一枝，行期未分壓春期。江魚朔雁長相憶，',40,'御定全唐詩/json/540.json','["芳桂當年各一枝，行期未分壓春期。江魚朔雁長相憶，", "灞陵柳色無離恨，莫枉長條贈所思。"]'),
('yuding-10','《野菊','李商隱','唐','御定全唐诗','yuding','','[]','苦竹園南椒塢邊，微香冉冉淚涓涓。已悲節物同寒雁，',40,'御定全唐詩/json/540.json','["苦竹園南椒塢邊，微香冉冉淚涓涓。已悲節物同寒雁，", "紫雲新苑移花處，不敢霜栽近禦筵。"]'),
('yuding-11','板橋曉別','李商隱','唐','御定全唐诗','yuding','','[]','回望高城落曉河，長亭窗戶壓微波。',32,'御定全唐詩/json/540.json','["回望高城落曉河，長亭窗戶壓微波。", "水仙欲上鯉魚去，一夜芙蓉紅淚多。"]'),
('yuding-12','過伊僕射舊宅','李商隱','唐','御定全唐诗','yuding','','[]','朱邸方酬力戰功，華筵俄歎逝波窮。回廊簷斷燕飛去，',40,'御定全唐詩/json/540.json','["朱邸方酬力戰功，華筵俄歎逝波窮。回廊簷斷燕飛去，", "何能更涉瀧江去，獨立寒流吊楚宮。"]'),
('yuding-13','關門柳','李商隱','唐','御定全唐诗','yuding','','[]','永定河邊一行柳，依依長髮故年春。',32,'御定全唐詩/json/540.json','["永定河邊一行柳，依依長髮故年春。", "東來西去人情薄，不為清陰減路塵。"]'),
('yuding-14','酬別令狐補闕','李商隱','唐','御定全唐诗','yuding','','[]','惜別夏仍半，回途秋已期。那修直諫草，更賦贈行詩。',72,'御定全唐詩/json/540.json','["惜別夏仍半，回途秋已期。那修直諫草，更賦贈行詩。", "錦段知無報，青萍肯見疑。人生有通塞，公等系安危。", "警露鶴辭侶，吸風蟬抱枝。彈冠如不問，又到掃門時。"]'),
('yuding-15','銀河吹笙','李商隱','唐','御定全唐诗','yuding','','[]','悵望銀河吹玉笙，樓寒院冷接平明。重衾幽夢他年斷，',40,'御定全唐詩/json/540.json','["悵望銀河吹玉笙，樓寒院冷接平明。重衾幽夢他年斷，", "不須浪作緱山意，湘瑟秦簫自有情。"]'),
('yuding-16','與同年李定言曲水閒話戲作','李商隱','唐','御定全唐诗','yuding','','[]','海燕參差溝水流，同君身世屬離憂。相攜花下非秦贅，',40,'御定全唐詩/json/540.json','["海燕參差溝水流，同君身世屬離憂。相攜花下非秦贅，", "莫驚五勝埋香骨，地下傷春亦白頭。"]'),
('yuding-17','彭城公薨後贈杜二十七勝李十七潘二君並與愚同出故尚書安平公門下','李商隱','唐','御定全唐诗','yuding','','[]','梁山兗水約從公，兩地參差一旦空。',32,'御定全唐詩/json/540.json','["梁山兗水約從公，兩地參差一旦空。", "謝墅庾村相吊後，自今岐路各西東。"]'),
('yuding-18','聞歌','李商隱','唐','御定全唐诗','yuding','','[]','斂笑凝眸意欲歌，高雲不動碧嵯峨。銅台罷望歸何處，',40,'御定全唐詩/json/540.json','["斂笑凝眸意欲歌，高雲不動碧嵯峨。銅台罷望歸何處，", "此聲腸斷非今日，香灺燈光奈爾何。"]'),
('yuding-19','贈華陽宋真人兼寄清都劉先生','李商隱','唐','御定全唐诗','yuding','','[]','淪謫千年別帝宸，至今猶謝蕊珠人。但驚茅許同仙籍，',40,'御定全唐詩/json/540.json','["淪謫千年別帝宸，至今猶謝蕊珠人。但驚茅許同仙籍，", "不因杖屨逢周史，徐甲何曾有此身。"]'),
('yuding-20','楚宮二首','李商隱','唐','御定全唐诗','yuding','','[]','十二峰前落照微，高唐宮暗坐迷歸。',72,'御定全唐詩/json/540.json','["十二峰前落照微，高唐宮暗坐迷歸。", "朝雲暮雨長相接，猶自君王恨見稀。", "月姊曾逢下彩蟾，傾城消息隔重簾。已聞佩響知腰細，", "王昌且在牆東住，未必金堂得免嫌。"]'),
('yuding-21','和友人戲贈二首','李商隱','唐','御定全唐诗','yuding','','[]','東望花樓曾不同，西來雙燕信休通。仙人掌冷三霄露，',80,'御定全唐詩/json/540.json','["東望花樓曾不同，西來雙燕信休通。仙人掌冷三霄露，", "殷勤莫使清香透，牢合金魚鎖桂叢。", "迢遞青門有幾關，柳梢樓角見南山。明珠可貫須為佩，", "猿啼鶴怨終年事，未抵熏爐一夕間。"]'),
('yuding-22','題二首後重有戲贈任秀才','李商隱','唐','御定全唐诗','yuding','','[]','一丈紅薔擁翠筠，羅窗不識繞街塵。峽中尋覓長逢雨，',40,'御定全唐詩/json/540.json','["一丈紅薔擁翠筠，羅窗不識繞街塵。峽中尋覓長逢雨，", "適知小閣還斜照，羨殺烏龍臥錦茵。"]'),
('yuding-23','有感二首','李商隱','唐','御定全唐诗','yuding','','[]','九服歸元化，三靈葉睿圖。如何本初輩，自取屈犛誅。',192,'御定全唐詩/json/540.json','["九服歸元化，三靈葉睿圖。如何本初輩，自取屈犛誅。", "有甚當車泣，因勞下殿趨。何成奏雲物，直是滅萑苻。", "證逮符書密，辭連性命俱。竟緣尊漢相，不早辨胡雛。", "鬼籙分朝部，軍烽照上都。敢雲堪慟哭，未免怨洪爐。", "丹陛猶敷奏，彤庭欻戰爭。臨危對盧植，始悔用龐萌。", "禦仗收前殿，兵徒劇背城。蒼黃五色棒，掩遏一陽生。", "古有清君側，今非乏老成。素心雖未易，此舉太無名。", "誰瞑銜冤目，寧吞欲絕聲。近聞開壽宴，不廢用咸英。"]'),
('yuding-24','重有感','李商隱','唐','御定全唐诗','yuding','','[]','玉帳牙旗得上游，安危須共主君憂。竇融表已來關右，',40,'御定全唐詩/json/540.json','["玉帳牙旗得上游，安危須共主君憂。竇融表已來關右，", "晝號夜哭兼幽顯，早晚星關雪涕收。"]'),
('yuding-25','壽安公主出降','李商隱','唐','御定全唐诗','yuding','','[]','溈水聞貞媛，常山索銳師。昔憂迷帝力，今分送王姬。',48,'御定全唐詩/json/540.json','["溈水聞貞媛，常山索銳師。昔憂迷帝力，今分送王姬。", "事等和強虜，恩殊睦本枝。四郊多壘在，此禮恐無時。"]'),
('yuding-26','夕陽樓','李商隱','唐','御定全唐诗','yuding','','[]','花明柳暗繞天愁，上盡重城更上樓。',32,'御定全唐詩/json/540.json','["花明柳暗繞天愁，上盡重城更上樓。", "欲問孤鴻向何處，不知身世自悠悠。"]'),
('yuding-27','春雨','李商隱','唐','御定全唐诗','yuding','','[]','悵臥新春白袷衣，白門寥落意多違。紅樓隔雨相望冷，',40,'御定全唐詩/json/540.json','["悵臥新春白袷衣，白門寥落意多違。紅樓隔雨相望冷，", "玉璫緘劄何由達，萬里雲羅一雁飛。"]'),
('yuding-28','中元作','李商隱','唐','御定全唐诗','yuding','','[]','絳節飄颻宮國來，中元朝拜上清回。羊權須得金條脫，',40,'御定全唐詩/json/540.json','["絳節飄颻宮國來，中元朝拜上清回。羊權須得金條脫，", "有娀未抵瀛洲遠，青雀如何鴆鳥媒。"]'),
('yuding-29','鴛鴦','李商隱','唐','御定全唐诗','yuding','','[]','雌去雄飛萬里天，雲羅滿眼淚潸然。',32,'御定全唐詩/json/540.json','["雌去雄飛萬里天，雲羅滿眼淚潸然。", "不須長結風波願，鎖向金籠始兩全。"]'),
('yuding-30','楚宮','李商隱','唐','御定全唐诗','yuding','','[]','湘波如淚色漻漻，楚厲迷魂逐恨遙。楓樹夜猿愁自斷，',40,'御定全唐詩/json/540.json','["湘波如淚色漻漻，楚厲迷魂逐恨遙。楓樹夜猿愁自斷，", "但使故鄉三戶在，彩絲誰惜懼長蛟。"]'),
('yuding-31','妓席暗記送同年獨孤雲之武昌','李商隱','唐','御定全唐诗','yuding','','[]','疊嶂千重叫恨猿，長江萬里洗離魂。',32,'御定全唐詩/json/540.json','["疊嶂千重叫恨猿，長江萬里洗離魂。", "武昌若有山頭石，為拂蒼苔檢淚痕。"]'),
('yuding-32','宿晉昌亭聞驚禽','李商隱','唐','御定全唐诗','yuding','','[]','羈緒鰥鰥夜景侵，高窗不掩見驚禽。飛來曲渚煙方合，',40,'御定全唐詩/json/540.json','["羈緒鰥鰥夜景侵，高窗不掩見驚禽。飛來曲渚煙方合，", "失群掛木知何限，遠隔天涯共此心。"]'),
('yuding-33','深宮','李商隱','唐','御定全唐诗','yuding','','[]','金殿銷香閉綺櫳，玉壺傳點咽銅龍。狂飆不惜蘿陰薄，',40,'御定全唐詩/json/540.json','["金殿銷香閉綺櫳，玉壺傳點咽銅龍。狂飆不惜蘿陰薄，", "豈知為雨為雲處，只有高唐十二峰。"]'),
('yuding-34','明禪師院酬從兄見寄','李商隱','唐','御定全唐诗','yuding','','[]','貞吝嫌茲世，會心馳本原。人非四禪縛，地絕一塵喧。',48,'御定全唐詩/json/540.json','["貞吝嫌茲世，會心馳本原。人非四禪縛，地絕一塵喧。", "霜露欹高木，星河壓故園。斯遊儻為勝，九折幸回軒。"]'),
('yuding-35','寄裴衡','李商隱','唐','御定全唐诗','yuding','','[]','別地蕭條極，如何更獨來。秋應為黃葉，雨不厭青苔。',48,'御定全唐詩/json/540.json','["別地蕭條極，如何更獨來。秋應為黃葉，雨不厭青苔。", "沈約只能瘦，潘仁豈是才。雜情堪底寄，惟有冷於灰。"]'),
('yuding-36','即日','李商隱','唐','御定全唐诗','yuding','','[]','小苑試春衣，高樓倚暮暉。夭桃惟是笑，舞蝶不空飛。',48,'御定全唐詩/json/540.json','["小苑試春衣，高樓倚暮暉。夭桃惟是笑，舞蝶不空飛。", "赤嶺久無耗，鴻門猶合圍。幾家緣錦字，含淚坐鴛機。"]'),
('yuding-37','淮陽路','李商隱','唐','御定全唐诗','yuding','','[]','荒村倚廢營，投宿旅魂驚。斷雁高仍急，寒溪曉更清。',48,'御定全唐詩/json/540.json','["荒村倚廢營，投宿旅魂驚。斷雁高仍急，寒溪曉更清。", "昔年嘗聚盜，此日頗分兵。猜貳誰先致，三朝事始平。"]'),
('yuding-38','崇讓宅東亭醉後沔然有作','李商隱','唐','御定全唐诗','yuding','','[]','曲岸風雷罷，東亭霽日涼。新秋仍酒困，幽興暫江鄉。',120,'御定全唐詩/json/540.json','["曲岸風雷罷，東亭霽日涼。新秋仍酒困，幽興暫江鄉。", "搖落真何遽，交親或未忘。一帆彭蠡月，數雁塞門霜。", "俗態雖多累，仙標發近狂。聲名佳句在，身世玉琴張。", "萬古山空碧，無人鬢免黃。驊騮憂老大，鶗鴂妒芬芳。", "密竹沈虛籟，孤蓮泊晚香。如何此幽勝，淹臥劇清漳。"]'),
('yuding-39','晚晴','李商隱','唐','御定全唐诗','yuding','','[]','深居俯夾城，春去夏猶清。天意憐幽草，人間重晚晴。',48,'御定全唐詩/json/540.json','["深居俯夾城，春去夏猶清。天意憐幽草，人間重晚晴。", "並添高閣迥，微注小窗明。越鳥巢幹後，歸飛體更輕。"]'),
('yuding-40','迎寄韓魯州','李商隱','唐','御定全唐诗','yuding','','[]','積雨晚騷騷，相思正郁陶。不知人萬里，時有燕雙高。',48,'御定全唐詩/json/540.json','["積雨晚騷騷，相思正郁陶。不知人萬里，時有燕雙高。", "寇盜纏三輔，莓苔滑百牢。聖朝推衛霍，歸日動仙曹。"]'),
('yuding-41','武夷山','李商隱','唐','御定全唐诗','yuding','','[]','只得流霞酒一杯，空中簫鼓幾時回。',32,'御定全唐詩/json/540.json','["只得流霞酒一杯，空中簫鼓幾時回。", "武夷洞裏生毛竹，老盡曾孫更不來。"]'),
('yuding-42','一片','李商隱','唐','御定全唐诗','yuding','','[]','一片瓊英價動天，連城十二昔虛傳。',32,'御定全唐詩/json/540.json','["一片瓊英價動天，連城十二昔虛傳。", "良工巧費真為累，楮葉成來不直錢。"]'),
('yuding-43','寄成都高苗二從事','李商隱','唐','御定全唐诗','yuding','','[]','紅蓮幕下紫梨新，命斷湘南病渴人。',32,'御定全唐詩/json/540.json','["紅蓮幕下紫梨新，命斷湘南病渴人。", "今日問君能寄否，二江風水接天津。"]'),
('yuding-44','鄭州獻從叔舍人褎','李商隱','唐','御定全唐诗','yuding','','[]','蓬島煙霞閬苑鐘，三官箋奏附金龍。茅君奕世仙曹貴，',40,'御定全唐詩/json/540.json','["蓬島煙霞閬苑鐘，三官箋奏附金龍。茅君奕世仙曹貴，", "不知他日華陽洞，許上經樓第幾重。"]'),
('yuding-45','西南行卻寄相送者','李商隱','唐','御定全唐诗','yuding','','[]','百里陰雲覆雪泥，行人只在雪雲西。',32,'御定全唐詩/json/540.json','["百里陰雲覆雪泥，行人只在雪雲西。", "明朝驚破還鄉夢，定是陳倉碧野雞。"]'),
('yuding-46','四皓廟','李商隱','唐','御定全唐诗','yuding','','[]','羽翼殊勳棄若遺，皇天有運我無時。',32,'御定全唐詩/json/540.json','["羽翼殊勳棄若遺，皇天有運我無時。", "廟前便接山門路，不長青松長紫芝。"]'),
('yuding-47','題白石蓮花寄楚公','李商隱','唐','御定全唐诗','yuding','','[]','白石蓮花誰所共，六時長捧佛前燈。空庭苔蘚饒霜露，',40,'御定全唐詩/json/540.json','["白石蓮花誰所共，六時長捧佛前燈。空庭苔蘚饒霜露，", "漫誇鶖子真羅漢，不會牛車是上乘。"]'),
('yuding-48','安定城樓','李商隱','唐','御定全唐诗','yuding','','[]','迢遞高城百尺樓，綠楊枝外盡汀洲。賈生年少虛垂淚，',40,'御定全唐詩/json/540.json','["迢遞高城百尺樓，綠楊枝外盡汀洲。賈生年少虛垂淚，", "不知腐鼠成滋味，猜意鴛雛竟未休。"]'),
('yuding-49','隋宮守歲','李商隱','唐','御定全唐诗','yuding','','[]','消息東郊木帝回，宮中行樂有新梅。沈香甲煎為庭燎，',40,'御定全唐詩/json/540.json','["消息東郊木帝回，宮中行樂有新梅。沈香甲煎為庭燎，", "昭陽第一傾城客，不踏金蓮不肯來。"]'),
('yuding-50','利州江潭作','李商隱','唐','御定全唐诗','yuding','','[]','神劍飛來不易銷，碧潭珍重駐蘭橈。自攜明月移燈疾，',40,'御定全唐詩/json/540.json','["神劍飛來不易銷，碧潭珍重駐蘭橈。自攜明月移燈疾，", "他時燕脯無人寄，雨滿空城蕙葉雕。"]'),
('yuding-51','即目','李商隱','唐','御定全唐诗','yuding','','[]','地寬樓已迥，人更迥于樓。細意經春物，傷酲屬暮愁。',96,'御定全唐詩/json/540.json','["地寬樓已迥，人更迥于樓。細意經春物，傷酲屬暮愁。", "望賒殊易斷，恨久欲難收。大勢真無利，多情豈自由。", "空園兼樹廢，敗港擁花流。書去青楓驛，鴻歸杜若洲。", "單棲應分定，辭疾索誰憂。更替林鴉恨，驚頻去不休。"]'),
('yuding-52','相思','李商隱','唐','御定全唐诗','yuding','','[]','相思樹上合歡枝，紫鳳青鸞共羽儀。',32,'御定全唐詩/json/540.json','["相思樹上合歡枝，紫鳳青鸞共羽儀。", "腸斷秦台吹管客，日西春盡到來遲。"]'),
('yuding-53','茂陵','李商隱','唐','御定全唐诗','yuding','','[]','漢家天馬出蒲梢，苜蓿榴花遍近郊。內苑只知含鳳觜，',40,'御定全唐詩/json/540.json','["漢家天馬出蒲梢，苜蓿榴花遍近郊。內苑只知含鳳觜，", "誰料蘇卿老歸國，茂陵松柏雨蕭蕭。"]'),
('yuding-54','鏡檻','李商隱','唐','御定全唐诗','yuding','','[]','鏡檻芙蓉入，香台翡翠過。撥弦驚火鳳，交扇拂天鵝。',192,'御定全唐詩/json/540.json','["鏡檻芙蓉入，香台翡翠過。撥弦驚火鳳，交扇拂天鵝。", "隱忍陽城笑，喧傳郢市歌。仙眉瓊作葉，佛髻鈿為螺。", "五裏無因霧，三秋只見河。月中供藥剩，海上得綃多。", "玉集胡沙割，犀留聖水磨。斜門穿戲蝶，小閣鎖飛蛾。", "騎襜侵韉卷，車帷約幰鈋。傳書兩行雁，取酒一封駝。", "橋迥涼風壓，溝橫夕照和。待烏燕太子，駐馬魏東阿。", "想像鋪芳褥，依稀解醉羅。散時簾隔露，臥後幕生波。", "梯穩從攀桂，弓調任射莎。豈能拋斷夢，聽鼓事朝珂。"]'),
('yuding-55','送鄭大台文南覲','李商隱','唐','御定全唐诗','yuding','','[]','黎辟灘聲五月寒，南風無處附平安。',32,'御定全唐詩/json/540.json','["黎辟灘聲五月寒，南風無處附平安。", "君懷一匹胡威絹，爭拭酬恩淚得幹。"]'),
('yuding-56','風','李商隱','唐','御定全唐诗','yuding','','[]','迥拂來鴻急，斜催別燕高。已寒休慘澹，更遠尚呼號。',48,'御定全唐詩/json/540.json','["迥拂來鴻急，斜催別燕高。已寒休慘澹，更遠尚呼號。", "楚色分西塞，夷音接下牢。歸舟天外有，一為戒波濤。"]'),
('yuding-57','洞庭魚','李商隱','唐','御定全唐诗','yuding','','[]','洞庭魚可拾，不假更垂罾。鬧若雨前蟻，多於秋後蠅。',48,'御定全唐詩/json/540.json','["洞庭魚可拾，不假更垂罾。鬧若雨前蟻，多於秋後蠅。", "豈思鱗作簟，仍計腹為燈。浩蕩天池路，翱翔欲化鵬。"]'),
('yuding-58','天涯','李商隱','唐','御定全唐诗','yuding','','[]','春日在天涯，天涯日又斜。鶯啼如有淚，為濕最高花。',24,'御定全唐詩/json/540.json','["春日在天涯，天涯日又斜。鶯啼如有淚，為濕最高花。"]'),
('yuding-59','喜舍弟羲叟及第上禮部魏公','李商隱','唐','御定全唐诗','yuding','','[]','國以斯文重，公仍內署來。風標森太華，星象逼中台。',48,'御定全唐詩/json/540.json','["國以斯文重，公仍內署來。風標森太華，星象逼中台。", "朝滿遷鶯侶，門多吐鳳才。甯同魯司寇，惟鑄一顏回。"]'),
('yuding-60','哀箏','李商隱','唐','御定全唐诗','yuding','','[]','延頸全同鶴，柔腸素怯猿。湘波無限淚，蜀魄有餘冤。',48,'御定全唐詩/json/540.json','["延頸全同鶴，柔腸素怯猿。湘波無限淚，蜀魄有餘冤。", "輕幰長無道，哀箏不出門。何由問香炷，翠幕自黃昏。"]'),
('yuding-61','自南山北歸經分水嶺','李商隱','唐','御定全唐诗','yuding','','[]','水急愁無地，山深故有雲。那通極目望，又作斷腸分。',48,'御定全唐詩/json/540.json','["水急愁無地，山深故有雲。那通極目望，又作斷腸分。", "鄭驛來雖及，燕台哭不聞。猶餘遺意在，許刻鎮南勳。"]'),
('yuding-62','舊頓','李商隱','唐','御定全唐诗','yuding','','[]','東人望幸久咨嗟，四海於今是一家。',32,'御定全唐詩/json/540.json','["東人望幸久咨嗟，四海於今是一家。", "猶鎖平時舊行殿，盡無宮戶有宮鴉。"]'),
('yuding-63','代董秀才卻扇','李商隱','唐','御定全唐诗','yuding','','[]','莫將畫扇出帷來，遮掩春山滯上才。',32,'御定全唐詩/json/540.json','["莫將畫扇出帷來，遮掩春山滯上才。", "若道團圓似明月，此中須放桂花開。"]'),
('yuding-64','有感','李商隱','唐','御定全唐诗','yuding','','[]','非關宋玉有微辭，卻是襄王夢覺遲。',32,'御定全唐詩/json/540.json','["非關宋玉有微辭，卻是襄王夢覺遲。", "一自高唐賦成後，楚天雲雨盡堪疑。"]'),
('yuding-65','驪山有感','李商隱','唐','御定全唐诗','yuding','','[]','驪岫飛泉泛暖香，九龍呵護玉蓮房。',32,'御定全唐詩/json/540.json','["驪岫飛泉泛暖香，九龍呵護玉蓮房。", "平明每幸長生殿，不從金輿惟壽王。"]'),
('yuding-66','別智玄法師','李商隱','唐','御定全唐诗','yuding','','[]','雲鬢無端怨別離，十年移易住山期。',32,'御定全唐詩/json/540.json','["雲鬢無端怨別離，十年移易住山期。", "東西南北皆垂淚，卻是楊朱真本師。"]'),
('yuding-67','贈孫綺新及第','李商隱','唐','御定全唐诗','yuding','','[]','長樂遙聽上苑鐘，彩衣稱慶桂香濃。',32,'御定全唐詩/json/540.json','["長樂遙聽上苑鐘，彩衣稱慶桂香濃。", "陸機始擬誇文賦，不覺雲間有士龍。"]'),
('yuding-68','代秘書贈弘文館諸校書','李商隱','唐','御定全唐诗','yuding','','[]','清切曹司近玉除，比來秋興複何如。',32,'御定全唐詩/json/540.json','["清切曹司近玉除，比來秋興複何如。", "崇文館裏丹霜後，無限紅梨憶校書。"]'),
('yuding-69','亂石','李商隱','唐','御定全唐诗','yuding','','[]','虎踞龍蹲縱複橫，星光漸減雨痕生。',32,'御定全唐詩/json/540.json','["虎踞龍蹲縱複橫，星光漸減雨痕生。", "不須並礙東西路，哭殺廚頭阮步兵。"]'),
('yuding-70','日日','李商隱','唐','御定全唐诗','yuding','','[]','日日春光鬥日光，山城斜路杏花香。',32,'御定全唐詩/json/540.json','["日日春光鬥日光，山城斜路杏花香。", "幾時心緒渾無事，得及遊絲百尺長。"]'),
('yuding-71','過楚宮','李商隱','唐','御定全唐诗','yuding','','[]','巫峽迢迢舊楚宮，至今雲雨暗丹楓。',32,'御定全唐詩/json/540.json','["巫峽迢迢舊楚宮，至今雲雨暗丹楓。", "微生盡戀人間樂，只有襄王憶夢中。"]'),
('yuding-72','龍池','李商隱','唐','御定全唐诗','yuding','','[]','龍池賜酒敞雲屏，羯鼓聲高眾樂停。',32,'御定全唐詩/json/540.json','["龍池賜酒敞雲屏，羯鼓聲高眾樂停。", "夜半宴歸宮漏永，薛王沉醉壽王醒。"]'),
('yuding-73','淚','李商隱','唐','御定全唐诗','yuding','','[]','永巷長年怨綺羅，離情終日思風波。湘江竹上痕無限，',40,'御定全唐詩/json/540.json','["永巷長年怨綺羅，離情終日思風波。湘江竹上痕無限，", "朝來灞水橋邊問，未抵青袍送玉珂。"]'),
('yuding-74','十字水期韋潘侍禦同年不至時韋寓居水次故郭汾甯宅','李商隱','唐','御定全唐诗','yuding','','[]','伊水濺濺相背流，朱欄畫閣幾人遊。漆燈夜照真無數，',40,'御定全唐詩/json/540.json','["伊水濺濺相背流，朱欄畫閣幾人遊。漆燈夜照真無數，", "西園碧樹今誰主，與近高窗臥聽秋。"]'),
('yuding-75','流鶯','李商隱','唐','御定全唐诗','yuding','','[]','流鶯漂蕩複參差，渡陌臨流不自持。巧囀豈能無本意，',40,'御定全唐詩/json/540.json','["流鶯漂蕩複參差，渡陌臨流不自持。巧囀豈能無本意，", "曾苦傷春不忍聽，鳳城何處有花枝。"]'),
('yuding-76','出關宿盤豆館對叢蘆有感','李商隱','唐','御定全唐诗','yuding','','[]','蘆葉梢梢夏景深，郵亭暫欲灑塵襟。昔年曾是江南客，',40,'御定全唐詩/json/540.json','["蘆葉梢梢夏景深，郵亭暫欲灑塵襟。昔年曾是江南客，", "清聲不遠行人去，一世荒城伴夜砧。"]'),
('yuding-77','和韓錄事送宮人入道','李商隱','唐','御定全唐诗','yuding','','[]','星使追還不自由，雙童捧上綠瓊輈。九枝燈下朝金殿，',40,'御定全唐詩/json/540.json','["星使追還不自由，雙童捧上綠瓊輈。九枝燈下朝金殿，", "當時若愛韓公子，埋骨成灰恨未休。"]'),
('yuding-78','即目','李商隱','唐','御定全唐诗','yuding','','[]','小鼎煎茶面曲池，白須道士竹間棋。',32,'御定全唐詩/json/540.json','["小鼎煎茶面曲池，白須道士竹間棋。", "何人書破蒲葵扇，記著南塘移樹時。"]'),
('yuding-79','聖女祠','李商隱','唐','御定全唐诗','yuding','','[]','杳藹逢仙跡，蒼茫滯客途。何年歸碧落，此路向皇都。',96,'御定全唐詩/json/540.json','["杳藹逢仙跡，蒼茫滯客途。何年歸碧落，此路向皇都。", "消息期青雀，逢迎異紫姑。腸回楚國夢，心斷漢宮巫。", "從騎裁寒竹，行車蔭白榆。星娥一去後，月姊更來無。", "寡鵠迷蒼壑，羈凰怨翠梧。惟應碧桃下，方朔是狂夫。"]'),
('yuding-80','七月二十九日崇讓宅宴作','李商隱','唐','御定全唐诗','yuding','','[]','露如微霰下前池，月過回塘萬竹悲。浮世本來多聚散，',40,'御定全唐詩/json/540.json','["露如微霰下前池，月過回塘萬竹悲。浮世本來多聚散，", "豈到白頭長只爾，嵩陽松雪有心期。"]'),
('yuding-81','贈從兄閬之','李商隱','唐','御定全唐诗','yuding','','[]','悵望人間萬事違，私書幽夢約忘機。荻花村裏魚標在，',40,'御定全唐詩/json/540.json','["悵望人間萬事違，私書幽夢約忘機。荻花村裏魚標在，", "城中猘犬憎蘭佩，莫損幽芳久不歸。"]'),
('yuding-82','吳宮','李商隱','唐','御定全唐诗','yuding','','[]','龍檻沉沉水殿清，禁門深掩斷人聲。',32,'御定全唐詩/json/540.json','["龍檻沉沉水殿清，禁門深掩斷人聲。", "吳王宴罷滿宮醉，日暮水漂花出城。"]'),
('yuding-83','常娥','李商隱','唐','御定全唐诗','yuding','','[]','雲母屏風燭影深，長河漸落曉星沈。',32,'御定全唐詩/json/540.json','["雲母屏風燭影深，長河漸落曉星沈。", "常娥應悔偷靈藥，碧海青天夜夜心。"]'),
('yuding-84','殘花','李商隱','唐','御定全唐诗','yuding','','[]','殘花啼露莫留春，尖發誰非怨別人。',32,'御定全唐詩/json/540.json','["殘花啼露莫留春，尖發誰非怨別人。", "若但掩關勞獨夢，寶釵何日不生塵。"]'),
('yuding-85','天津西望','李商隱','唐','御定全唐诗','yuding','','[]','虜馬崩騰忽一狂，翠華無日到東方。',32,'御定全唐詩/json/540.json','["虜馬崩騰忽一狂，翠華無日到東方。", "天津西望腸真斷，滿眼秋波出苑牆。"]'),
('yuding-86','西亭','李商隱','唐','御定全唐诗','yuding','','[]','此夜西亭月正圓，疏簾相伴宿風煙。',32,'御定全唐詩/json/540.json','["此夜西亭月正圓，疏簾相伴宿風煙。", "梧桐莫更翻清露，孤鶴從來不得眠。"]'),
('yuding-87','憶住一師','李商隱','唐','御定全唐诗','yuding','','[]','無事經年別遠公，帝城鐘曉憶西峰。',32,'御定全唐詩/json/540.json','["無事經年別遠公，帝城鐘曉憶西峰。", "爐煙消盡寒燈晦，童子開門雪滿松。"]'),
('yuding-88','昨夜','李商隱','唐','御定全唐诗','yuding','','[]','不辭鶗鴂妒年芳，但惜流塵暗燭房。',32,'御定全唐詩/json/540.json','["不辭鶗鴂妒年芳，但惜流塵暗燭房。", "昨夜西池涼露滿，桂花吹斷月中香。"]'),
('yuding-89','海客','李商隱','唐','御定全唐诗','yuding','','[]','海客乘槎上紫氛，星娥罷織一相聞。',32,'御定全唐詩/json/540.json','["海客乘槎上紫氛，星娥罷織一相聞。", "只應不憚牽牛妒，聊用支機石贈君。"]'),
('yuding-90','初食筍呈座中','李商隱','唐','御定全唐诗','yuding','','[]','嫩籜香苞初出林，於陵論價重如金。',32,'御定全唐詩/json/540.json','["嫩籜香苞初出林，於陵論價重如金。", "皇都陸海應無數，忍剪淩雲一寸心。"]'),
('yuding-91','早起','李商隱','唐','御定全唐诗','yuding','','[]','風露澹清晨，簾間獨起人。鶯花啼又笑，畢竟是誰春。',24,'御定全唐詩/json/540.json','["風露澹清晨，簾間獨起人。鶯花啼又笑，畢竟是誰春。"]'),
('yuding-92','寄蜀客','李商隱','唐','御定全唐诗','yuding','','[]','君到臨邛問酒壚，近來還有長卿無。',32,'御定全唐詩/json/540.json','["君到臨邛問酒壚，近來還有長卿無。", "金徽卻是無情物，不許文君憶故夫。"]'),
('yuding-93','行至金牛驛寄興元渤海尚書','李商隱','唐','御定全唐诗','yuding','','[]','樓上春雲水底天，五雲章色破巴箋。諸生個個王恭柳，',40,'御定全唐詩/json/540.json','["樓上春雲水底天，五雲章色破巴箋。諸生個個王恭柳，", "深慚走馬金牛路，驟和陳王白玉篇。"]'),
('yuding-94','深樹見一顆櫻桃尚在','李商隱','唐','御定全唐诗','yuding','','[]','高桃留晚實，尋得小庭南。矮墮綠雲髻，欹危紅玉簪。',48,'御定全唐詩/json/540.json','["高桃留晚實，尋得小庭南。矮墮綠雲髻，欹危紅玉簪。", "惜堪充鳳食，痛已被鶯含。越鳥誇香荔，齊名亦未甘。"]'),
('yuding-95','細雨','李商隱','唐','御定全唐诗','yuding','','[]','帷飄白玉堂，簟卷碧牙床。楚女當時意，蕭蕭發彩涼。',24,'御定全唐詩/json/540.json','["帷飄白玉堂，簟卷碧牙床。楚女當時意，蕭蕭發彩涼。"]'),
('yuding-96','歌舞','李商隱','唐','御定全唐诗','yuding','','[]','遏雲歌響清，回雪舞腰輕。只要君流眄，君傾國自傾。',24,'御定全唐詩/json/540.json','["遏雲歌響清，回雪舞腰輕。只要君流眄，君傾國自傾。"]'),
('yuding-97','海上','李商隱','唐','御定全唐诗','yuding','','[]','石橋東望海連天，徐福空來不得仙。',32,'御定全唐詩/json/540.json','["石橋東望海連天，徐福空來不得仙。", "直遣麻姑與搔背，可能留命待桑田。"]'),
('yuding-98','魏侯第東北樓堂郢叔言別，聊用書所見成篇','李商隱','唐','御定全唐诗','yuding','','[]','暗樓連夜閣，不擬為黃昏。未必斷別淚，何曾妨夢魂。',108,'御定全唐詩/json/540.json','["暗樓連夜閣，不擬為黃昏。未必斷別淚，何曾妨夢魂。", "疑穿花逶迤，漸近火溫黁。海底翻無水，仙家卻有村。", "鎖香金屈戌，殢酒玉昆侖。羽白風交扇，冰清月映盆。", "舊歡塵自積，新歲電猶奔。霞綺空留段，雲峰不帶根。", "念君千里舸，江草漏燈痕。"]'),
('yuding-99','白雲夫舊居','李商隱','唐','御定全唐诗','yuding','','[]','平生誤識白雲夫，再到仙簷憶酒壚。',32,'御定全唐詩/json/540.json','["平生誤識白雲夫，再到仙簷憶酒壚。", "牆外萬株人絕跡，夕陽惟照欲棲烏。"]'),
('yuding-100','同學彭道士參寥','李商隱','唐','御定全唐诗','yuding','','[]','莫羨仙家有上真，仙家暫謫亦千春。',32,'御定全唐詩/json/540.json','["莫羨仙家有上真，仙家暫謫亦千春。", "月中桂樹高多少，試問西河斫樹人。"]'),
('yuding-101','到秋','李商隱','唐','御定全唐诗','yuding','','[]','扇風淅瀝簟流離，萬里南風滯所思。',32,'御定全唐詩/json/540.json','["扇風淅瀝簟流離，萬里南風滯所思。", "守到清秋還寂寞，葉丹苔碧閉門時。"]'),
('yuding-102','華師','李商隱','唐','御定全唐诗','yuding','','[]','孤鶴不睡雲無心，衲衣筇杖來西林。',32,'御定全唐詩/json/540.json','["孤鶴不睡雲無心，衲衣筇杖來西林。", "院門晝鎖回廊靜，秋日當階柿葉陰。"]'),
('yuding-103','華嶽下題西王母廟','李商隱','唐','御定全唐诗','yuding','','[]','神仙有分豈關情，八馬虛隨落日行。',32,'御定全唐詩/json/540.json','["神仙有分豈關情，八馬虛隨落日行。", "莫恨名姬中夜沒，君王猶自不長生。"]'),
('yuding-104','過華清內廄門','李商隱','唐','御定全唐诗','yuding','','[]','華清別館閉黃昏，碧草悠悠內廄門。',32,'御定全唐詩/json/540.json','["華清別館閉黃昏，碧草悠悠內廄門。", "自是明時不巡幸，至今青海有龍孫。"]'),
('yuding-105','樂游原','李商隱','唐','御定全唐诗','yuding','','[]','萬樹鳴蟬隔岸虹，樂游原上有西風。',32,'御定全唐詩/json/540.json','["萬樹鳴蟬隔岸虹，樂游原上有西風。", "羲和自趁虞泉宿，不放斜陽更向東。"]'),
('yuding-106','贈荷花','李商隱','唐','御定全唐诗','yuding','','[]','世間花葉不相倫，花入金盆葉作塵。惟有綠荷紅菡萏，',24,'御定全唐詩/json/540.json','["世間花葉不相倫，花入金盆葉作塵。惟有綠荷紅菡萏，"]'),
('yuding-107','丹丘','李商隱','唐','御定全唐诗','yuding','','[]','青女丁寧結夜霜，羲和辛苦送朝陽。',32,'御定全唐詩/json/540.json','["青女丁寧結夜霜，羲和辛苦送朝陽。", "丹丘萬里無消息，幾對梧桐憶鳳凰。"]'),
('yuding-108','房君珊瑚散','李商隱','唐','御定全唐诗','yuding','','[]','不見姮娥影，清秋守月輪。月中閑杵臼，桂子搗成塵。',24,'御定全唐詩/json/540.json','["不見姮娥影，清秋守月輪。月中閑杵臼，桂子搗成塵。"]'),
('yuding-109','小桃園','李商隱','唐','御定全唐诗','yuding','','[]','竟日小桃園，休寒亦未暄。坐鶯當酒重，送客出牆繁。',48,'御定全唐詩/json/540.json','["竟日小桃園，休寒亦未暄。坐鶯當酒重，送客出牆繁。", "啼久豔粉薄，舞多香雪翻。猶憐未圓月，先出照黃昏。"]'),
('yuding-110','嘲櫻桃','李商隱','唐','御定全唐诗','yuding','','[]','朱實鳥含盡，青樓人未歸。南園無限樹，獨自葉如幃。',24,'御定全唐詩/json/540.json','["朱實鳥含盡，青樓人未歸。南園無限樹，獨自葉如幃。"]'),
('yuding-111','和張秀才落花有感','李商隱','唐','御定全唐诗','yuding','','[]','晴暖感餘芳，紅苞雜絳房。落時猶自舞，掃後更聞香。',48,'御定全唐詩/json/540.json','["晴暖感餘芳，紅苞雜絳房。落時猶自舞，掃後更聞香。", "夢罷收羅薦，仙歸敕玉箱。回腸九回後，猶有剩回腸。"]'),
('yuding-112','代越公房妓嘲徐公主','李商隱','唐','御定全唐诗','yuding','','[]','笑啼俱不敢，幾欲是吞聲。遽遣離琴怨，都由半鏡明。',36,'御定全唐詩/json/540.json','["笑啼俱不敢，幾欲是吞聲。遽遣離琴怨，都由半鏡明。", "應防啼與笑，微露淺深情。"]'),
('yuding-113','代貴公主','李商隱','唐','御定全唐诗','yuding','','[]','芳條得意紅，飄落忽西東。分逐春風去，風回得故叢。',36,'御定全唐詩/json/540.json','["芳條得意紅，飄落忽西東。分逐春風去，風回得故叢。", "明朝金井露，始看憶春風。"]'),
('yuding-114','鳳','李商隱','唐','御定全唐诗','yuding','','[]','萬里峰巒歸路迷，未判容彩借山雞。',32,'御定全唐詩/json/540.json','["萬里峰巒歸路迷，未判容彩借山雞。", "新春定有將雛樂，阿閣華池兩處棲。"]'),
('yuding-115','昭肅皇帝挽歌辭三首','李商隱','唐','御定全唐诗','yuding','','[]','九縣懷雄武，三靈仰睿文。周王傳叔父，漢後重神君。',144,'御定全唐詩/json/540.json','["九縣懷雄武，三靈仰睿文。周王傳叔父，漢後重神君。", "玉律朝驚露，金莖夜切雲。笳簫淒欲斷，無複詠橫汾。", "玉塞驚宵柝，金橋罷舉烽。始巢阿閣鳳，旋駕鼎湖龍。", "門咽通神鼓，樓凝警夜鐘。小臣觀吉從，猶誤欲東封。", "莫驗昭華管，虛傳甲帳神。海迷求藥使，雪隔獻桃人。", "桂寢青雲斷，松扉白露新。萬方同象鳥，舉慟滿秋塵。"]'),
('yuding-116','梓州罷吟寄同舍','李商隱','唐','御定全唐诗','yuding','','[]','不揀花朝與雪朝，五年從事霍嫖姚。君緣接座交珠履，',40,'御定全唐詩/json/540.json','["不揀花朝與雪朝，五年從事霍嫖姚。君緣接座交珠履，", "長吟遠下燕台去，惟有衣香染未銷。"]'),
('yuding-117','無題二首','李商隱','唐','御定全唐诗','yuding','','[]','鳳尾香羅薄幾重，碧文圓頂夜深縫。扇裁月魄羞難掩，',80,'御定全唐詩/json/540.json','["鳳尾香羅薄幾重，碧文圓頂夜深縫。扇裁月魄羞難掩，", "斑騅只系垂楊岸，何處西南任好風。", "重帷深下莫愁堂，臥後清宵細細長。神女生涯原是夢，", "直道相思了無益，未妨惆悵是清狂。"]'),
('yuding-118','病中早訪招國李十將軍遇挈家游曲江','李商隱','唐','御定全唐诗','yuding','','[]','十頃平波溢岸清，病來惟夢此中行。',32,'御定全唐詩/json/540.json','["十頃平波溢岸清，病來惟夢此中行。", "相如未是真消渴，猶放沱江過錦城。"]'),
('yuding-119','昨日','李商隱','唐','御定全唐诗','yuding','','[]','昨日紫姑神去也，今朝青鳥使來賒。未容言語還分散，',40,'御定全唐詩/json/540.json','["昨日紫姑神去也，今朝青鳥使來賒。未容言語還分散，", "平明鐘後更何事，笑倚牆邊梅樹花。"]'),
('yuding-120','櫻桃花下','李商隱','唐','御定全唐诗','yuding','','[]','流鶯舞蝶兩相欺，不取花芳正結時。',32,'御定全唐詩/json/540.json','["流鶯舞蝶兩相欺，不取花芳正結時。", "他日未開今日謝，嘉辰長短是參差。"]'),
('yuding-121','故驛迎吊故桂府常侍有感','李商隱','唐','御定全唐诗','yuding','','[]','饑烏翻樹晚雞啼，泣過秋原沒馬泥。',32,'御定全唐詩/json/540.json','["饑烏翻樹晚雞啼，泣過秋原沒馬泥。", "二紀征南恩與舊，此時丹旐玉山西。"]'),
('yuding-122','槿花','李商隱','唐','御定全唐诗','yuding','','[]','風露淒淒秋景繁，可憐榮落在朝昏。',32,'御定全唐詩/json/540.json','["風露淒淒秋景繁，可憐榮落在朝昏。", "未央宮裏三千女，但保紅顏莫保恩。"]'),
('yuding-123','暮秋獨游曲江','李商隱','唐','御定全唐诗','yuding','','[]','荷葉生時春恨生，荷葉枯時秋恨成。',32,'御定全唐詩/json/540.json','["荷葉生時春恨生，荷葉枯時秋恨成。", "深知身在情長在，悵望江頭江水聲。"]'),
('yuding-124','任弘農尉獻州刺史乞假還京','李商隱','唐','御定全唐诗','yuding','','[]','黃昏封印點刑徒，愧負荊山入座隅。',32,'御定全唐詩/json/540.json','["黃昏封印點刑徒，愧負荊山入座隅。", "卻羨卞和雙刖足，一生無複沒階趨。"]'),
('yuding-125','贈句芒神','李商隱','唐','御定全唐诗','yuding','','[]','佳期不定春期賒，春物夭閼興咨嗟。',32,'御定全唐詩/json/540.json','["佳期不定春期賒，春物夭閼興咨嗟。", "願得句芒索青女，不教容易損年華。"]'),
('yuding-126','無愁果有愁曲北齊歌','李商隱','唐','御定全唐诗','yuding','','[]','東有青龍西白虎，中含福星包世度。玉壺渭水笑清潭，',64,'御定全唐詩/json/540.json','["東有青龍西白虎，中含福星包世度。玉壺渭水笑清潭，", "秋娥點滴不成淚，十二玉樓無故釘。推煙唾月拋千里，", "日暮向風牽短絲，血凝血散今誰是。"]'),
('yuding-127','房中曲','李商隱','唐','御定全唐诗','yuding','','[]','薔薇泣幽素，翠帶花錢小。嬌郎癡若雲，抱日西簾曉。',96,'御定全唐詩/json/540.json','["薔薇泣幽素，翠帶花錢小。嬌郎癡若雲，抱日西簾曉。", "枕是龍宮石，割得秋波色。玉簟失柔膚，但見蒙羅碧。", "憶得前年春，未語含悲辛。歸來已不見，錦瑟長於人。", "今日澗底松，明日山頭檗。愁到天池翻，相看不相識。"]'),
('yuding-128','齊梁晴雲','李商隱','唐','御定全唐诗','yuding','','[]','緩逐煙波起，如妒柳綿飄。故臨飛閣度，欲入回陂銷。',48,'御定全唐詩/json/540.json','["緩逐煙波起，如妒柳綿飄。故臨飛閣度，欲入回陂銷。", "縈歌憐畫扇，敞景弄柔條。更奈天南位，牛渚宿殘宵。"]'),
('yuding-129','效徐陵體贈更衣','李商隱','唐','御定全唐诗','yuding','','[]','密帳真珠絡，溫幃翡翠裝。楚腰知便寵，宮眉正鬥強。',48,'御定全唐詩/json/540.json','["密帳真珠絡，溫幃翡翠裝。楚腰知便寵，宮眉正鬥強。", "結帶懸梔子，繡領刺鴛鴦。輕寒衣省夜，金鬥熨沈香。"]'),
('yuding-130','又效江南曲','李商隱','唐','御定全唐诗','yuding','','[]','郎船安兩槳，儂舸動雙橈。掃黛開宮額，裁裙約楚腰。',48,'御定全唐詩/json/540.json','["郎船安兩槳，儂舸動雙橈。掃黛開宮額，裁裙約楚腰。", "乖期方積思，臨酒欲拌嬌。莫以采菱唱，欲羨秦台簫。"]'),
('yuding-131','月夜重寄宋華陽姊妹','李商隱','唐','御定全唐诗','yuding','','[]','偷桃竊藥事難兼，十二城中鎖彩蟾。',32,'御定全唐詩/json/540.json','["偷桃竊藥事難兼，十二城中鎖彩蟾。", "應共三英同夜賞，玉樓仍是水精簾。"]'),
('yuding-132','訪人不遇留別館','李商隱','唐','御定全唐诗','yuding','','[]','卿卿不惜鎖窗春，去作長楸走馬身。',32,'御定全唐詩/json/540.json','["卿卿不惜鎖窗春，去作長楸走馬身。", "閑倚繡簾吹柳絮，日高深院斷無人。"]'),
('yuding-133','雨中長樂水館送趙十五滂不及','李商隱','唐','御定全唐诗','yuding','','[]','碧雲東去雨雲西，苑路高高驛路低。',32,'御定全唐詩/json/540.json','["碧雲東去雨雲西，苑路高高驛路低。", "秋水綠蕪終盡分，夫君太騁錦障泥。"]'),
('yuding-134','汴上送李郢之蘇州','李商隱','唐','御定全唐诗','yuding','','[]','人高詩苦滯夷門，萬里梁王有舊園。煙幌自應憐白紵，',40,'御定全唐詩/json/540.json','["人高詩苦滯夷門，萬里梁王有舊園。煙幌自應憐白紵，", "蘇小小墳今在否，紫蘭香徑與招魂。"]'),
('yuding-135','贈鄭讜處士','李商隱','唐','御定全唐诗','yuding','','[]','浪跡江湖白髮新，浮雲一片是吾身。寒歸山觀隨棋局，',40,'御定全唐詩/json/540.json','["浪跡江湖白髮新，浮雲一片是吾身。寒歸山觀隨棋局，", "相逢一笑憐疏放，他日扁舟有故人。"]'),
('yuding-136','複至裴明府所居','李商隱','唐','御定全唐诗','yuding','','[]','伊人卜築自幽深，桂巷杉籬不可尋。柱上雕蟲對書字，',40,'御定全唐詩/json/540.json','["伊人卜築自幽深，桂巷杉籬不可尋。柱上雕蟲對書字，", "賒取松醪一鬥酒，與君相伴灑煩襟。"]'),
('yuding-137','覽古','李商隱','唐','御定全唐诗','yuding','','[]','莫恃金湯忽太平，草間霜露古今情。空糊赬壤真何益，',40,'御定全唐詩/json/540.json','["莫恃金湯忽太平，草間霜露古今情。空糊赬壤真何益，", "回頭一吊箕山客，始信逃堯不為名。"]'),
('yuding-138','子初郊墅','李商隱','唐','御定全唐诗','yuding','','[]','看山對酒君思我，聽鼓離城我訪君。臘雪已添牆下水，',40,'御定全唐詩/json/540.json','["看山對酒君思我，聽鼓離城我訪君。臘雪已添牆下水，", "亦擬村南買煙舍，子孫相約事耕耘。"]'),
('yuding-139','漢南書事','李商隱','唐','御定全唐诗','yuding','','[]','西師萬眾幾時回，哀痛天書近已裁。文吏何曾重刀筆，',40,'御定全唐詩/json/540.json','["西師萬眾幾時回，哀痛天書近已裁。文吏何曾重刀筆，", "陛下好生千萬壽，玉樓長禦白雲杯。"]'),
('yuding-140','當句有對','李商隱','唐','御定全唐诗','yuding','','[]','密邇平陽接上蘭，秦樓鴛瓦漢宮盤。池光不定花光亂，',40,'御定全唐詩/json/540.json','["密邇平陽接上蘭，秦樓鴛瓦漢宮盤。池光不定花光亂，", "三星自轉三山遠，紫府程遙碧落寬。"]'),
('yuding-141','井絡','李商隱','唐','御定全唐诗','yuding','','[]','井絡天彭一掌中，漫誇天設劍為峰。陣圖東聚燕江石，',40,'御定全唐詩/json/540.json','["井絡天彭一掌中，漫誇天設劍為峰。陣圖東聚燕江石，", "將來為報奸雄輩，莫向金牛訪舊蹤。"]'),
('yuding-142','寫意','李商隱','唐','御定全唐诗','yuding','','[]','燕雁迢迢隔上林，高秋望斷正長吟。人間路有潼江險，',40,'御定全唐詩/json/540.json','["燕雁迢迢隔上林，高秋望斷正長吟。人間路有潼江險，", "三年已制思鄉淚，更入新年恐不禁。"]'),
('yuding-143','隨師東','李商隱','唐','御定全唐诗','yuding','','[]','東征日調萬黃金，幾竭中原買鬥心。軍令未聞誅馬謖，',40,'御定全唐詩/json/540.json','["東征日調萬黃金，幾竭中原買鬥心。軍令未聞誅馬謖，", "可惜前朝玄菟郡，積骸成莽陣雲深。"]'),
('yuding-144','宋玉','李商隱','唐','御定全唐诗','yuding','','[]','何事荊台百萬家，惟教宋玉擅才華。楚辭已不饒唐勒，',40,'御定全唐詩/json/540.json','["何事荊台百萬家，惟教宋玉擅才華。楚辭已不饒唐勒，", "可憐庾信尋荒徑，猶得三朝托後車。"]'),
('yuding-145','韓同年新居餞韓西迎家室戲贈','李商隱','唐','御定全唐诗','yuding','','[]','籍籍征西萬戶侯，新緣貴婿起朱樓。一名我漫居先甲，',40,'御定全唐詩/json/540.json','["籍籍征西萬戶侯，新緣貴婿起朱樓。一名我漫居先甲，", "南朝禁臠無人近，瘦盡瓊枝詠四愁。"]'),
('yuding-146','奉和太原公送前楊秀才戴兼招楊正字戎','李商隱','唐','御定全唐诗','yuding','','[]','潼關地接古弘農，萬里高飛雁與鴻。桂樹一枝當白日，',40,'御定全唐詩/json/540.json','["潼關地接古弘農，萬里高飛雁與鴻。桂樹一枝當白日，", "誰憚士龍多笑疾，美髭終類晉司空。"]'),
('yuding-147','池邊','李商隱','唐','御定全唐诗','yuding','','[]','玉管葭灰細細吹，流鶯上下燕參差。',32,'御定全唐詩/json/540.json','["玉管葭灰細細吹，流鶯上下燕參差。", "日西千繞池邊樹，憶把枯條撼雪時。"]'),
('yuding-148','賈生','李商隱','唐','御定全唐诗','yuding','','[]','宣室求賢訪逐臣，賈生才調更無倫。',32,'御定全唐詩/json/540.json','["宣室求賢訪逐臣，賈生才調更無倫。", "可憐夜半虛前席，不問蒼生問鬼神。"]'),
('yuding-149','送王十三校書分司','李商隱','唐','御定全唐诗','yuding','','[]','多少分曹掌秘文，洛陽花雪夢隨君。',32,'御定全唐詩/json/540.json','["多少分曹掌秘文，洛陽花雪夢隨君。", "定知何遜緣聯句，每到城東憶範雲。"]'),
('yuding-150','寄惱韓同年二首','李商隱','唐','御定全唐诗','yuding','','[]','簾外辛夷定已開，開時莫放豔陽回。',64,'御定全唐詩/json/540.json','["簾外辛夷定已開，開時莫放豔陽回。", "年華若到經風雨，便是胡僧話劫灰。", "龍山晴雪鳳樓霞，洞裏迷人有幾家。", "我為傷春心自醉，不勞君勸石榴花。"]'),
('yuding-151','謁山','李商隱','唐','御定全唐诗','yuding','','[]','從來系日乏長繩，水去雲回恨不勝。',32,'御定全唐詩/json/540.json','["從來系日乏長繩，水去雲回恨不勝。", "欲就麻姑買滄海，一杯春露冷如冰。"]'),
('yuding-152','鈞天','李商隱','唐','御定全唐诗','yuding','','[]','上帝鈞天會眾靈，昔人因夢到青冥。',32,'御定全唐詩/json/540.json','["上帝鈞天會眾靈，昔人因夢到青冥。", "伶倫吹裂孤生竹，卻為知音不得聽。"]'),
('yuding-153','失猿','李商隱','唐','御定全唐诗','yuding','','[]','祝融南去萬重雲，清嘯無因更一聞。',32,'御定全唐詩/json/540.json','["祝融南去萬重雲，清嘯無因更一聞。", "莫遣碧江通箭道，不教腸斷憶同群。"]'),
('yuding-154','戲題友人壁','李商隱','唐','御定全唐诗','yuding','','[]','花徑逶迤柳巷深，小闌亭午囀春禽。',32,'御定全唐詩/json/540.json','["花徑逶迤柳巷深，小闌亭午囀春禽。", "相如解作長門賦，卻用文君取酒金。"]'),
('yuding-155','假日','李商隱','唐','御定全唐诗','yuding','','[]','素琴弦斷酒瓶空，倚坐欹眠日已中。',32,'御定全唐詩/json/540.json','["素琴弦斷酒瓶空，倚坐欹眠日已中。", "誰向劉靈天幕內，更當陶令北窗風。"]'),
('yuding-156','寄遠','李商隱','唐','御定全唐诗','yuding','','[]','姮娥搗藥無時已，玉女投壺未肯休。',32,'御定全唐詩/json/540.json','["姮娥搗藥無時已，玉女投壺未肯休。", "何日桑田俱變了，不教伊水向東流。"]'),
('yuding-157','王昭君','李商隱','唐','御定全唐诗','yuding','','[]','毛延壽畫欲通神，忍為黃金不顧人。',32,'御定全唐詩/json/540.json','["毛延壽畫欲通神，忍為黃金不顧人。", "馬上琵琶行萬里，漢宮長有隔生春。"]'),
('yuding-158','舊將軍','李商隱','唐','御定全唐诗','yuding','','[]','雲台高議正紛紛，誰定當時蕩寇勳。',32,'御定全唐詩/json/540.json','["雲台高議正紛紛，誰定當時蕩寇勳。", "日暮灞陵原上獵，李將軍是故將軍。"]'),
('yuding-159','曼倩辭','李商隱','唐','御定全唐诗','yuding','','[]','十八年來墮世間，瑤池歸夢碧桃閑。',32,'御定全唐詩/json/540.json','["十八年來墮世間，瑤池歸夢碧桃閑。", "如何漢殿穿針夜，又向窗中覷阿環。"]'),
('yuding-160','所居','李商隱','唐','御定全唐诗','yuding','','[]','窗下尋書細，溪邊坐石平。水風醒酒病，霜日曝衣輕。',48,'御定全唐詩/json/540.json','["窗下尋書細，溪邊坐石平。水風醒酒病，霜日曝衣輕。", "雞黍隨人設，蒲魚得地生。前賢無不謂，容易即遺名。"]'),
('yuding-161','高松','李商隱','唐','御定全唐诗','yuding','','[]','高松出眾木，伴我向天涯。客散初晴候，僧來不語時。',48,'御定全唐詩/json/540.json','["高松出眾木，伴我向天涯。客散初晴候，僧來不語時。", "有風傳雅韻，無雪試幽姿。上藥終相待，他年訪伏龜。"]'),
('yuding-162','訪秋','李商隱','唐','御定全唐诗','yuding','','[]','酒薄吹還醒，樓危望已窮。江皋當落日，帆席見歸風。',48,'御定全唐詩/json/540.json','["酒薄吹還醒，樓危望已窮。江皋當落日，帆席見歸風。", "煙帶龍潭白，霞分鳥道紅。殷勤報秋意，只是有丹楓。"]'),
('yuding-163','昭州','李商隱','唐','御定全唐诗','yuding','','[]','桂水春猶早，昭川日正西。虎當官道鬥，猿上驛樓啼。',48,'御定全唐詩/json/540.json','["桂水春猶早，昭川日正西。虎當官道鬥，猿上驛樓啼。", "繩爛金沙井，松幹乳洞梯。鄉音殊可駭，仍有醉如泥。"]'),
('yuding-164','哭劉司戶蕡','李商隱','唐','御定全唐诗','yuding','','[]','路有論冤謫，言皆在中興。空聞遷賈誼，不待相孫弘。',48,'御定全唐詩/json/540.json','["路有論冤謫，言皆在中興。空聞遷賈誼，不待相孫弘。", "江闊惟回首，天高但撫膺。去年相送地，春雪滿黃陵。"]'),
('yuding-165','裴明府居止','李商隱','唐','御定全唐诗','yuding','','[]','愛君茅屋下，向晚水溶溶。試墨書新竹，張琴和古松。',48,'御定全唐詩/json/540.json','["愛君茅屋下，向晚水溶溶。試墨書新竹，張琴和古松。", "坐來聞好鳥，歸去度疏鐘。明日還相見，橋南貰酒醲。"]'),
('yuding-166','陸發荊南始至商洛','李商隱','唐','御定全唐诗','yuding','','[]','昔去真無奈，今還豈自知。青辭木奴橘，紫見地仙芝。',48,'御定全唐詩/json/540.json','["昔去真無奈，今還豈自知。青辭木奴橘，紫見地仙芝。", "四海秋風闊，千岩暮景遲。向來憂際會，猶有五湖期。"]'),
('yuding-167','陳後宮','李商隱','唐','御定全唐诗','yuding','','[]','玄武開新苑，龍舟宴幸頻。渚蓮參法駕，沙鳥犯句陳。',48,'御定全唐詩/json/540.json','["玄武開新苑，龍舟宴幸頻。渚蓮參法駕，沙鳥犯句陳。", "壽獻金莖露，歌翻玉樹塵。夜來江令醉，別詔宿臨春。"]'),
('yuding-168','樂游原','李商隱','唐','御定全唐诗','yuding','','[]','春夢亂不記，春原登已重。青門弄煙柳，紫閣舞雲松。',48,'御定全唐詩/json/540.json','["春夢亂不記，春原登已重。青門弄煙柳，紫閣舞雲松。", "拂硯輕冰散，開尊綠酎濃。無悰托詩遣，吟罷更無悰。"]'),
('yuding-169','贈子直花下','李商隱','唐','御定全唐诗','yuding','','[]','池光忽隱牆，花氣亂侵房。屏緣蝶留粉，窗油蜂印黃。',48,'御定全唐詩/json/540.json','["池光忽隱牆，花氣亂侵房。屏緣蝶留粉，窗油蜂印黃。", "官書推小吏，侍史從清郎。並馬更吟去，尋思有底忙。"]'),
('yuding-170','小園獨酌','李商隱','唐','御定全唐诗','yuding','','[]','柳帶誰能結，花房未肯開。空餘雙蝶舞，竟絕一人來。',48,'御定全唐詩/json/540.json','["柳帶誰能結，花房未肯開。空餘雙蝶舞，竟絕一人來。", "半展龍須席，輕斟瑪瑙杯。年年春不定，虛信歲前梅。"]'),
('yuding-171','思歸','李商隱','唐','御定全唐诗','yuding','','[]','固有樓堪倚，能無酒可傾。嶺雲春沮洳，江月夜晴明。',48,'御定全唐詩/json/540.json','["固有樓堪倚，能無酒可傾。嶺雲春沮洳，江月夜晴明。", "魚亂書何托，猿哀夢易驚。舊居連上苑，時節正遷鶯。"]'),
('yuding-172','獻寄舊府開封公','李商隱','唐','御定全唐诗','yuding','','[]','幕府三年遠，春秋一字褒。書論秦逐客，賦續楚離騷。',48,'御定全唐詩/json/540.json','["幕府三年遠，春秋一字褒。書論秦逐客，賦續楚離騷。", "地理南溟闊，天文北極高。酬恩撫身世，未覺勝鴻毛。"]'),
('yuding-173','向晚','李商隱','唐','御定全唐诗','yuding','','[]','當風橫去幰，臨水卷空帷。北土秋千罷，南朝祓禊歸。',48,'御定全唐詩/json/540.json','["當風橫去幰，臨水卷空帷。北土秋千罷，南朝祓禊歸。", "花情羞脈脈，柳意悵微微。莫歎佳期晚，佳期自古稀。"]'),
('yuding-174','春遊','李商隱','唐','御定全唐诗','yuding','','[]','橋峻斑騅疾，川長白鳥高。煙輕惟潤柳，風濫欲吹桃。',48,'御定全唐詩/json/540.json','["橋峻斑騅疾，川長白鳥高。煙輕惟潤柳，風濫欲吹桃。", "徙倚三層閣，摩挲七寶刀。庾郎年最少，青草妒春袍。"]'),
('yuding-175','離席','李商隱','唐','御定全唐诗','yuding','','[]','出宿金尊掩，從公玉帳新。依依向餘照，遠遠隔芳塵。',48,'御定全唐詩/json/540.json','["出宿金尊掩，從公玉帳新。依依向餘照，遠遠隔芳塵。", "細草翻驚雁，殘花伴醉人。楊朱不用勸，只是更沾巾。"]'),
('yuding-176','俳諧','李商隱','唐','御定全唐诗','yuding','','[]','短顧何由遂，遲光且莫驚。鶯能歌子夜，蝶解舞宮城。',48,'御定全唐詩/json/540.json','["短顧何由遂，遲光且莫驚。鶯能歌子夜，蝶解舞宮城。", "柳訝眉雙淺，桃猜粉太輕。年華有情狀，吾豈怯平生。"]'),
('yuding-177','細雨','李商隱','唐','御定全唐诗','yuding','','[]','蕭灑傍回汀，依微過短亭。氣涼先動竹，點細未開萍。',48,'御定全唐詩/json/540.json','["蕭灑傍回汀，依微過短亭。氣涼先動竹，點細未開萍。", "稍促高高燕，微疏的的螢。故園煙草色，仍近五門青。"]'),
('yuding-178','商於新開路','李商隱','唐','御定全唐诗','yuding','','[]','六百商于路，崎嶇古共聞。蜂房春欲暮，虎阱日初曛。',48,'御定全唐詩/json/540.json','["六百商于路，崎嶇古共聞。蜂房春欲暮，虎阱日初曛。", "路向泉間辨，人從樹杪分。更誰開捷徑，速擬上青雲。"]'),
('yuding-179','題鄭大有隱居','李商隱','唐','御定全唐诗','yuding','','[]','結構何峰是，喧閑此地分。石樑高瀉月，樵路細侵雲。',48,'御定全唐詩/json/540.json','["結構何峰是，喧閑此地分。石樑高瀉月，樵路細侵雲。", "偃臥蛟螭室，希夷鳥獸群。近知西嶺上，玉管有時聞。"]'),
('yuding-180','夜飲','李商隱','唐','御定全唐诗','yuding','','[]','卜夜容衰鬢，開筵屬異方。燭分歌扇淚，雨送酒船香。',48,'御定全唐詩/json/540.json','["卜夜容衰鬢，開筵屬異方。燭分歌扇淚，雨送酒船香。", "江海三年客，乾坤百戰場。誰能辭酩酊，淹臥劇清漳。"]'),
('yuding-181','江上','李商隱','唐','御定全唐诗','yuding','','[]','萬里風來地，清江北望樓。雲通梁苑路，月帶楚城秋。',48,'御定全唐詩/json/540.json','["萬里風來地，清江北望樓。雲通梁苑路，月帶楚城秋。", "刺字從漫滅，歸途尚阻修。前程更煙水，吾道豈淹留。"]'),
('yuding-182','涼思','李商隱','唐','御定全唐诗','yuding','','[]','客去波平檻，蟬休露滿枝。永懷當此節，倚立自移時。',48,'御定全唐詩/json/540.json','["客去波平檻，蟬休露滿枝。永懷當此節，倚立自移時。", "北斗兼春遠，南陵寓使遲。天涯占夢數，疑誤有新知。"]'),
('yuding-183','鸞鳳','李商隱','唐','御定全唐诗','yuding','','[]','舊鏡鸞何處，衰桐鳳不棲。金錢饒孔雀，錦段落山雞。',48,'御定全唐詩/json/540.json','["舊鏡鸞何處，衰桐鳳不棲。金錢饒孔雀，錦段落山雞。", "王子調清管，天人降紫泥。豈無雲路分，相望不應迷。"]'),
('yuding-184','李衛公','李商隱','唐','御定全唐诗','yuding','','[]','絳紗弟子音塵絕，鸞鏡佳人舊會稀。',32,'御定全唐詩/json/540.json','["絳紗弟子音塵絕，鸞鏡佳人舊會稀。", "今日致身歌舞地，木棉花暖鷓鴣飛。"]'),
('yuding-185','韋蟾','李商隱','唐','御定全唐诗','yuding','','[]','謝家離別正淒涼，少傅臨岐賭佩囊。',32,'御定全唐詩/json/540.json','["謝家離別正淒涼，少傅臨岐賭佩囊。", "卻憶短亭回首處，夜來煙雨滿池塘。"]'),
('yuding-186','自貺','李商隱','唐','御定全唐诗','yuding','','[]','陶令棄官後，仰眠書屋中。誰將五斗米，擬換北窗風。',24,'御定全唐詩/json/540.json','["陶令棄官後，仰眠書屋中。誰將五斗米，擬換北窗風。"]'),
('yuding-187','蝶','李商隱','唐','御定全唐诗','yuding','','[]','孤蝶小徘徊，翩翾粉翅開。並應傷皎潔，頻近雪中來。',24,'御定全唐詩/json/540.json','["孤蝶小徘徊，翩翾粉翅開。並應傷皎潔，頻近雪中來。"]'),
('yuding-188','夜意','李商隱','唐','御定全唐诗','yuding','','[]','簾垂幕半卷，枕冷被仍香。如何為相憶，魂夢過瀟湘。',24,'御定全唐詩/json/540.json','["簾垂幕半卷，枕冷被仍香。如何為相憶，魂夢過瀟湘。"]'),
('yuding-189','因書','李商隱','唐','御定全唐诗','yuding','','[]','絕徼南通棧，孤城北枕江。猿聲連月檻，鳥影落天窗。',48,'御定全唐詩/json/540.json','["絕徼南通棧，孤城北枕江。猿聲連月檻，鳥影落天窗。", "海石分棋子，郫筒當酒缸。生歸話辛苦，別夜對凝釭。"]'),
('yuding-190','奉寄安國大師兼簡子蒙','李商隱','唐','御定全唐诗','yuding','','[]','憶奉蓮花座，兼聞貝葉經。岩光分蠟屐，澗響入銅瓶。',48,'御定全唐詩/json/540.json','["憶奉蓮花座，兼聞貝葉經。岩光分蠟屐，澗響入銅瓶。", "日下徒推鶴，天涯正對螢。魚山羨曹植，眷屬有文星。"]'),
('yuding-191','閒遊','李商隱','唐','御定全唐诗','yuding','','[]','危亭題竹粉，曲沼嗅荷花。數日同攜酒，平明不在家。',48,'御定全唐詩/json/540.json','["危亭題竹粉，曲沼嗅荷花。數日同攜酒，平明不在家。", "尋幽殊未極，得句總堪誇。強下西樓去，西樓倚暮霞。"]'),
('yuding-192','縣中惱飲席','李商隱','唐','御定全唐诗','yuding','','[]','晚醉題詩贈物華，罷吟還醉忘歸家。',32,'御定全唐詩/json/540.json','["晚醉題詩贈物華，罷吟還醉忘歸家。", "若無江氏五色筆，爭奈河陽一縣花。"]'),
('yuding-193','題李上謨壁','李商隱','唐','御定全唐诗','yuding','','[]','舊著思玄賦，新編雜擬詩。江庭猶近別，山捨得幽期。',48,'御定全唐詩/json/540.json','["舊著思玄賦，新編雜擬詩。江庭猶近別，山捨得幽期。", "嫩割周顒韭，肥烹鮑照葵。飽聞南燭酒，仍及撥醅時。"]'),
('yuding-194','江村題壁','李商隱','唐','御定全唐诗','yuding','','[]','沙岸竹森森，維艄聽越禽。數家同老壽，一逕自陰深。',48,'御定全唐詩/json/540.json','["沙岸竹森森，維艄聽越禽。數家同老壽，一逕自陰深。", "喜客嘗留橘，應官說採金。傾壺真得地，愛日靜霜砧。"]'),
('yuding-195','即日','李商隱','唐','御定全唐诗','yuding','','[]','桂林聞舊說，曾不異炎方。山響匡床語，花飄度臘香。',48,'御定全唐詩/json/540.json','["桂林聞舊說，曾不異炎方。山響匡床語，花飄度臘香。", "幾時逢雁足，著處斷猿腸。獨撫青青桂，臨城憶雪霜。"]'),
('yuding-196','漫成五章','李商隱','唐','御定全唐诗','yuding','','[]','沈宋裁辭矜變律，王楊落筆得良朋。',160,'御定全唐詩/json/540.json','["沈宋裁辭矜變律，王楊落筆得良朋。", "當時自謂宗師妙，今日惟觀對屬能。", "李杜操持事略齊，三才萬象共端倪。", "集仙殿與金鑾殿，可是蒼蠅惑曙雞。", "生兒古有孫征虜，嫁女今無王右軍。", "借問琴書終一世，何如旗蓋仰三分。", "代北偏師銜使節，關中裨將建行台。", "不妨常日饒輕薄，且喜臨戎用草萊。", "郭令素心非黷武，韓公本意在和戎。", "兩都耆舊偏垂淚，臨老中原見朔風。"]'),
('yuding-197','射魚曲','李商隱','唐','御定全唐诗','yuding','','[]','思牢弩箭磨青石，繡額蠻渠三虎力。尋潮背日伺泅鱗，',40,'御定全唐詩/json/540.json','["思牢弩箭磨青石，繡額蠻渠三虎力。尋潮背日伺泅鱗，", "含冰漢語遠于天，何由回作金盤死。"]'),
('yuding-198','日高','李商隱','唐','御定全唐诗','yuding','','[]','鍍鐶故錦縻輕拖，玉xC不動便門鎖。水精眠夢是何人，',41,'御定全唐詩/json/540.json','["鍍鐶故錦縻輕拖，玉xC不動便門鎖。水精眠夢是何人，", "輕身滅影何可望，粉蛾帖死屏風上。"]'),
('yuding-199','宮中曲','李商隱','唐','御定全唐诗','yuding','','[]','雲母濾宮月，夜夜白于水。賺得羊車來，低扇遮黃子。',72,'御定全唐詩/json/540.json','["雲母濾宮月，夜夜白于水。賺得羊車來，低扇遮黃子。", "水精不覺冷，自刻鴛鴦翅。蠶縷茜香濃，正朝纏左臂。", "巴箋兩三幅，滿寫承恩字。欲得識青天，昨夜蒼龍是。"]'),
('yuding-200','海上謠','李商隱','唐','御定全唐诗','yuding','','[]','桂水寒于江，玉兔秋冷咽。海底覓仙人，香桃如瘦骨。',68,'御定全唐詩/json/540.json','["桂水寒于江，玉兔秋冷咽。海底覓仙人，香桃如瘦骨。", "紫鸞不肯舞，滿翅蓬山雪。借得龍堂寬，曉出揲雲發。", "劉郎舊香炷，立見茂陵樹。雲孫帖帖臥秋煙，"]'),
('yuding-201','李夫人三首','李商隱','唐','御定全唐诗','yuding','','[]','一帶不結心，兩股方安髻。慚愧白茅人，月沒教星替。',92,'御定全唐詩/json/540.json','["一帶不結心，兩股方安髻。慚愧白茅人，月沒教星替。", "剩結茱萸枝，多擘秋蓮的。獨自有波光，彩囊盛不得。", "蠻絲系條脫，妍眼和香屑。壽宮不惜鑄南人，", "不知瘦骨類冰井，更許夜簾通曉霜。土花漠漠雲茫茫，"]'),
('yuding-202','景陽宮井雙桐','李商隱','唐','御定全唐诗','yuding','','[]','秋港菱花幹，玉盤明月蝕。血滲兩枯心，情多去未得。',116,'御定全唐詩/json/540.json','["秋港菱花幹，玉盤明月蝕。血滲兩枯心，情多去未得。", "徒經白門伴，不見丹山客。未待刻作人，愁多有魂魄。", "誰將玉盤與，不死翻相誤。天更闊于江，孫枝覓郎主。", "昔妒鄰宮槐，道類雙眉斂。今日繁紅櫻，拋人占長簟。", "翠襦不禁綻，留淚啼天眼。寒灰劫盡問方知，"]'),
('yuding-203','秋日晚思','李商隱','唐','御定全唐诗','yuding','','[]','桐槿日零落，雨餘方寂寥。枕寒莊蝶去，窗冷胤螢銷。',48,'御定全唐詩/json/540.json','["桐槿日零落，雨餘方寂寥。枕寒莊蝶去，窗冷胤螢銷。", "取適琴將酒，忘名牧與樵。平生有遊舊，一一在煙霄。"]'),
('yuding-204','春宵自遣','李商隱','唐','御定全唐诗','yuding','','[]','地勝遺塵事，身閑念歲華。晚晴風過竹，深夜月當花。',48,'御定全唐詩/json/540.json','["地勝遺塵事，身閑念歲華。晚晴風過竹，深夜月當花。", "石亂知泉咽，苔荒任徑斜。陶然恃琴酒，忘卻在山家。"]'),
('yuding-205','七夕偶題','李商隱','唐','御定全唐诗','yuding','','[]','寶婺搖珠佩，常娥照玉輪。靈歸天上匹，巧遺世間人。',48,'御定全唐詩/json/540.json','["寶婺搖珠佩，常娥照玉輪。靈歸天上匹，巧遺世間人。", "花果香千戶，笙竽濫四鄰。明朝曬犢鼻，方信阮家貧。"]'),
('yuding-206','靈仙閣晚眺寄鄆州韋評事','李商隱','唐','御定全唐诗','yuding','','[]','愚公方住穀，仁者本依山。共誓林泉志，胡為尊俎間。',96,'御定全唐詩/json/540.json','["愚公方住穀，仁者本依山。共誓林泉志，胡為尊俎間。", "華蓮開菡萏，荊玉刻孱顏。爽氣臨周道，嵐光入漢關。", "滿壺從蟻泛，高閣已苔斑。想就安車召，寧期負矢還。", "潘游全璧散，郭去半舟閑。定笑幽人跡，鴻軒不可攀。"]'),
('yuding-207','幽居冬暮','李商隱','唐','御定全唐诗','yuding','','[]','羽翼摧殘日，郊園寂寞時。曉雞驚樹雪，寒鶩守冰池。',48,'御定全唐詩/json/540.json','["羽翼摧殘日，郊園寂寞時。曉雞驚樹雪，寒鶩守冰池。", "急景忽雲暮，頹年浸已衰。如何匡國分，不與夙心期。"]'),
('yuding-208','過姚孝子廬偶書','李商隱','唐','御定全唐诗','yuding','','[]','拱木臨周道，荒廬積古苔。魚因感薑出，鶴為吊陶來。',48,'御定全唐詩/json/540.json','["拱木臨周道，荒廬積古苔。魚因感薑出，鶴為吊陶來。", "兩鬢蓬常亂，雙眸血不開。聖朝敦爾類，非獨路人哀。"]'),
('yuding-209','賦得月照冰池','李商隱','唐','御定全唐诗','yuding','','[]','皓月方離海，堅冰正滿池。金波雙激射，璧彩兩參差。',96,'御定全唐詩/json/540.json','["皓月方離海，堅冰正滿池。金波雙激射，璧彩兩參差。", "影占徘徊處，光含的皪時。高低連素色，上下接清規。", "顧兔飛難定，潛魚躍未期。鵲驚俱欲繞，狐聽始無疑。", "似鏡將盈手，如霜恐透肌。獨憐遊玩意，達曉不知疲。"]'),
('yuding-210','永樂縣所居一草一木無非自栽今春悉已芳茂因書即事一章','李商隱','唐','御定全唐诗','yuding','','[]','手種悲陳事，心期玩物華。柳飛彭澤雪，桃散武陵霞。',72,'御定全唐詩/json/540.json','["手種悲陳事，心期玩物華。柳飛彭澤雪，桃散武陵霞。", "枳嫩棲鸞葉，桐香待鳳花。綬藤縈弱蔓，袍草展新芽。", "學植功雖倍，成蹊跡尚賒。芳年誰共玩，終老邵平瓜。"]'),
('yuding-211','南潭上亭宴集以疾後至因而抒情','李商隱','唐','御定全唐诗','yuding','','[]','馬卿聊應召，謝傅已登山。歌發百花外，樂調深竹間。',72,'御定全唐詩/json/540.json','["馬卿聊應召，謝傅已登山。歌發百花外，樂調深竹間。", "鷁舟縈遠岸，魚鑰啟重關。鶯蝶如相引，煙蘿不暇攀。", "佳人啟玉齒，上客頷朱顏。肯念沉痾士，俱期倒載還。"]'),
('yuding-212','寒食行次冷泉驛','李商隱','唐','御定全唐诗','yuding','','[]','驛途仍近節，旅宿倍思家。獨夜三更月，空庭一樹花。',48,'御定全唐詩/json/540.json','["驛途仍近節，旅宿倍思家。獨夜三更月，空庭一樹花。", "介山當驛秀，汾水繞關斜。自怯春寒苦，那堪禁火賒。"]'),
('yuding-213','寄華岳孫逸人','李商隱','唐','御定全唐诗','yuding','','[]','靈嶽幾千仞，老松逾百尋。攀崖仍躡壁，啖葉複眠陰。',48,'御定全唐詩/json/540.json','["靈嶽幾千仞，老松逾百尋。攀崖仍躡壁，啖葉複眠陰。", "海上呼三島，齋中戲五禽。唯應逢阮籍，長嘯作鸞音。"]'),
('yuding-214','戲題贈稷山驛吏王全','李商隱','唐','御定全唐诗','yuding','','[]','絳台驛吏老風塵，耽酒成仙幾十春。',32,'御定全唐詩/json/540.json','["絳台驛吏老風塵，耽酒成仙幾十春。", "過客不勞詢甲子，惟書亥字與時人。"]'),
('yuding-215','和韋潘前輩七月十二日夜泊池州城下先寄上李使君','李商隱','唐','御定全唐诗','yuding','','[]','桂含爽氣三秋首，蓂吐中旬二葉新。',32,'御定全唐詩/json/540.json','["桂含爽氣三秋首，蓂吐中旬二葉新。", "正是澄江如練處，玄暉應喜見詩人。"]'),
('yuding-216','花下醉','李商隱','唐','御定全唐诗','yuding','','[]','尋芳不覺醉流霞，倚樹沉眠日已斜。',32,'御定全唐詩/json/540.json','["尋芳不覺醉流霞，倚樹沉眠日已斜。", "客散酒醒深夜後，更持紅燭賞殘花。"]'),
('yuding-217','所居永樂縣久旱，縣宰祈禱得雨，因賦詩','李商隱','唐','御定全唐诗','yuding','','[]','甘膏滴滴是精誠，晝夜如絲一尺盈。',32,'御定全唐詩/json/540.json','["甘膏滴滴是精誠，晝夜如絲一尺盈。", "只怪閭閻喧鼓吹，邑人同報朿長生。"]'),
('yuding-0','正月十五夜聞京有燈，恨不得觀','李商隱','唐','御定全唐诗','yuding','','[]','月色燈光滿帝都，香車寶輦隘通衢。',32,'御定全唐詩/json/541.json','["月色燈光滿帝都，香車寶輦隘通衢。", "身閑不睹中興盛，羞逐鄉人賽紫姑。"]'),
('yuding-1','贈趙協律皙','李商隱','唐','御定全唐诗','yuding','','[]','俱識孫公與謝公，二年歌哭處還同。已叨鄒馬聲華末，',40,'御定全唐詩/json/541.json','["俱識孫公與謝公，二年歌哭處還同。已叨鄒馬聲華末，", "不堪歲暮相逢地，我欲西征君又東。"]'),
('yuding-2','搖落','李商隱','唐','御定全唐诗','yuding','','[]','搖落傷年日，羈留念遠心。水亭吟斷續，月幌夢飛沉。',96,'御定全唐詩/json/541.json','["搖落傷年日，羈留念遠心。水亭吟斷續，月幌夢飛沉。", "古木含風久，疏螢怯露深。人閑始遙夜，地迥更清砧。", "結愛曾傷晚，端憂複至今。未諳滄海路，何處玉山岑。", "灘激黃牛暮，雲屯白帝陰。遙知沾灑意，不減欲分襟。"]'),
('yuding-3','滯雨','李商隱','唐','御定全唐诗','yuding','','[]','滯雨長安夜，殘燈獨客愁。故鄉雲水地，歸夢不宜秋。',24,'御定全唐詩/json/541.json','["滯雨長安夜，殘燈獨客愁。故鄉雲水地，歸夢不宜秋。"]'),
('yuding-4','偶題二首','李商隱','唐','御定全唐诗','yuding','','[]','小亭閑眠微醉消，山榴海柏枝相交。',64,'御定全唐詩/json/541.json','["小亭閑眠微醉消，山榴海柏枝相交。", "水文簟上琥珀枕，傍有墮釵雙翠翹。", "清月依微香露輕，曲房小院多逢迎。", "春叢定見饒棲鳥，飲罷莫持紅燭行。"]'),
('yuding-5','月','李商隱','唐','御定全唐诗','yuding','','[]','過水穿樓觸處明，藏人帶樹遠含清。',32,'御定全唐詩/json/541.json','["過水穿樓觸處明，藏人帶樹遠含清。", "初生欲缺虛惆悵，未必圓時即有情。"]'),
('yuding-6','夜冷','李商隱','唐','御定全唐诗','yuding','','[]','樹繞池寬月影多，村砧塢笛隔風蘿。',32,'御定全唐詩/json/541.json','["樹繞池寬月影多，村砧塢笛隔風蘿。", "西亭翠被餘香薄，一夜將愁向敗荷。"]'),
('yuding-7','正月崇讓宅','李商隱','唐','御定全唐诗','yuding','','[]','密鎖重關掩綠苔，廊深閣迥此徘徊。先知風起月含暈，',40,'御定全唐詩/json/541.json','["密鎖重關掩綠苔，廊深閣迥此徘徊。先知風起月含暈，", "背燈獨共餘香語，不覺猶歌起夜來。"]'),
('yuding-8','城外','李商隱','唐','御定全唐诗','yuding','','[]','露寒風定不無情，臨水當山又隔城。',32,'御定全唐詩/json/541.json','["露寒風定不無情，臨水當山又隔城。", "未必明時勝蚌蛤，一生長共月虧盈。"]'),
('yuding-9','撰彭陽公志文畢有感','李商隱','唐','御定全唐诗','yuding','','[]','延陵留表墓，峴首送沈碑。敢伐不加點，猶當無愧辭。',48,'御定全唐詩/json/541.json','["延陵留表墓，峴首送沈碑。敢伐不加點，猶當無愧辭。", "百生終莫報，九死諒難追。待得生金後，川原亦幾移。"]'),
('yuding-10','北青蘿','李商隱','唐','御定全唐诗','yuding','','[]','殘陽西入崦，茅屋訪孤僧。落葉人何在，寒雲路幾層。',48,'御定全唐詩/json/541.json','["殘陽西入崦，茅屋訪孤僧。落葉人何在，寒雲路幾層。", "獨敲初夜磬，閑倚一枝藤。世界微塵裏，吾寧愛與憎。"]'),
('yuding-11','戲贈張書記','李商隱','唐','御定全唐诗','yuding','','[]','別館君孤枕，空庭我閉關。池光不受月，野氣欲沉山。',72,'御定全唐詩/json/541.json','["別館君孤枕，空庭我閉關。池光不受月，野氣欲沉山。", "星漢秋方會，關河夢幾還。危弦傷遠道，明鏡惜紅顏。", "古木含風久，平蕪盡日閑。心知兩愁絕，不斷若尋環。"]'),
('yuding-12','幽人','李商隱','唐','御定全唐诗','yuding','','[]','丹灶三年火，蒼崖萬歲藤。樵歸說逢虎，棋罷正留僧。',48,'御定全唐詩/json/541.json','["丹灶三年火，蒼崖萬歲藤。樵歸說逢虎，棋罷正留僧。", "星斗同秦分，人煙接漢陵。東流清渭苦，不盡照衰興。"]'),
('yuding-13','念遠','李商隱','唐','御定全唐诗','yuding','','[]','日月淹秦甸，江湖動越吟。蒼桐應露下，白閣自雲深。',72,'御定全唐詩/json/541.json','["日月淹秦甸，江湖動越吟。蒼桐應露下，白閣自雲深。", "皎皎非鸞扇，翹翹失鳳簪。床空鄂君被，杵冷女媭砧。", "北思驚沙雁，南情屬海禽。關山已搖落，天地共登臨。"]'),
('yuding-14','過故崔兗海宅與崔明秀才話舊因寄舊僚杜趙李三掾','李商隱','唐','御定全唐诗','yuding','','[]','絳帳恩如昨，烏衣事莫尋。諸生空會葬，舊掾已華簪。',48,'御定全唐詩/json/541.json','["絳帳恩如昨，烏衣事莫尋。諸生空會葬，舊掾已華簪。", "共入留賓驛，俱分市駿金。莫憑無鬼論，終負托孤心。"]'),
('yuding-15','微雨','李商隱','唐','御定全唐诗','yuding','','[]','初隨林靄動，稍共夜涼分。窗迥侵燈冷，庭虛近水聞。',24,'御定全唐詩/json/541.json','["初隨林靄動，稍共夜涼分。窗迥侵燈冷，庭虛近水聞。"]'),
('yuding-16','南山趙行軍新詩盛稱遊宴之洽，因寄一絕','李商隱','唐','御定全唐诗','yuding','','[]','蓮幕遙臨黑水津，櫜鞬無事但尋春。',32,'御定全唐詩/json/541.json','["蓮幕遙臨黑水津，櫜鞬無事但尋春。", "梁王司馬非孫武，且免宮中斬美人。"]'),
('yuding-17','曲江','李商隱','唐','御定全唐诗','yuding','','[]','望斷平時翠輦過，空聞子夜鬼悲歌。金輿不返傾城色，',40,'御定全唐詩/json/541.json','["望斷平時翠輦過，空聞子夜鬼悲歌。金輿不返傾城色，", "天荒地變心雖折，若比陽春意未多。"]'),
('yuding-18','景陽井','李商隱','唐','御定全唐诗','yuding','','[]','景陽宮井剩堪悲，不盡龍鸞誓死期。',32,'御定全唐詩/json/541.json','["景陽宮井剩堪悲，不盡龍鸞誓死期。", "腸斷吳王宮外水，濁泥猶得葬西施。"]'),
('yuding-19','故番禺侯以贓罪致不辜，事覺，母者他日過其門','李商隱','唐','御定全唐诗','yuding','','[]','飲鴆非君命，茲身亦厚亡。江陵從種橘，交廣合投香。',48,'御定全唐詩/json/541.json','["飲鴆非君命，茲身亦厚亡。江陵從種橘，交廣合投香。", "不見千金子，空餘數仞牆。殺人須顯戮，誰舉漢三章。"]'),
('yuding-20','詠雲','李商隱','唐','御定全唐诗','yuding','','[]','捧月三更斷，藏星七夕明。才聞飄迥路，旋見隔重城。',48,'御定全唐詩/json/541.json','["捧月三更斷，藏星七夕明。才聞飄迥路，旋見隔重城。", "潭暮隨龍起，河秋壓雁聲。只應惟宋玉，知是楚神名。"]'),
('yuding-21','夜出西溪','李商隱','唐','御定全唐诗','yuding','','[]','東府憂春盡，西溪許日曛。月澄新漲水，星見欲銷雲。',48,'御定全唐詩/json/541.json','["東府憂春盡，西溪許日曛。月澄新漲水，星見欲銷雲。", "柳好休傷別，松高莫出群。軍書雖倚馬，猶未當能文。"]'),
('yuding-22','效長吉','李商隱','唐','御定全唐诗','yuding','','[]','長長漢殿眉，窄窄楚宮衣。鏡好鸞空舞，簾疏燕誤飛。',36,'御定全唐詩/json/541.json','["長長漢殿眉，窄窄楚宮衣。鏡好鸞空舞，簾疏燕誤飛。", "君王不可問，昨夜約黃歸。"]'),
('yuding-23','柳','李商隱','唐','御定全唐诗','yuding','','[]','江南江北雪初消，漠漠輕黃惹嫩條。灞岸已攀行客手，',40,'御定全唐詩/json/541.json','["江南江北雪初消，漠漠輕黃惹嫩條。灞岸已攀行客手，", "如線如絲正牽恨，王孫歸路一何遙。"]'),
('yuding-24','九月於東逢雪','李商隱','唐','御定全唐诗','yuding','','[]','舉家忻共報，秋雪墮前峰。嶺外他年憶，於東此日逢。',48,'御定全唐詩/json/541.json','["舉家忻共報，秋雪墮前峰。嶺外他年憶，於東此日逢。", "粒輕還自亂，花薄未成重。豈是驚離鬢，應來洗病容。"]'),
('yuding-25','四皓廟','李商隱','唐','御定全唐诗','yuding','','[]','本為留侯慕赤松，漢庭方識紫芝翁。',32,'御定全唐詩/json/541.json','["本為留侯慕赤松，漢庭方識紫芝翁。", "蕭何只解追韓信，豈得虛當第一功。"]'),
('yuding-26','送阿龜歸華','李商隱','唐','御定全唐诗','yuding','','[]','草堂歸意背煙蘿，黃綬垂腰不奈何。',32,'御定全唐詩/json/541.json','["草堂歸意背煙蘿，黃綬垂腰不奈何。", "因汝華陽求藥物，碧松根下茯苓多。"]'),
('yuding-27','九日','李商隱','唐','御定全唐诗','yuding','','[]','曾共山翁把酒時，霜天白菊繞階墀。十年泉下無人問，',40,'御定全唐詩/json/541.json','["曾共山翁把酒時，霜天白菊繞階墀。十年泉下無人問，", "郎君官貴施行馬，東閣無因再得窺。"]'),
('yuding-28','僧院牡丹','李商隱','唐','御定全唐诗','yuding','','[]','薄葉風才倚，枝輕霧不勝。開先如避客，色淺為依僧。',48,'御定全唐詩/json/541.json','["薄葉風才倚，枝輕霧不勝。開先如避客，色淺為依僧。", "粉壁正蕩水，緗幃初卷燈。傾城惟待笑，要裂幾多繒。"]'),
('yuding-29','贈司勳杜十三員外','李商隱','唐','御定全唐诗','yuding','','[]','杜牧司勳字牧之，清秋一首杜秋詩。前身應是梁江總，',40,'御定全唐詩/json/541.json','["杜牧司勳字牧之，清秋一首杜秋詩。前身應是梁江總，", "漢江遠吊西江水，羊祜韋丹盡有碑。"]'),
('yuding-30','高花','李商隱','唐','御定全唐诗','yuding','','[]','花將人共笑，籬外露繁枝。宋玉臨江宅，牆低不礙窺。',24,'御定全唐詩/json/541.json','["花將人共笑，籬外露繁枝。宋玉臨江宅，牆低不礙窺。"]'),
('yuding-31','嘲桃','李商隱','唐','御定全唐诗','yuding','','[]','無賴夭桃面，平時露井東。春風為開了，卻擬笑春風。',24,'御定全唐詩/json/541.json','["無賴夭桃面，平時露井東。春風為開了，卻擬笑春風。"]'),
('yuding-32','送豐都李尉','李商隱','唐','御定全唐诗','yuding','','[]','萬古商於地，憑君泣路岐。固難尋綺季，可得信張儀。',48,'御定全唐詩/json/541.json','["萬古商於地，憑君泣路岐。固難尋綺季，可得信張儀。", "雨氣燕先覺，葉陰蟬遽知。望鄉尤忌晚，山晚更參差。"]'),
('yuding-33','天平公座中呈令狐令公時蔡京在坐京曾為僧徒故有第五句','李商隱','唐','御定全唐诗','yuding','','[]','罷執霓旌上醮壇，慢妝嬌樹水晶盤。更深欲訴蛾眉斂，',40,'御定全唐詩/json/541.json','["罷執霓旌上醮壇，慢妝嬌樹水晶盤。更深欲訴蛾眉斂，", "雖然同是將軍客，不敢公然子細看。"]'),
('yuding-34','江上憶嚴五廣休','李商隱','唐','御定全唐诗','yuding','','[]','征南幕下帶長刀，夢筆深藏五色毫。',32,'御定全唐詩/json/541.json','["征南幕下帶長刀，夢筆深藏五色毫。", "逢著澄江不敢詠，鎮西留與謝功曹。"]'),
('yuding-35','餞席重送從叔余之梓州','李商隱','唐','御定全唐诗','yuding','','[]','莫歎萬重山，君還我未還。武關猶悵望，何況百牢關。',24,'御定全唐詩/json/541.json','["莫歎萬重山，君還我未還。武關猶悵望，何況百牢關。"]'),
('yuding-36','訪隱','李商隱','唐','御定全唐诗','yuding','','[]','路到層峰斷，門依老樹開。月從平楚轉，泉自上方來。',48,'御定全唐詩/json/541.json','["路到層峰斷，門依老樹開。月從平楚轉，泉自上方來。", "薤白羅朝饌，松黃暖夜杯。相留笑孫綽，空解賦天臺。"]'),
('yuding-37','寓興','李商隱','唐','御定全唐诗','yuding','','[]','薄宦仍多病，從知竟遠遊。談諧叨客禮，休浣接冥搜。',48,'御定全唐詩/json/541.json','["薄宦仍多病，從知竟遠遊。談諧叨客禮，休浣接冥搜。", "樹好頻移榻，雲奇不下樓。豈關無景物，自是有鄉愁。"]'),
('yuding-38','東南','李商隱','唐','御定全唐诗','yuding','','[]','東南一望日中烏，欲逐羲和去得無。',32,'御定全唐詩/json/541.json','["東南一望日中烏，欲逐羲和去得無。", "且向秦樓棠樹下，每朝先覓照羅敷。"]'),
('yuding-39','歸來','李商隱','唐','御定全唐诗','yuding','','[]','舊隱無何別，歸來始更悲。難尋白道士，不見惠禪師。',48,'御定全唐詩/json/541.json','["舊隱無何別，歸來始更悲。難尋白道士，不見惠禪師。", "草徑蟲鳴急，沙渠水下遲。卻將波浪眼，清曉對紅梨。"]'),
('yuding-40','子直晉昌李花','李商隱','唐','御定全唐诗','yuding','','[]','吳館何時熨，秦台幾夜熏。綃輕誰解卷，香異自先聞。',48,'御定全唐詩/json/541.json','["吳館何時熨，秦台幾夜熏。綃輕誰解卷，香異自先聞。", "月裏誰無姊，雲中亦有君。樽前見飄蕩，愁極客襟分。"]'),
('yuding-41','河清與趙氏昆季宴集得擬杜工部','李商隱','唐','御定全唐诗','yuding','','[]','勝概殊江右，佳名逼渭川。虹收青嶂雨，鳥沒夕陽天。',48,'御定全唐詩/json/541.json','["勝概殊江右，佳名逼渭川。虹收青嶂雨，鳥沒夕陽天。", "客鬢行如此，滄波坐渺然。此中真得地，漂蕩釣魚船。"]'),
('yuding-42','寓目','李商隱','唐','御定全唐诗','yuding','','[]','園桂懸心碧，池蓮飫眼紅。此生真遠客，幾別即衰翁。',48,'御定全唐詩/json/541.json','["園桂懸心碧，池蓮飫眼紅。此生真遠客，幾別即衰翁。", "小幌風煙入，高窗霧雨通。新知他日好，錦瑟傍朱櫳。"]'),
('yuding-43','題道靜院院在中條山故王顏中丞所置虢州刺史捨官居此今寫真存焉','李商隱','唐','御定全唐诗','yuding','','[]','紫府丹成化鶴群，青松手植變龍文。壺中別有仙家日，',40,'御定全唐詩/json/541.json','["紫府丹成化鶴群，青松手植變龍文。壺中別有仙家日，", "自憐築室靈山下，徒望朝嵐與夕曛。"]'),
('yuding-44','賦得桃李無言','李商隱','唐','御定全唐诗','yuding','','[]','夭桃花正發，穠李蕊方繁。應候非爭豔，成蹊不在言。',72,'御定全唐詩/json/541.json','["夭桃花正發，穠李蕊方繁。應候非爭豔，成蹊不在言。", "靜中霞暗吐，香處雪潛翻。得意搖風態，含情泣露痕。", "芬芳光上苑，寂默委中園。赤白徒自許，幽芳誰與論。"]'),
('yuding-45','登霍山驛樓','李商隱','唐','御定全唐诗','yuding','','[]','廟列前峰迥，樓開四望窮。嶺鼷嵐色外，陂雁夕陽中。',48,'御定全唐詩/json/541.json','["廟列前峰迥，樓開四望窮。嶺鼷嵐色外，陂雁夕陽中。", "弱柳千條露，衰荷一面風。壺關有狂孽，速繼老生功。"]'),
('yuding-46','寄和水部馬郎中題興德驛，時昭義已平','李商隱','唐','御定全唐诗','yuding','','[]','仙郎倦去心，鄭驛暫登臨。水色瀟湘闊，沙程朔漠深。',48,'御定全唐詩/json/541.json','["仙郎倦去心，鄭驛暫登臨。水色瀟湘闊，沙程朔漠深。", "鷁舟時往復，鷗鳥恣浮沉。更想逢歸馬，悠悠嶽樹陰。"]'),
('yuding-47','題小松','李商隱','唐','御定全唐诗','yuding','','[]','憐君孤秀植庭中，細葉輕陰滿座風。桃李盛時雖寂寞，',40,'御定全唐詩/json/541.json','["憐君孤秀植庭中，細葉輕陰滿座風。桃李盛時雖寂寞，", "為謝西園車馬客，定悲搖落盡成空。"]'),
('yuding-48','行次昭應縣道上，送戶部李郎中充昭義攻討','李商隱','唐','御定全唐诗','yuding','','[]','將軍大旆掃狂童，詔選名賢贊武功。暫逐虎牙臨故絳，',40,'御定全唐詩/json/541.json','["將軍大旆掃狂童，詔選名賢贊武功。暫逐虎牙臨故絳，", "早勒勳庸燕石上，佇光綸綍漢廷中。"]'),
('yuding-49','水齋','李商隱','唐','御定全唐诗','yuding','','[]','多病欣依有道邦，南塘宴起想秋江。捲簾飛燕還拂水，',40,'御定全唐詩/json/541.json','["多病欣依有道邦，南塘宴起想秋江。捲簾飛燕還拂水，", "誰人為報故交道，莫惜鯉魚時一雙。"]'),
('yuding-50','奉同諸公題河中任中丞新創河亭四韻之作','李商隱','唐','御定全唐诗','yuding','','[]','萬里誰能訪十洲，新亭雲構壓中流。河鮫縱玩難為室，',40,'御定全唐詩/json/541.json','["萬里誰能訪十洲，新亭雲構壓中流。河鮫縱玩難為室，", "獨留巧思傳千古，長與蒲津作勝遊。"]'),
('yuding-51','過故府中武威公交城舊莊感事','李商隱','唐','御定全唐诗','yuding','','[]','信陵亭館接郊畿，幽象遙通晉水祠。日落高門喧燕雀，',40,'御定全唐詩/json/541.json','["信陵亭館接郊畿，幽象遙通晉水祠。日落高門喧燕雀，", "山下只今黃絹字，淚痕猶墮六州兒。"]'),
('yuding-52','贈田叟','李商隱','唐','御定全唐诗','yuding','','[]','荷筱衰翁似有情，相逢攜手繞村行。燒畬曉映遠山色，',40,'御定全唐詩/json/541.json','["荷筱衰翁似有情，相逢攜手繞村行。燒畬曉映遠山色，", "撫躬地道誠感激，在野無賢心自驚。"]'),
('yuding-53','贈別前蔚州契苾使君','李商隱','唐','御定全唐诗','yuding','','[]','何年部落到陰陵，奕世勤王國史稱。夜卷牙旗千帳雪，',40,'御定全唐詩/json/541.json','["何年部落到陰陵，奕世勤王國史稱。夜卷牙旗千帳雪，", "日晚鸊鵜泉畔獵，路人遙識郅都鷹。"]'),
('yuding-54','和人題真娘墓','李商隱','唐','御定全唐诗','yuding','','[]','虎丘山下劍池邊，長遣遊人歎逝川。罥樹斷絲悲舞席，',40,'御定全唐詩/json/541.json','["虎丘山下劍池邊，長遣遊人歎逝川。罥樹斷絲悲舞席，", "一自香魂招不得，只應江上獨嬋娟。"]'),
('yuding-55','人日即事','李商隱','唐','御定全唐诗','yuding','','[]','文王喻複今朝是，子晉吹笙此日同。舜格有苗旬太遠，',40,'御定全唐詩/json/541.json','["文王喻複今朝是，子晉吹笙此日同。舜格有苗旬太遠，", "獨想道衡詩思苦，離家恨得二年中。"]'),
('yuding-56','春日寄懷','李商隱','唐','御定全唐诗','yuding','','[]','世間榮落重逡巡，我獨丘園坐四春。縱使有花兼有月，',40,'御定全唐詩/json/541.json','["世間榮落重逡巡，我獨丘園坐四春。縱使有花兼有月，", "欲逐風波千萬里，未知何路到龍津。"]'),
('yuding-57','和劉評事永樂閒居見寄','李商隱','唐','御定全唐诗','yuding','','[]','白社幽閒君暫居，青雲器業我全疏。看封諫草歸鸞掖，',40,'御定全唐詩/json/541.json','["白社幽閒君暫居，青雲器業我全疏。看封諫草歸鸞掖，", "自探典籍忘名利，欹枕時驚落蠹魚。"]'),
('yuding-58','和馬郎中移白菊見示','李商隱','唐','御定全唐诗','yuding','','[]','陶詩只采黃金實，郢曲新傳白雪英。素色不同籬下發，',40,'御定全唐詩/json/541.json','["陶詩只采黃金實，郢曲新傳白雪英。素色不同籬下發，", "偏稱含香五字客，從茲得地始芳榮。"]'),
('yuding-59','喜聞太原同院崔侍禦台拜兼寄在台三二同年之什','李商隱','唐','御定全唐诗','yuding','','[]','鵬魚何事遇屯同，雲水升沉一會中。劉放未歸雞樹老，',40,'御定全唐詩/json/541.json','["鵬魚何事遇屯同，雲水升沉一會中。劉放未歸雞樹老，", "若向南台見鶯友，為傳垂翅度春風。"]'),
('yuding-60','喜雪','李商隱','唐','御定全唐诗','yuding','','[]','朔雪自龍沙，呈祥勢可嘉。有田皆種玉，無樹不開花。',120,'御定全唐詩/json/541.json','["朔雪自龍沙，呈祥勢可嘉。有田皆種玉，無樹不開花。", "班扇慵裁素，曹衣詎比麻。鵝歸逸少宅，鶴滿令威家。", "寂寞門扉掩，依稀履跡斜。人疑游面市，馬似困鹽車。", "洛水妃虛妒，姑山客漫誇。聯辭雖許謝，和曲本慚巴。", "粉署闈全隔，霜台路正賒。此時傾賀酒，相望在京華。"]'),
('yuding-61','柳枝五首','李商隱','唐','御定全唐诗','yuding','','[]','花房與蜜脾，蜂雄蛺蝶雌。同時不同類，那複更相思。',120,'御定全唐詩/json/541.json','["花房與蜜脾，蜂雄蛺蝶雌。同時不同類，那複更相思。", "本是丁香樹，春條結始生。玉作彈棋局，中心亦不平。", "嘉瓜引蔓長，碧玉冰寒漿。東陵雖五色，不忍值牙香。", "柳枝井上蟠，蓮葉浦中幹。錦鱗與繡羽，水陸有傷殘。", "畫屏繡步障，物物自成雙。如何湖上望，只是見鴛鴦。"]'),
('yuding-62','燕台四首：春','李商隱','唐','御定全唐诗','yuding','','[]','風光冉冉東西陌，幾日嬌魂尋不得。蜜房羽客類芳心，',88,'御定全唐詩/json/541.json','["風光冉冉東西陌，幾日嬌魂尋不得。蜜房羽客類芳心，", "雄龍雌鳳杳何許，絮亂絲繁天亦迷。醉起微陽若初曙，", "衣帶無情有寬窄，春煙自碧秋霜白。研丹擘石天不知，", "今日東風自不勝，化作幽光入西海。"]'),
('yuding-63','燕台四首：夏','李商隱','唐','御定全唐诗','yuding','','[]','前閣雨簾愁不卷，後堂芳樹陰陰見。石城景物類黃泉，',72,'御定全唐詩/json/541.json','["前閣雨簾愁不卷，後堂芳樹陰陰見。石城景物類黃泉，", "蜀魂寂寞有伴未，幾夜瘴花開木棉。桂宮留影光難取，", "濁水清波何異源，濟河水清黃河渾。安得薄霧起緗裙，"]'),
('yuding-64','燕台四首：秋','李商隱','唐','御定全唐诗','yuding','','[]','月浪沖天天宇濕，涼蟾落盡疏星入。雲屏不動掩孤嚬，',88,'御定全唐詩/json/541.json','["月浪沖天天宇濕，涼蟾落盡疏星入。雲屏不動掩孤嚬，", "但聞北斗聲回環，不見長河水清淺。金魚鎖斷紅桂春，", "瑤琴愔愔藏楚弄，越羅冷薄金泥重。簾鉤鸚鵡夜驚霜，", "歌唇一世銜雨看，可惜馨香手中故。"]'),
('yuding-65','燕台四首：冬','李商隱','唐','御定全唐诗','yuding','','[]','天東日出天西下，雌鳳孤飛女龍寡。青溪白石不相望，',72,'御定全唐詩/json/541.json','["天東日出天西下，雌鳳孤飛女龍寡。青溪白石不相望，", "浪乘畫舸憶蟾蜍，月娥未必嬋娟子。楚管蠻弦愁一概，", "破鬟矮墮淩朝寒，白玉燕釵黃金蟬。風車雨馬不持去，"]'),
('yuding-66','河內詩二首','李商隱','唐','御定全唐诗','yuding','','[]','鼉鼓沉沉虯水咽，秦絲不上蠻弦絕。常娥衣薄不禁寒，',112,'御定全唐詩/json/541.json','["鼉鼓沉沉虯水咽，秦絲不上蠻弦絕。常娥衣薄不禁寒，", "靈香不下兩皇子，孤星直上相風竿。八桂林邊九芝草，", "梔子交加香蓼繁，停辛佇苦留待君。", "閶門日下吳歌遠，陂路綠菱香滿滿。後溪暗起鯉魚風，", "莫因風雨罷團扇，此曲斷腸惟北聲。低樓小徑城南道，"]'),
('yuding-67','贈送前劉五經映三十四韻','李商隱','唐','御定全唐诗','yuding','','[]','建國宜師古，興邦屬上庠。從來以儒戲，安得振朝綱。',408,'御定全唐詩/json/541.json','["建國宜師古，興邦屬上庠。從來以儒戲，安得振朝綱。", "叔世何多難，茲基遂已亡。泣麟猶委吏，歌鳳更佯狂。", "屋壁餘無幾，焚坑逮可傷。挾書秦二世，壞宅漢諸王。", "草草臨盟誓，區區務富強。微茫金馬署，狼藉鬥雞場。", "盡欲心無竅，皆如面正牆。驚疑豹文鼠，貪竊虎皮羊。", "南渡宜終否，西遷冀小康。策非方正士，貢絕孝廉郎。", "海鳥悲鐘鼓，狙公畏服裳。多岐空擾擾，幽室竟倀倀。", "凝邈為時範，虛空作士常。何由羞五霸，直自呰三皇。", "別派驅楊墨，他鑣並老莊。詩書資破塚，法制困探囊。", "周禮仍存魯，隋師果禪唐。鼎新麾一舉，革故法三章。", "星宿森文雅，風雷起退藏。縲囚為學切，掌故受經忙。", "夫子時之彥，先生跡未荒。褐衣終不召，白首興難忘。", "感激殊非聖，棲遲到異粻。片辭褒有德，一字貶無良。", "燕地尊鄒衍，西河重卜商。式閭真道在，擁彗信謙光。", "獲預青衿列，叨來絳帳旁。雖從各言志，還要大為防。", "勿謂孤寒棄，深憂訐直妨。叔孫讒易得，盜蹠暴難當。", "雁下秦雲黑，蟬休隴葉黃。莫逾巾屨念，容許後升堂。"]'),
('yuding-68','哭遂州蕭侍郎二十四韻','李商隱','唐','御定全唐诗','yuding','','[]','遙作時多難，先令禍有源。初驚逐客議，旋駭黨人冤。',288,'御定全唐詩/json/541.json','["遙作時多難，先令禍有源。初驚逐客議，旋駭黨人冤。", "密侍榮方入，司刑望愈尊。皆因優詔用，實有諫書存。", "苦霧三辰沒，窮陰四塞昏。虎威狐更假，隼擊鳥逾喧。", "徒欲心存闕，終遭耳屬垣。遺音和蜀魄，易簀對巴猿。", "有女悲初寡，無男泣過門。朝爭屈原草，廟餒莫敖魂。", "迥閣傷神峻，長江極望翻。青雲寧寄意，白骨始沾恩。", "早歲思東閣，為邦屬故園。登舟慚郭泰，解榻愧陳蕃。", "分以忘年契，情猶錫類敦。公先真帝子，我系本王孫。", "嘯傲張高蓋，從容接短轅。秋吟小山桂，春醉後堂萱。", "自歎離通籍，何嘗忘叫閽。不成穿壙入，終擬上書論。", "多士還魚貫，雲誰正駿奔。暫能誅倏忽，長與問乾坤。", "蟻漏三泉路，螿啼百草根。始知同泰講，徼福是虛言。"]'),
('yuding-69','送千牛李將軍赴闕五十韻','李商隱','唐','御定全唐诗','yuding','','[]','照席瓊枝秀，當年紫綬榮。班資古直閣，勳伐舊西京。',576,'御定全唐詩/json/541.json','["照席瓊枝秀，當年紫綬榮。班資古直閣，勳伐舊西京。", "在昔王綱紊，因誰國步清。如無一戰霸，安有大橫庚。", "內豎依憑切，凶門責望輕。中台終惡直，上將更要盟。", "丹陛祥煙滅，皇闈殺氣橫。喧闐眾狙怒，容易八蠻驚。", "檮杌寬之久，防風戮不行。素來矜異類，此去豈親征。", "舍魯真非策，居邠未有名。曾無力牧禦，甯待雨師迎。", "火箭侵乘石，雲橋逼禁營。何時絕刁鬥，不夜見欃槍。", "屢亦聞投鼠，誰其敢射鯨。世情休念亂，物議笑輕生。", "大鹵思龍躍，蒼梧失象耕。靈衣沾愧汗，儀馬困陰兵。", "別館蘭熏酷，深宮蠟焰明。黃山遮舞態，黑水斷歌聲。", "縱未移周鼎，何辭免趙坑。空拳轉鬥地，數板不沈城。", "且欲憑神算，無因計力爭。幽囚蘇武節，棄市仲由纓。", "下殿言終驗，增埤事早萌。蒸雞殊減膳，屑麹異和羹。", "否極時還泰，屯餘運果亨。流離幾南渡，倉卒得西平。", "神鬼收昏黑，奸凶首滿盈。官非督護貴，師以丈人貞。", "覆載還高下，寒暄急改更。馬前烹莽卓，壇上揖韓彭。", "扈蹕三才正，回軍六合晴。此時惟短劍，仍世盡雙旌。", "顧我由群從，逢君歎老成。慶流歸嫡長，貽厥在名卿。", "隼擊須當要，鵬摶莫問程。趨朝排玉座，出位泣金莖。", "幸藉梁園賦，叨蒙許氏評。中郎推貴婿，定遠重時英。", "政已標三尚，人今佇一鳴。長刀懸月魄，快馬駭星精。", "披豁慚深眷，睽離動素誠。蕙留春晼晚，松待歲崢嶸。", "異縣期回雁，登時已飯鯖。去程風刺刺，別夜漏丁丁。", "庾信生多感，楊朱死有情。弦危中婦瑟，甲冷想夫箏。"]'),
('yuding-70','詠懷寄秘閣舊僚二十六韻','李商隱','唐','御定全唐诗','yuding','','[]','年鬢日堪悲，衡茅益自嗤。攻文枯若木，處世鈍如錘。',288,'御定全唐詩/json/541.json','["年鬢日堪悲，衡茅益自嗤。攻文枯若木，處世鈍如錘。", "敢忘垂堂戒，寧將暗室欺。懸頭曾苦學，折臂反成醫。", "僕禦嫌夫懦，孩童笑叔癡。小男方嗜栗，幼女漫憂葵。", "遇炙誰先啖，逢齏即便吹。官銜同畫餅，面貌乏凝脂。", "典籍將蠡測，文章若管窺。圖形翻類狗，入夢肯非羆。", "自哂成書簏，終當咒酒卮。懶沾襟上血，羞鑷鏡中絲。", "橐鑰言方喻，樗蒱齒詎知。事神徒惕慮，佞佛愧虛辭。", "曲藝垂麟角，浮名狀虎皮。乘軒寧見寵，巢幕更逢危。", "禮俗拘嵇喜，侯王忻戴逵。途窮方結舌，靜勝但支頤。", "糲食空彈劍，亨衢詎置錐。柏台成口號，芸閣暫肩隨。", "悔逐遷鶯伴，誰觀擇虱時。甕間眠太率，床下隱何卑。", "奮跡登弘閣，摧心對董帷。校讎如有暇，松竹一相思。"]'),
('yuding-71','戊辰會靜中出貽同志二十韻','李商隱','唐','御定全唐诗','yuding','','[]','大道諒無外，會越自登真。丹元子何索，在己莫問鄰。',240,'御定全唐詩/json/541.json','["大道諒無外，會越自登真。丹元子何索，在己莫問鄰。", "蒨璨玉琳華，翱翔九真君。戲擲萬里火，聊召六甲旬。", "瑤簡被靈誥，持符開七門。金鈴攝群魔，絳節何兟兟。", "吟弄東海若，笑倚扶桑春。三山誠迥視，九州揚一塵。", "我本玄元胄，稟華由上津。中迷鬼道樂，沉為下土民。", "托質屬太陰，煉形複為人。誓將覆宮澤，安此真與神。", "龜山有慰薦，南真為彌綸。玉管會玄圃，火棗承天姻。", "科車遏故氣，侍香傳靈氛。飄颻被青霓，婀娜佩紫紋。", "林洞何其微，下仙不與群。丹泥因未控，萬劫猶逡巡。", "荊蕪既以薙，舟壑永無湮。相期保妙命，騰景侍帝宸。"]'),
('yuding-72','和鄭愚贈汝陽王孫家箏妓二十韻','李商隱','唐','御定全唐诗','yuding','','[]','冰霧怨何窮，秦絲嬌未已。寒空煙霞高，白日一萬里。',240,'御定全唐詩/json/541.json','["冰霧怨何窮，秦絲嬌未已。寒空煙霞高，白日一萬里。", "碧嶂愁不行，濃翠遙相倚。茜袖捧瓊姿，皎日丹霞起。", "孤猿耿幽寂，西風吹白芷。回首蒼梧深，女蘿閉山鬼。", "荒郊白鱗斷，別浦晴霞委。長彴壓河心，白道連地尾。", "秦人昔富家，綠窗聞妙旨。鴻驚雁背飛，象床殊故里。", "因令五十絲，中道分宮征。鬥粟配新聲，娣侄徒纖指。", "風流大堤上，悵望白門裏。蠹粉實雌弦，燈光冷如水。", "羌管促蠻柱，從醉吳宮耳。滿內不掃眉，君王對西子。", "初花慘朝露，冷臂淒愁髓。一曲送連錢，遠別長於死。", "玉砌銜紅蘭，妝窗結碧綺。九門十二關，清晨禁桃李。"]'),
('yuding-73','四年冬以退居蒲之永樂渴然有農夫望歲之志遂作憶雪又作殘雪詩各一百言以寄情於游舊憶雪','李商隱','唐','御定全唐诗','yuding','','[]','愛景人方樂，同雪候稍愆。徒聞周雅什，願賦朔風篇。',120,'御定全唐詩/json/541.json','["愛景人方樂，同雪候稍愆。徒聞周雅什，願賦朔風篇。", "欲俟千箱慶，須資六出妍。詠留飛絮後，歌唱落梅前。", "庭樹思瓊蕊，妝樓認粉綿。瑞邀盈尺日，豐待兩岐年。", "預約延枚酒，虛乘訪戴船。映書孤志業，披氅阻神仙。", "幾向霜階步，頻將月幌褰。玉京應已足，白屋但顒然。"]'),
('yuding-74','四年冬以退居蒲之永樂渴然有農夫望歲之志遂作憶雪又作殘雪詩各一百言以寄情於游舊憶雪','李商隱','唐','御定全唐诗','yuding','','[]','旭日開晴色，寒空失素塵。繞牆全剝粉，傍井漸消銀。',120,'御定全唐詩/json/541.json','["旭日開晴色，寒空失素塵。繞牆全剝粉，傍井漸消銀。", "刻獸摧鹽虎，為山倒玉人。珠還猶照魏，璧碎尚留秦。", "落日驚侵晝，餘光誤惜春。簷冰滴鵝管，屋瓦鏤魚鱗。", "嶺霽嵐光坼，松暄翠粒新。擁林愁拂盡，著砌恐行頻。", "焦寢忻無患，梁園去有因。莫能知帝力，空此荷平均。"]'),
('yuding-75','大鹵平後移家到永樂縣居書懷十韻寄劉韋二前輩二公嘗於此縣寄居','李商隱','唐','御定全唐诗','yuding','','[]','驅馬繞河幹，家山照露寒。依然五柳在，況值百花殘。',120,'御定全唐詩/json/541.json','["驅馬繞河幹，家山照露寒。依然五柳在，況值百花殘。", "昔去驚投筆，今來分掛冠。不憂懸磬乏，乍喜覆盂安。", "甑破寧回顧，舟沉豈暇看。脫身離虎口，移疾就豬肝。", "鬢入新年白，顏無舊日丹。自悲秋獲少，誰懼夏畦難。", "逸志忘鴻鵠，清香披蕙蘭。還持一杯酒，坐想二公歡。"]'),
('yuding-76','河陽詩','李商隱','唐','御定全唐诗','yuding','','[]','黃河搖溶天上來，玉樓影近中天臺。龍頭瀉酒客壽杯，',144,'御定全唐詩/json/541.json','["黃河搖溶天上來，玉樓影近中天臺。龍頭瀉酒客壽杯，", "可惜秋眸一臠光，漢陵走馬黃塵起。南浦老魚腥古涎，", "憶得蛟絲裁小卓，蛺蝶飛回木綿薄。綠繡笙囊不見人，", "楚絲微覺竹枝高，半曲新辭寫綿紙。巴西夜市紅守宮，", "曉簾串斷蜻蜓翼，羅屏但有空青色。玉灣不釣三千年，", "不知桂樹在何處，仙人不下雙金莖。百尺相風插重屋，"]'),
('yuding-77','自桂林奉使江陵途中感懷寄獻尚書','李商隱','唐','御定全唐诗','yuding','','[]','下客依蓮幕，明公念竹林。縱然膺使命，何以奉徽音。',360,'御定全唐詩/json/541.json','["下客依蓮幕，明公念竹林。縱然膺使命，何以奉徽音。", "投刺雖傷晚，酬恩豈在今。迎來新瑣闥，從到碧瑤岑。", "水勢初知海，天文始識參。固慚非賈誼，惟恐後陳琳。", "前席驚虛辱，華樽許細斟。尚憐秦痔苦，不遣楚醪沈。", "既載從戎筆，仍披選勝襟。瀧通伏波柱，簾對有虞琴。", "宅與嚴城接，門藏別岫深。閣涼松冉冉，堂靜桂森森。", "社內容周續，鄉中保展禽。白衣居士訪，烏帽逸人尋。", "佞佛將成傳，耽書或類淫。長懷五羖贖，終著九州箴。", "良訊封鴛綺，餘光借玳簪。張衡愁浩浩，沈約瘦愔愔。", "蘆白疑粘鬢，楓丹欲照心。歸期無雁報，旅抱有猿侵。", "短日安能駐，低雲只有陰。亂鴉沖曬網，寒女簇遙砧。", "東道違寧久，西園望不禁。江生魂黯黯，泉客淚涔涔。", "逸翰應藏法，高辭肯浪吟。數須傳庾翼，莫獨與盧諶。", "假寐憑書簏，哀吟叩劍鐔。未嘗貪偃息，那復議登臨。", "彼美回清鏡，其誰受曲針。人皆向燕路，無乃費黃金。"]'),
('yuding-78','送從翁從東川弘農尚書幕','李商隱','唐','御定全唐诗','yuding','','[]','大鎮初更帥，嘉賓素見邀。使車無遠近，歸路更煙霄。',360,'御定全唐詩/json/541.json','["大鎮初更帥，嘉賓素見邀。使車無遠近，歸路更煙霄。", "穩放驊騮步，高安翡翠巢。禦風知有在，去國肯無聊。", "早忝諸孫末，俱從小隱招。心懸紫雲閣，夢斷赤城標。", "素女悲清瑟，秦娥弄玉簫。山連玄圃近，水接絳河遙。", "豈意聞周鐸，翻然慕舜韶。皆辭喬木去，遠逐斷蓬飄。", "薄俗誰其激，斯民已甚恌。鸞皇期一舉，燕雀不相饒。", "敢共頹波遠，因之內火燒。是非過別夢，時節慘驚飆。", "未至誰能賦，中幹欲病痟。屢曾紆錦繡，勉欲報瓊瑤。", "我恐霜侵鬢，君先綬掛腰。甘心與陳阮，揮手謝松喬。", "錦裏差鄰接，雲台閉寂寥。一川虛月魄，萬崦自芝苗。", "瘴雨瀧間急，離魂峽外銷。非關無燭夜，其奈落花朝。", "幾處逢鳴佩，何筵不翠翹。蠻童騎象舞，江市賣鮫綃。", "南詔知非敵，西山亦屢驕。勿貪佳麗地，不為聖明朝。", "少減東城飲，時看北斗杓。莫因乖別久，遂逐歲寒凋。", "盛幕開高宴，將軍問故僚。為言公玉季，早日棄漁樵。"]'),
('yuding-79','李肱所遺畫松詩書兩紙得四十韻','李商隱','唐','御定全唐诗','yuding','','[]','萬草已涼露，開圖披古松。青山遍滄海，此樹生何峰。',492,'御定全唐詩/json/541.json','["萬草已涼露，開圖披古松。青山遍滄海，此樹生何峰。", "孤根邈無倚，直立撐鴻蒙。端如君子身，挺若壯士胸。", "樛枝勢夭矯，忽欲蟠拏空。又如驚螭走，默與奔雲逢。", "孫枝擢細葉，旖旎狐裘茸。鄒顛蓐發軟，麗姬眉黛濃。", "視久眩目睛，倏忽變輝容。竦削正稠直，婀娜旋敷峰。", "又如洞房冷，翠被張穹籠。亦若暨羅女，平旦妝顏容。", "細疑襲氣母，猛若爭神功。燕雀固寂寂，霧露常衝衝。", "香蘭愧傷暮，碧竹慚空中。可集呈瑞鳳，堪藏行雨龍。", "淮山桂偃蹇，蜀郡桑重童。枝條亮眇脆，靈氣何由同。", "昔聞咸陽帝，近說稽山儂。或著仙人號，或以大夫封。", "終南與清都，煙雨遙相通。安知夜夜意，不起西南風。", "美人昔清興，重之猶月鐘。寶笥十八九，香緹千萬重。", "一旦鬼瞰室，稠疊張羉罿。赤羽中要害，是非皆匆匆。", "生如碧海月，死踐霜郊蓬。平生握中玩，散失隨奴童。", "我聞照妖鏡，及與神劍鋒。寓身會有地，不為凡物蒙。", "伊人秉茲圖，顧眄擇所從。而我何為者，開顏捧靈蹤。", "報以漆鳴琴，懸之真珠櫳。是時方暑夏，座內若嚴冬。", "憶昔謝四騎，學仙玉陽東。千株盡若此，路入瓊瑤宮。", "口詠玄雲歌，手把金芙蓉。濃藹深霓袖，色映琅玕中。", "悲哉墮世網，去之若遺弓。形魄天壇上，海日高瞳瞳。", "終騎紫鸞歸，持寄扶桑翁。"]'),
('yuding-80','戲題樞言草閣三十二韻','李商隱','唐','御定全唐诗','yuding','','[]','君家在河北，我家在山西。百歲本無業，陰陰仙李枝。',384,'御定全唐詩/json/541.json','["君家在河北，我家在山西。百歲本無業，陰陰仙李枝。", "尚書文與武，戰罷幕府開。君從渭南至，我自仙遊來。", "平昔苦南北，動成雲雨乖。逮今兩攜手，對若床下鞋。", "夜歸碣石館，朝上黃金台。我有苦寒調，君抱陽春才。", "年顏各少壯，發綠齒尚齊。我雖不能飲，君時醉如泥。", "政靜籌畫簡，退食多相攜。掃掠走馬路，整頓射雉翳。", "春風二三月，柳密鶯正啼。清河在門外，上與浮雲齊。", "欹冠調玉琴，彈作松風哀。又彈明君怨，一去怨不回。", "感激坐者泣，起視雁行低。翻憂龍山雪，卻雜胡沙飛。", "仲容銅琵琶，項直聲淒淒。上貼金捍撥，畫為承露雞。", "君時臥掁觸，勸客白玉杯。苦雲年光疾，不飲將安歸。", "我賞此言是，因循未能諧。君言中聖人，坐臥莫我違。", "榆莢亂不整，楊花飛相隨。上有白日照，下有東風吹。", "青樓有美人，顏色如玫瑰。歌聲入青雲，所痛無良媒。", "少年苦不久，顧慕良難哉。徒令真珠肶，裛入珊瑚腮。", "君今且少安，聽我苦吟詩。古詩何人作，老大徒傷悲。"]'),
('yuding-81','偶成轉韻七十二句贈四同舍','李商隱','唐','御定全唐诗','yuding','','[]','沛國東風吹大澤，蒲青柳碧春一色。我來不見隆准人，',288,'御定全唐詩/json/541.json','["沛國東風吹大澤，蒲青柳碧春一色。我來不見隆准人，", "藍山寶肆不可入，玉中仍是青琅玕。武威將軍使中俠，", "詰旦九門傳奏章，高車大馬來煌煌。路逢鄒枚不暇揖，", "眾中賞我賦高唐，回看屈宋由年輩。公事武皇為鐵冠，", "明年赴辟下昭桂，東郊慟哭辭兄弟。韓公堆上跋馬時，", "湘妃廟下已春盡，虞帝城前初日曛。謝游橋上澄江館，", "頃之失職辭南風，破帆壞槳荊江中。斬蛟斷璧不無意，", "天官補吏府中趨，玉骨瘦來無一把。手封狴牢屯制囚，", "舊山萬仞青霞外，望見扶桑出東海。愛君憂國去未能，", "且吟王粲從軍樂，不賦淵明歸去來。彭門十萬皆雄勇，", "之子夫君鄭與裴，何甥謝舅當世才。青袍白簡風流極，", "橫行闊視倚公憐，狂來筆力如牛弩。借酒祝公千萬年，"]'),
('yuding-82','五言述德抒情詩一首四十韻獻上杜七兄僕射相公','李商隱','唐','御定全唐诗','yuding','','[]','帝作黃金闕，仙開白玉京。有人扶太極，惟嶽降元精。',480,'御定全唐詩/json/541.json','["帝作黃金闕，仙開白玉京。有人扶太極，惟嶽降元精。", "耿賈官勳大，荀陳地望清。旗常懸祖德，甲令著嘉聲。", "經出宣尼壁，書留晏子楹。武鄉傳陣法，踐土主文盟。", "自昔流王澤，由來仗國楨。九河分合遝，一柱忽崢嶸。", "得主勞三顧，驚人肯再鳴。碧虛天共轉，黃道日同行。", "後飲曹參酒，先和傅說羹。即時賢路辟，此夜泰階平。", "願保無疆福，將圖不朽名。率身期濟世，叩額慮興兵。", "感念殽屍露，咨嗟趙卒坑。儻令安隱忍，何以贊貞明。", "惡草雖當路，寒松實挺生。人言真可畏，公意本無爭。", "故事留台閣，前驅且旆旌。芙蓉王儉府，楊柳亞夫營。", "清嘯頻疏俗，高談屢析酲。過庭多令子，乞墅有名甥。", "南詔應聞命，西山莫敢驚。寄辭收的博，端坐掃欃槍。", "雅宴初無倦，長歌底有情。檻危春水暖，樓迥雪峰晴。", "移席牽緗蔓，回橈撲絳英。誰知杜武庫，只見謝宣城。", "有客趨高義，於今滯下卿。登門慚後至，置驛恐虛迎。", "自是依劉表，安能比老彭。雕龍心已切，畫虎意何成。", "豈有曾黔突，徒勞不倚衡。乘時乖巧宦，占象合艱貞。", "廢忘淹中學，遲回穀口耕。悼傷潘岳重，樹立馬遷輕。", "隴鳥悲丹觜，湘蘭怨紫莖。歸期過舊歲，旅夢繞殘更。", "弱植叨華族，衰門倚外兄。欲陳勞者曲，未唱淚先橫。"]'),
('yuding-83','今月二日不自量度，輒以詩一首四十韻干瀆尊嚴，伏蒙仁恩，俯賜披覽，獎踰其實，情溢於辭，顧惟疏蕪，曷用酬戴，輒復五言四十韻詩獻上，亦詩人詠嘆不足之義也','李商隱','唐','御定全唐诗','yuding','','[]','家擅無雙譽，朝居第一功。四時當首夏，八節應條風。',480,'御定全唐詩/json/541.json','["家擅無雙譽，朝居第一功。四時當首夏，八節應條風。", "滌濯臨清濟，巉岩倚碧嵩。鮑壺冰皎潔，王佩玉丁東。", "處劇張京兆，通經戴侍中。將星臨迥夜，卿月麗層穹。", "下令銷秦盜，高談破宋聾。含霜太山竹，拂霧嶧陽桐。", "樂道幹知退，當官蹇匪躬。服箱青海馬，入兆渭川熊。", "固是符真宰，徒勞讓化工。鳳池春瀲豔，雞樹曉曈曨。", "願守三章約，還期九譯通。熏琴調大舜，寶瑟和神農。", "慷慨資元老，周旋值狡童。仲尼羞問陣，魏絳喜和戎。", "款款將除蠹，孜孜欲達聰。所求因渭濁，安肯與雷同。", "物議將調鼎，君恩忽賜弓。開吳相上下，全蜀占西東。", "銳卒魚懸餌，豪胥鳥在籠。疲民呼杜母，鄰國仰羊公。", "置驛推東道，安禪合北宗。嘉賓增重價，上士悟真空。", "扇舉遮王導，樽開見孔融。煙飛愁舞罷，塵定惜歌終。", "岸柳兼池綠，園花映燭紅。未曾周顗醉，轉覺季心恭。", "系滯喧人望，便蕃屬聖衷。天書何日降，庭燎幾時烘。", "早歲乖投刺，今晨幸發蒙。遠途哀跛鱉，薄藝獎雕蟲。", "故事曾尊隗，前修有薦雄。終須煩刻畫，聊擬更磨礱。", "蠻嶺晴留雪，巴江晚帶楓。營巢憐越燕，裂帛待燕鴻。", "自苦誠先檗，長飄不後蓬。容華雖少健，思緒即悲翁。", "感激淮山館，優遊碣石宮。待公三入相，丕祚始無窮。"]'),
('yuding-84','驕兒詩','李商隱','唐','御定全唐诗','yuding','','[]','袞師我驕兒，美秀乃無匹。文葆未周晬，固已知六七。',433,'御定全唐詩/json/541.json','["袞師我驕兒，美秀乃無匹。文葆未周晬，固已知六七。", "四歲知名姓，眼不視梨栗。交朋頗窺觀，謂是丹穴物。", "前朝尚器貌，流品方第一。不然神仙姿，不爾燕鶴骨。", "安得此相謂，欲慰衰朽質。青春妍和月，朋戲渾甥侄。", "繞堂複穿林，沸若金鼎溢。門有長者來，造次請先出。", "客前問所須，含意下吐實。歸來學客面，e5敗秉爺笏。", "或謔張飛胡，或笑鄧艾吃。豪鷹毛崱屴，猛馬氣佶傈。", "截得青筼簹，騎走恣唐突。忽複學參軍，按聲喚蒼鶻。", "又複紗燈旁，稽首禮夜佛。仰鞭罥蛛網，俯首飲花蜜。", "欲爭蛺蝶輕，未謝柳絮疾。階前逢阿姊，六甲頗輸失。", "凝走弄香奩，拔脫金屈戌。抱持多反側，威怒不可律。", "曲躬牽窗網，衉唾拭琴漆。有時看臨書，挺立不動膝。", "古錦請裁衣，玉軸亦欲乞。請爺書春勝，春勝宜春日。", "芭蕉斜卷箋，辛夷低過筆。爺昔好讀書，懇苦自著述。", "憔悴欲四十，無肉畏蚤虱。兒慎勿學爺，讀書求甲乙。", "穰苴司馬法，張良黃石術。便為帝王師，不假更纖悉。", "況今西與北，羌戎正狂悖。誅赦兩未成，將養如痼疾。", "兒當速成大，探雛入虎穴。當為萬戶侯，勿守一經帙。"]'),
('yuding-85','行次西郊作一百韻','李商隱','唐','御定全唐诗','yuding','','[]','蛇年建午月，我自梁還秦。南下大散關，北濟渭之濱。',576,'御定全唐詩/json/541.json','["蛇年建午月，我自梁還秦。南下大散關，北濟渭之濱。", "草木半舒坼，不類冰雪晨。又若夏苦熱，燋卷無芳津。", "高田長檞櫪，下田長荊榛。農具棄道旁，饑牛死空墩。", "依依過村落，十室無一存。存者皆面啼，無衣可迎賓。", "始若畏人問，及門還具陳。右輔田疇薄，斯民常苦貧。", "伊昔稱樂土，所賴牧伯仁。官清若冰玉，吏善如六親。", "生兒不遠征，生女事四鄰。濁酒盈瓦缶，爛谷堆荊囷。", "健兒庇旁婦，衰翁舐童孫。況自貞觀後，命官多儒臣。", "例以賢牧伯，征入司陶鈞。降及開元中，奸邪撓經綸。", "晉公忌此事，多錄邊將勳。因令猛毅輩，雜牧升平民。", "中原遂多故，除授非至尊。或出幸臣輩，或由帝戚恩。", "中原困屠解，奴隸厭肥豚。皇子棄不乳，椒房抱羌渾。", "重賜竭中國，強兵臨北邊。控弦二十萬，長臂皆如猿。", "皇都三千里，來往同雕鳶。五裏一換馬，十裏一開筵。", "指顧動白日，暖熱回蒼旻。公卿辱嘲叱，唾棄如糞丸。", "大朝會萬方，天子正臨軒。采旗轉初旭，玉座當祥煙。", "金障既特設，珠簾亦高褰。捋須蹇不顧，坐在禦榻前。", "忤者死艱屨，附之升頂顛。華侈矜遞衒，豪俊相併吞。", "因失生惠養，漸見徵求頻。奚寇西北來，揮霍如天翻。", "是時正忘戰，重兵多在邊。列城繞長河，平明插旗幡。", "但聞虜騎入，不見漢兵屯。大婦抱兒哭，小婦攀車轓。", "生小太平年，不識夜閉門。少壯盡點行，疲老守空村。", "生分作死誓，揮淚連秋雲。廷臣例獐怯，諸將如羸奔。", "為賊掃上陽，捉人送潼關。玉輦望南斗，未知何日旋。"]'),
('yuding-86','井泥四十韻','李商隱','唐','御定全唐诗','yuding','','[]','皇都依仁裏，西北有高齋。昨日主人氏，治井堂西陲。',480,'御定全唐詩/json/541.json','["皇都依仁裏，西北有高齋。昨日主人氏，治井堂西陲。", "工人三五輩，輦出土與泥。到水不數尺，積共庭樹齊。", "他日井甃畢，用土益作堤。曲隨林掩映，繚以池周回。", "下去冥寞穴，上承雨露滋。寄辭別地脈，因言謝泉扉。", "升騰不自意，疇昔忽已乖。伊餘掉行鞅，行行來自西。", "一日下馬到，此時芳草萋。四面多好樹，旦暮雲霞姿。", "晚落花滿地，幽鳥鳴何枝。蘿幄既已薦，山樽亦可開。", "待得孤月上，如與佳人來。因茲感物理，惻愴平生懷。", "茫茫此群品，不定輪與蹄。喜得舜可禪，不以瞽瞍疑。", "禹竟代舜立，其父籲咈哉。嬴氏並六合，所來因不韋。", "漢祖把左契，自言一布衣。當塗佩國璽，本乃黃門攜。", "長戟亂中原，何妨起戎氐。不獨帝王耳，臣下亦如斯。", "伊尹佐興王，不藉漢父資。磻溪老釣叟，坐為周之師。", "屠狗與販繒，突起定傾危。長沙啟封土，豈是出程姬。", "帝問主人翁，有自賣珠兒。武昌昔男子，老苦為人妻。", "蜀王有遺魄，今在林中啼。淮南雞舐藥，翻向雲中飛。", "大鈞運群有，難以一理推。顧於冥冥內，為問秉者誰。", "我恐更萬世，此事愈雲為。猛虎與雙翅，更以角副之。", "鳳凰不五色，聯翼上雞棲。我欲秉鈞者，朅來與我偕。", "浮雲不相顧，寥泬誰為梯。悒怏夜將半，但歌井中泥。"]'),
('yuding-87','夜思','李商隱','唐','御定全唐诗','yuding','','[]','銀箭耿寒漏，金釭凝夜光。彩鸞空自舞，別燕不相將。',120,'御定全唐詩/json/541.json','["銀箭耿寒漏，金釭凝夜光。彩鸞空自舞，別燕不相將。", "寄恨一尺素，含情雙玉璫。會前猶月在，去後始宵長。", "往事經春物，前期托報章。永令虛粲枕，長不掩蘭房。", "覺動迎猜影，疑來浪認香。鶴應聞露警，蜂亦為花忙。", "古有陽臺夢，今多下蔡倡。何為薄冰雪，消瘦滯非鄉。"]'),
('yuding-88','思賢頓','李商隱','唐','御定全唐诗','yuding','','[]','內殿張弦管，中原絕鼓鼙。舞成青海馬，鬥殺汝南雞。',48,'御定全唐詩/json/541.json','["內殿張弦管，中原絕鼓鼙。舞成青海馬，鬥殺汝南雞。", "不見華胥夢，空聞下蔡迷。宸襟他日淚，薄暮望賢西。"]'),
('yuding-89','無題','李商隱','唐','御定全唐诗','yuding','','[]','萬里風波一葉舟，憶歸初罷更夷猶。碧江地沒元相引，',40,'御定全唐詩/json/541.json','["萬里風波一葉舟，憶歸初罷更夷猶。碧江地沒元相引，", "人生豈得長無謂，懷古思鄉共白頭。"]'),
('yuding-90','有懷在蒙飛卿','李商隱','唐','御定全唐诗','yuding','','[]','薄宦頻移疾，當年久索居。哀同庾開府，瘦極沈尚書。',48,'御定全唐詩/json/541.json','["薄宦頻移疾，當年久索居。哀同庾開府，瘦極沈尚書。", "城綠新陰遠，江清返照虛。所思惟翰墨，從古待雙魚。"]'),
('yuding-91','春深脫衣','李商隱','唐','御定全唐诗','yuding','','[]','睥睨江鴉集，堂皇海燕過。減衣憐蕙若，展帳動煙波。',48,'御定全唐詩/json/541.json','["睥睨江鴉集，堂皇海燕過。減衣憐蕙若，展帳動煙波。", "日烈憂花甚，風長奈柳何。陳遵容易學，身世醉時多。"]'),
('yuding-92','懷求古翁','李商隱','唐','御定全唐诗','yuding','','[]','何時粉署仙，傲兀逐戎旃。關塞猶傳箭，江湖莫系船。',48,'御定全唐詩/json/541.json','["何時粉署仙，傲兀逐戎旃。關塞猶傳箭，江湖莫系船。", "欲收棋子醉，竟把釣車眠。謝脁真堪憶，多才不忌前。"]'),
('yuding-93','五月六日夜憶往歲秋與徹師同宿','李商隱','唐','御定全唐诗','yuding','','[]','紫閣相逢處，丹岩議宿時。墮蟬翻敗葉，棲鳥定寒枝。',48,'御定全唐詩/json/541.json','["紫閣相逢處，丹岩議宿時。墮蟬翻敗葉，棲鳥定寒枝。", "萬里飄流遠，三年問訊遲。炎方憶初地，頻夢碧琉璃。"]'),
('yuding-94','城上','李商隱','唐','御定全唐诗','yuding','','[]','有客虛投筆，無憀獨上城。沙禽失侶遠，江樹著陰輕。',48,'御定全唐詩/json/541.json','["有客虛投筆，無憀獨上城。沙禽失侶遠，江樹著陰輕。", "邊遽稽天討，軍須竭地征。賈生遊刃極，作賦又論兵。"]'),
('yuding-95','如有','李商隱','唐','御定全唐诗','yuding','','[]','如有瑤台客，相難複索歸。芭蕉開綠扇，菡萏薦紅衣。',48,'御定全唐詩/json/541.json','["如有瑤台客，相難複索歸。芭蕉開綠扇，菡萏薦紅衣。", "浦外傳光遠，煙中結響微。良宵一寸焰，回首是重幃。"]'),
('yuding-96','朱槿花二首','李商隱','唐','御定全唐诗','yuding','','[]','蓮後紅何患，梅先白莫誇。才飛建章火，又落赤城霞。',96,'御定全唐詩/json/541.json','["蓮後紅何患，梅先白莫誇。才飛建章火，又落赤城霞。", "不卷錦步障，未登油壁車。日西相對罷，休浣向天涯。", "勇多侵路去，恨有礙燈還。嗅自微微白，看成遝遝殷。", "坐疑忘物外，歸去有簾間。君問傷春句，千辭不可刪。"]'),
('yuding-97','寓懷','李商隱','唐','御定全唐诗','yuding','','[]','彩鸞餐顥氣，威鳳入卿雲。長養三清境，追隨五帝君。',144,'御定全唐詩/json/541.json','["彩鸞餐顥氣，威鳳入卿雲。長養三清境，追隨五帝君。", "煙波遺汲汲，矰繳任云云。下界圍黃道，前程合紫氛。", "金書惟是見，玉管不勝聞。草為回生種，香緣卻死熏。", "海明三島見，天迥九江分。搴樹無勞援，神禾豈用耘。", "鬥龍風結陣，惱鶴露成文。漢嶺霜何早，秦宮日易曛。", "星機拋密緒，月杵散靈氛。陽鳥西南下，相思不及群。"]'),
('yuding-98','木蘭','李商隱','唐','御定全唐诗','yuding','','[]','二月二十二，木蘭開坼初。初當新病酒，複自久離居。',96,'御定全唐詩/json/541.json','["二月二十二，木蘭開坼初。初當新病酒，複自久離居。", "愁絕更傾國，驚新聞遠書。紫絲何日障，油壁幾時車。", "弄粉知傷重，調紅或有餘。波痕空映襪，煙態不勝裾。", "桂嶺含芳遠，蓮塘屬意疏。瑤姬與神女，長短定何如。"]'),
('yuding-99','細雨成詠獻尚書河東公','李商隱','唐','御定全唐诗','yuding','','[]','灑砌聽來響，捲簾看已迷。江間風暫定，雲外日應西。',96,'御定全唐詩/json/541.json','["灑砌聽來響，捲簾看已迷。江間風暫定，雲外日應西。", "稍稍落蝶粉，班班融燕泥。颭萍初過沼，重柳更緣堤。", "必擬和殘漏，寧無晦暝鼙。半將花漠漠，全共草萋萋。", "猿別方長嘯，烏驚始獨棲。府公能八詠，聊且續新題。"]'),
('yuding-100','病中聞河東公樂營置酒口占寄上','李商隱','唐','御定全唐诗','yuding','','[]','聞駐行春旆，中途賞物華。緣憂武昌柳，遂憶洛陽花。',144,'御定全唐詩/json/541.json','["聞駐行春旆，中途賞物華。緣憂武昌柳，遂憶洛陽花。", "嵇鶴元無對，荀龍不在誇。只將滄海月，長壓赤城霞。", "興欲傾燕館，歡終到習家。風長應側帽，路隘豈容車。", "樓迥波窺錦，窗虛日弄紗。鎖門金了鳥，展障玉鴉叉。", "舞妙從兼楚，歌能莫雜巴。必投潘嶽果，誰摻禰衡撾。", "刻燭當時忝，傳杯此夕賒。可憐漳浦臥，愁緒獨如麻。"]'),
('yuding-101','回中牡丹為雨所敗二首','李商隱','唐','御定全唐诗','yuding','','[]','下苑他年未可追，西州今日忽相期。水亭暮雨寒猶在，',80,'御定全唐詩/json/541.json','["下苑他年未可追，西州今日忽相期。水亭暮雨寒猶在，", "章台街裏芳菲伴，且問宮腰損幾枝。", "浪笑榴花不及春，先期零落更愁人。玉盤迸淚傷心數，", "前溪舞罷君回顧，並覺今朝粉態新。"]'),
('yuding-102','擬意','李商隱','唐','御定全唐诗','yuding','','[]','悵望逢張女，遲回送阿侯。空看小垂手，忍問大刀頭。',288,'御定全唐詩/json/541.json','["悵望逢張女，遲回送阿侯。空看小垂手，忍問大刀頭。", "妙選茱萸帳，平居翡翠樓。雲屏不取暖，月扇未遮羞。", "上掌真何有，傾城豈自由。楚妃交薦枕，漢後共藏鬮。", "夫向羊車覓，男從鳳穴求。書成祓禊帖，唱殺畔牢愁。", "夜杵鳴江練，春刀解若榴。象床穿幰網，犀帖釘窗油。", "仁壽遺明鏡，陳倉拂彩球。真防舞如意，佯蓋臥箜篌。", "濯錦桃花水，濺裙杜若洲。魚兒懸寶劍，燕子合金甌。", "銀箭催搖落，華筵慘去留。幾時銷薄怒，從此抱離憂。", "帆落啼猿峽，樽開畫鷁舟。急弦腸對斷，翦蠟淚爭流。", "璧馬誰能帶，金蟲不復收。銀河撲醉眼，珠串咽歌喉。", "去夢隨川後，來風貯石郵。蘭叢銜露重，榆莢點星稠。", "解佩無遺跡，淩波有舊遊。曾來十九首，私讖詠牽牛。"]'),
('yuding-103','謝往桂林至彤庭竊詠','李商隱','唐','御定全唐诗','yuding','','[]','辰象森羅正，句陳翊衛寬。魚龍排百戲，劍佩儼千官。',120,'御定全唐詩/json/541.json','["辰象森羅正，句陳翊衛寬。魚龍排百戲，劍佩儼千官。", "城禁將開晚，宮深欲曙難。月輪移枍詣，仙路下欄幹。", "共賀高禖應，將陳壽酒歡。金星壓芒角，銀漢轉波瀾。", "王母來空闊，羲和上屈盤。鳳凰傳詔旨，獬廌冠朝端。", "造化中台座，威風上將壇。甘泉猶望幸，早晚冠呼韓。"]'),
('yuding-104','燒香曲','李商隱','唐','御定全唐诗','yuding','','[]','鈿雲蟠蟠牙比魚，孔雀翅尾蛟龍須。漳宮舊樣博山爐，',72,'御定全唐詩/json/541.json','["鈿雲蟠蟠牙比魚，孔雀翅尾蛟龍須。漳宮舊樣博山爐，", "白天月澤寒未冰，金虎含秋向東吐。玉佩呵光銅照昏，", "露庭月井大紅氣，輕衫薄細當君意。蜀殿瓊人伴夜深，"]'),
('yuding-105','送從翁東川弘農尚書幕','李商隱','唐','御定全唐诗','yuding','','[]','昔帝回沖眷，維皇惻上仁。三靈迷赤氣，萬匯叫蒼旻。',408,'御定全唐詩/json/541.json','["昔帝回沖眷，維皇惻上仁。三靈迷赤氣，萬匯叫蒼旻。", "刊木方隆禹，陛陑始創殷。夏台曾圮閉，汜水敢逡巡。", "拯溺休規步，防虞要徙薪。蒸黎今得請，宇宙昨還淳。", "纘祖功宜急，貽孫計甚勤。降災雖代有，稔惡不無因。", "宮掖方為蠱，邊隅忽遘迍。獻書秦逐客，間諜漢名臣。", "北伐將誰使，南征決此辰。中原重板蕩，玄象失鉤陳。", "詰旦違清道，銜枚別紫宸。茲行殊厭勝，故老遂分新。", "去異封于鞏，來寧避處豳。永嘉幾失墜，宣政遽酸辛。", "元子當傳啟，皇孫合授詢。時非三揖讓，表請再陶鈞。", "舊好盟還在，中樞策屢遵。蒼黃傳國璽，違遠屬車塵。", "雛虎如憑怒，漦龍性漫馴。封崇自何等，流落乃斯民。", "逗撓官軍亂，優容敗將頻。早朝披草莽，夜縋達絲綸。", "忘戰追無及，長驅氣益振。婦言終未易，廟算況非神。", "日馭難淹蜀，星旄要定秦。人心誠未去，天道亦無親。", "錦水湔雲浪，黃山掃地春。斯文虛夢鳥，吾道欲悲麟。", "斷續殊鄉淚，存亡滿席珍。魂銷季羔竇，衣化子張紳。", "建議庸何所，通班昔濫臻。浮生見開泰，獨得詠汀蘋。"]'),
('yuding-106','晉昌晚歸馬上贈','李商隱','唐','御定全唐诗','yuding','','[]','西北朝天路，登臨思上才。城閑煙草遍，村暗雨雲回。',48,'御定全唐詩/json/541.json','["西北朝天路，登臨思上才。城閑煙草遍，村暗雨雲回。", "人豈無端別，猿應有意哀。征南予更遠，吟斷望鄉台。"]'),
('yuding-107','哭虔州楊侍郎','李商隱','唐','御定全唐诗','yuding','','[]','漢網疏仍漏，齊民困未蘇。如何大丞相，翻作弛刑徒。',168,'御定全唐詩/json/541.json','["漢網疏仍漏，齊民困未蘇。如何大丞相，翻作弛刑徒。", "中憲方外易，尹京終就拘。本矜能弭謗，先議取非辜。", "巧有凝脂密，功無一柱扶。深知獄吏貴，幾迫季冬誅。", "叫帝青天闊，辭家白日晡。流亡誠不吊，神理若為誣。", "在昔恩知忝，諸生禮秩殊。入韓非劍客，過趙受鉗奴。", "楚水招魂遠，邙山卜宅孤。甘心親垤蟻，旋踵戮城狐。", "陰騭今如此，天災未可無。莫憑牲玉請，便望救焦枯。"]'),
('yuding-108','寄太原盧司空三十韻','李商隱','唐','御定全唐诗','yuding','','[]','隋艦臨淮甸，唐旗出井陘。斷鼇支四柱，卓馬濟三靈。',360,'御定全唐詩/json/541.json','["隋艦臨淮甸，唐旗出井陘。斷鼇支四柱，卓馬濟三靈。", "祖業隆盤古，孫謀複大庭。從來師俊傑，可以煥丹青。", "舊族開東嶽，雄圖奮北溟。邪同獬廌觸，樂伴鳳凰聽。", "酣戰仍揮日，降妖亦鬥霆。將軍功不伐，叔舅德惟馨。", "雞塞誰生事，狼煙不暫停。擬填滄海鳥，敢競太陽螢。", "內草才傳詔，前茅已勒銘。那勞出師表，盡入大荒經。", "德水縈長帶，陰山繞畫屏。只憂非綮肯，未覺有膻腥。", "保佐資沖漠，扶持在杳冥。乃心防暗室，華髮稱明廷。", "按甲神初靜，揮戈思欲醒。羲之當妙選，孝若近歸寧。", "月色來侵幌，詩成有轉欞。羅含黃菊宅，柳惲白蘋汀。", "神物龜酬孔，仙才鶴姓丁。西山童子藥，南極老人星。", "自頃徒窺管，於今愧挈瓶。何由叨末席，還得叩玄扃。", "莊叟虛悲雁，終童漫識鼮。幕中雖策畫，劍外且伶俜。", "俁俁行忘止，鰥鰥臥不瞑。身應瘠于魯，淚欲溢為滎。", "禹貢思金鼎，堯圖憶土鉶。公乎來入相，王欲駕雲亭。"]'),
('yuding-109','安平公詩','李商隱','唐','御定全唐诗','yuding','','[]','丈人博陵王名家，憐我總角稱才華。華州留語曉至暮，',192,'御定全唐詩/json/541.json','["丈人博陵王名家，憐我總角稱才華。華州留語曉至暮，", "仲子延嶽年十六，面如白玉欹烏紗。其弟炳章猶兩丱，", "府中從事杜與李，麟角虎翅相過摩。清詞孤韻有歌響，", "時禽得伴戲新木，其聲尖咽如鳴梭。公時載酒領從事，", "面熱腳掉互登陟，青雲表柱白雲崖。一百八句在貝葉，", "公時受詔鎮東魯，遣我草詔隨車牙。顧我下筆即千字，", "五月至止六月病，遽頹泰山驚逝波。明年徒步吊京國，", "古人常歎知己少，況我淪賤艱虞多。如公之德世一二，"]'),
('yuding-110','《赤壁','李商隱','唐','御定全唐诗','yuding','','[]','折戟沈沙鐵未銷，自將磨洗認前朝。',32,'御定全唐詩/json/541.json','["折戟沈沙鐵未銷，自將磨洗認前朝。", "東風不與周郎便，銅雀春深鎖二喬。"]'),
('yuding-111','垂柳','李商隱','唐','御定全唐诗','yuding','','[]','垂柳碧鬅茸，樓昏雨帶容。思量成夜夢，束久廢春慵。',96,'御定全唐詩/json/541.json','["垂柳碧鬅茸，樓昏雨帶容。思量成夜夢，束久廢春慵。", "梳洗憑張敞，乘騎笑稚恭。碧虛隨轉笠，紅燭近高舂。", "怨目明秋水，愁眉淡遠峰。小闌花盡蝶，靜院醉醒蛩。", "舊作琴台鳳，今為藥店龍。寶奩拋擲久，一任景陽鐘。"]'),
('yuding-112','清夜怨','李商隱','唐','御定全唐诗','yuding','','[]','含淚坐春宵，聞君欲度遼。綠池荷葉嫩，紅砌杏花嬌。',48,'御定全唐詩/json/541.json','["含淚坐春宵，聞君欲度遼。綠池荷葉嫩，紅砌杏花嬌。", "曙月當窗滿，征雲出塞遙。畫樓終日閉，清管為誰調。"]'),
('yuding-113','《定子','李商隱','唐','御定全唐诗','yuding','','[]','檀槽一抹廣陵春，定子初開睡臉新。',32,'御定全唐詩/json/541.json','["檀槽一抹廣陵春，定子初開睡臉新。", "卻笑吃虛隋煬帝，破家亡國為何人。"]'),
('yuding-114','木蘭花','李商隱','唐','御定全唐诗','yuding','','[]','洞庭波冷曉侵雲，日日征帆送遠人。',32,'御定全唐詩/json/541.json','["洞庭波冷曉侵雲，日日征帆送遠人。", "幾度木蘭舟上望，不知元是此花身。"]'),
('yuding-115','《遊靈伽寺','李商隱','唐','御定全唐诗','yuding','','[]','碧煙秋寺泛湖來，水打城根古堞摧。',32,'御定全唐詩/json/541.json','["碧煙秋寺泛湖來，水打城根古堞摧。", "盡日傷心人不見，石榴花滿舊琴台。"]'),
('yuding-116','龍丘途中','李商隱','唐','御定全唐诗','yuding','','[]','漢苑殘花別，吳江盛夏來。惟看萬樹穀，不見一枝開。',48,'御定全唐詩/json/541.json','["漢苑殘花別，吳江盛夏來。惟看萬樹穀，不見一枝開。", "水色饒湘浦，灘聲怯建溪。淚流回月上，可得更猿啼。"]'),
('yuding-117','句','李商隱','唐','御定全唐诗','yuding','','[]','蘭膏爇處心猶淺，銀燭燒殘焰不馨。好向書生窗畔種，',56,'御定全唐詩/json/541.json','["蘭膏爇處心猶淺，銀燭燒殘焰不馨。好向書生窗畔種，", "遙想故園陌，桃李正酣酣。", "頭上金雀釵，腰佩翠琅玕。", "蘆洲客雁報春來。"]'),
('yuding-0','送友人歸宜春','紀唐夫','唐','御定全唐诗','yuding','','[]','落花兼柳絮，無處不紛紛。遠道空歸去，流鶯獨自聞。',48,'御定全唐詩/json/542.json','["落花兼柳絮，無處不紛紛。遠道空歸去，流鶯獨自聞。", "墅橋喧碓水，山郭入樓雲。故里南陔曲，秋期欲送君。"]'),
('yuding-1','驄馬曲','紀唐夫','唐','御定全唐诗','yuding','','[]','連錢出塞蹋沙蓬，豈比當時禦史驄。逐北自諳深磧路，',40,'御定全唐詩/json/542.json','["連錢出塞蹋沙蓬，豈比當時禦史驄。逐北自諳深磧路，", "今日虜平將換妾，不如羅袖舞春風。"]'),
('yuding-2','送溫庭筠尉方城','紀唐夫','唐','御定全唐诗','yuding','','[]','何事明時泣玉頻，長安不見杏園春。鳳凰詔下雖沾命，',40,'御定全唐詩/json/542.json','["何事明時泣玉頻，長安不見杏園春。鳳凰詔下雖沾命，", "方城若比長沙路，猶隔千山與萬津。"]'),
('yuding-3','及第後宿平康裏','裴思謙','唐','御定全唐诗','yuding','','[]','銀缸斜背解鳴璫，小語偷聲賀玉郎。',32,'御定全唐詩/json/542.json','["銀缸斜背解鳴璫，小語偷聲賀玉郎。", "從此不知蘭麝貴，夜來新染桂枝香。"]'),
('yuding-4','都堂試貢士日慶春雪','李衢','唐','御定全唐诗','yuding','','[]','錫瑞來豐歲，旌賢入貢辰。輕搖梅共笑，飛嫋柳知春。',72,'御定全唐詩/json/542.json','["錫瑞來豐歲，旌賢入貢辰。輕搖梅共笑，飛嫋柳知春。", "繞砌封瓊屑，依階噴玉塵。蜉蝣吟更古，科鬥映還新。", "鶴毳迷難辨，冰壺鑒易真。因歌大君德，率舞詠陶鈞。"]'),
('yuding-5','都堂試貢士日慶春雪','李損之','唐','御定全唐诗','yuding','','[]','春雪晝悠揚，飄飛試士場。綴毫疑起草，沾字共成章。',72,'御定全唐詩/json/542.json','["春雪晝悠揚，飄飛試士場。綴毫疑起草，沾字共成章。", "匝地如鋪練，凝階似截肪。鵝毛縈樹合，柳絮帶風狂。", "息疫方殊慶，豐年已報祥。應知郢上曲，高唱出東堂。"]'),
('yuding-6','除夜長安作','李景','唐','御定全唐诗','yuding','','[]','長安朔風起，窮巷掩雙扉。新歲明朝是，故鄉何路歸。',48,'御定全唐詩/json/542.json','["長安朔風起，窮巷掩雙扉。新歲明朝是，故鄉何路歸。", "鬢絲饒鏡色，隙雪奪燈輝。卻羨秦州雁，逢春盡北飛。"]'),
('yuding-7','都堂試貢士日慶春雪','李景','唐','御定全唐诗','yuding','','[]','密雪分天路，群才坐粉廊。靄空迷晝景，臨宇借寒光。',72,'御定全唐詩/json/542.json','["密雪分天路，群才坐粉廊。靄空迷晝景，臨宇借寒光。", "似暖花消地，無聲玉滿堂。灑池偏誤曲，留硯忽因方。", "幾處曹風比，何人謝賦長。春暉早相照，莫滯九衢芳。"]'),
('yuding-8','登景雲寺閣','張元宗','唐','御定全唐诗','yuding','','[]','胡馬飲河洛，我家從此遷。今來獨垂淚，三十六峰前。',24,'御定全唐詩/json/542.json','["胡馬飲河洛，我家從此遷。今來獨垂淚，三十六峰前。"]'),
('yuding-9','望終南山','張元宗','唐','御定全唐诗','yuding','','[]','紅塵白日長安路，馬足車輪不暫閑。',32,'御定全唐詩/json/542.json','["紅塵白日長安路，馬足車輪不暫閑。", "唯有茂陵多病客，每來高處望南山。"]'),
('yuding-10','省試霓裳羽衣曲','李肱','唐','御定全唐诗','yuding','','[]','開元太平時，萬國賀豐歲。梨園獻舊曲，玉座流新制。',72,'御定全唐詩/json/542.json','["開元太平時，萬國賀豐歲。梨園獻舊曲，玉座流新制。", "鳳管遞參差，霞衣競搖曳。宴罷水殿空，輦餘春草細。", "蓬壺事已久，仙樂功無替。詎肯聽遺音，聖明知善繼。"]'),
('yuding-11','句','李肱','唐','御定全唐诗','yuding','','[]','水光先見月，露氣早知秋。。',13,'御定全唐詩/json/542.json','["水光先見月，露氣早知秋。。"]'),
('yuding-12','永州送侄歸宜春','鄭史','唐','御定全唐诗','yuding','','[]','宋玉正秋悲，那堪更別離。從來襟上淚，盡作鬢邊絲。',48,'御定全唐詩/json/542.json','["宋玉正秋悲，那堪更別離。從來襟上淚，盡作鬢邊絲。", "永水清如此，袁江色可知。到家黃菊坼，亦莫怪歸遲。"]'),
('yuding-13','秋日零陵與幕下諸賓遊河夜飲','鄭史','唐','御定全唐诗','yuding','','[]','湘月蘋風乍暢襟，燭前江水練千尋。新秋宋玉能為賦，',40,'御定全唐詩/json/542.json','["湘月蘋風乍暢襟，燭前江水練千尋。新秋宋玉能為賦，", "汀沙漸有珠凝露，緩棹蘭橈任夜深。"]'),
('yuding-14','贈妓行雲詩','鄭史','唐','御定全唐诗','yuding','','[]','最愛鉛華薄薄妝，更兼衣著又鵝黃。',32,'御定全唐詩/json/542.json','["最愛鉛華薄薄妝，更兼衣著又鵝黃。", "從來南國名佳麗，何事今朝在北行。"]'),
('yuding-15','紀夢','許瀍','唐','御定全唐诗','yuding','','[]','晚入瑤台露氣清，天風飛下步虛聲。',32,'御定全唐詩/json/542.json','["晚入瑤台露氣清，天風飛下步虛聲。", "塵心未盡俗緣在，十裏下山空月明。"]'),
('yuding-16','題朝陽岩','牛叢','唐','御定全唐诗','yuding','','[]','躡石攀蘿路不迷，曉天風好浪花低。',32,'御定全唐詩/json/542.json','["躡石攀蘿路不迷，曉天風好浪花低。", "洞名獨佔朝陽號，應有梧桐待鳳棲。"]'),
('yuding-17','咸陽有懷','陳上美','唐','御定全唐诗','yuding','','[]','山連河水碧氛氳，瑞氣東移擁聖君。秦苑有花空笑日，',40,'御定全唐詩/json/542.json','["山連河水碧氛氳，瑞氣東移擁聖君。秦苑有花空笑日，", "賴與淵明同把菊，煙郊西望夕陽曛。"]'),
('yuding-18','晴望九華山','楊鴻','唐','御定全唐诗','yuding','','[]','九華閑望簇清虛，氣象群峰盡不如。',32,'御定全唐詩/json/542.json','["九華閑望簇清虛，氣象群峰盡不如。", "惆悵都南掛冠吏，無人解向此山居。"]'),
('yuding-19','正月','趙璜','唐','御定全唐诗','yuding','','[]','正月今朝半，陽臺信未回。水芹寒不食，山杏雨應開。',48,'御定全唐詩/json/542.json','["正月今朝半，陽臺信未回。水芹寒不食，山杏雨應開。", "世網留三宿，真源寄一杯。因聲謝猿鳥，歲晏會歸來。"]'),
('yuding-20','七夕詩','趙璜','唐','御定全唐诗','yuding','','[]','烏鵲橋頭雙扇開，年年一度過河來。莫嫌天上稀相見，',40,'御定全唐詩/json/542.json','["烏鵲橋頭雙扇開，年年一度過河來。莫嫌天上稀相見，", "別時舊路長清淺，豈肯離情似死灰。"]'),
('yuding-21','曲江上巳','趙璜','唐','御定全唐诗','yuding','','[]','長堤十裏轉香車，兩岸煙花錦不如。',32,'御定全唐詩/json/542.json','["長堤十裏轉香車，兩岸煙花錦不如。", "欲問神仙在何處，紫雲樓閣向空虛。"]'),
('yuding-22','題七夕圖','趙璜','唐','御定全唐诗','yuding','','[]','帝子吹簫上翠微，秋風一曲鳳凰歸。',32,'御定全唐詩/json/542.json','["帝子吹簫上翠微，秋風一曲鳳凰歸。", "明年七月重相見，依舊高懸織女機。"]'),
('yuding-23','登明戍堡','潘鹹','唐','御定全唐诗','yuding','','[]','來經古城上，極目思無窮。寇盡煙蘿外，人歸蔓草中。',48,'御定全唐詩/json/542.json','["來經古城上，極目思無窮。寇盡煙蘿外，人歸蔓草中。", "峰巒當闕古，堞壘對雲空。不見昔名將，徒稱有戰功。"]'),
('yuding-24','送陳明府之任','潘鹹','唐','御定全唐诗','yuding','','[]','客見天台縣，閭閻樹色間。驂回幾臨水，帶緩獨開山。',48,'御定全唐詩/json/542.json','["客見天台縣，閭閻樹色間。驂回幾臨水，帶緩獨開山。", "吏散落花盡，人居遠島閑。過於老萊子，端簡獨承顏。"]'),
('yuding-25','長安春暮','潘鹹','唐','御定全唐诗','yuding','','[]','客在關西春暮夜，還同江外已清明。',32,'御定全唐詩/json/542.json','["客在關西春暮夜，還同江外已清明。", "三更獨立看花月，惟欠子規啼一聲。"]'),
('yuding-26','舟行','潘咸','唐','御定全唐诗','yuding','','[]','平沙極浦無人度，猶系孤舟寒草西。',32,'御定全唐詩/json/542.json','["平沙極浦無人度，猶系孤舟寒草西。", "半夜起看潮上月，萬山中有一猿啼。"]'),
('yuding-27','送僧','潘咸','唐','御定全唐诗','yuding','','[]','闕下僧歸山頂寺，卻看朝日下方明。',32,'御定全唐詩/json/542.json','["闕下僧歸山頂寺，卻看朝日下方明。", "莫道野人尋不見，半天雲裏有鐘聲。"]'),
('yuding-28','句','潘鹹','唐','御定全唐诗','yuding','','[]','棧踏猿聲暮，江看劍影秋。',64,'御定全唐詩/json/542.json','["棧踏猿聲暮，江看劍影秋。", "僧老白雲上，磬寒高鳥邊。", "心已同猿狖，不聞人是非。", "行人渡流水，白馬入前山。", "秋深雪滿黃金塞，夜夜鴻聲入漢陽。"]'),
('yuding-29','秋晚同友人閒步','薛瑩','唐','御定全唐诗','yuding','','[]','藉草與行莎，相看日未斜。斷崖分鳥道，疏樹見人家。',48,'御定全唐詩/json/542.json','["藉草與行莎，相看日未斜。斷崖分鳥道，疏樹見人家。", "望遠臨孤石，吟餘落片霞。野情看不足，歸路思猶賒。"]'),
('yuding-30','宿仙都觀陰王二君修道處','薛瑩','唐','御定全唐诗','yuding','','[]','十載別仙峰，峰前千古蹤。陰王修道處，雲雪滿高松。',48,'御定全唐詩/json/542.json','["十載別仙峰，峰前千古蹤。陰王修道處，雲雪滿高松。", "洞口風雷異，池心星漢重。明朝下山去，片月落殘鐘。"]'),
('yuding-31','宿東岩寺曉起','薛瑩','唐','御定全唐诗','yuding','','[]','野寺寒塘曉，遊人一夢分。鐘殘數樹月，僧起半岩雲。',48,'御定全唐詩/json/542.json','["野寺寒塘曉，遊人一夢分。鐘殘數樹月，僧起半岩雲。", "宿鳥驚初見，幽泉落不聞。吟餘憑前檻，紅葉下紛紛。"]'),
('yuding-32','秋日湖上','薛瑩','唐','御定全唐诗','yuding','','[]','落日五湖游，煙波處處愁。沈浮千古事，誰與問東流。',24,'御定全唐詩/json/542.json','["落日五湖游，煙波處處愁。沈浮千古事，誰與問東流。"]'),
('yuding-33','江山閑望','薛瑩','唐','御定全唐诗','yuding','','[]','渺渺無窮盡，風濤幾日平。年光與人事，東去一聲聲。',24,'御定全唐詩/json/542.json','["渺渺無窮盡，風濤幾日平。年光與人事，東去一聲聲。"]'),
('yuding-34','訪武陵道者不遇','薛瑩','唐','御定全唐诗','yuding','','[]','花發鳥仍啼，行行路欲迷。二真無問處，虛度武陵溪。',24,'御定全唐詩/json/542.json','["花發鳥仍啼，行行路欲迷。二真無問處，虛度武陵溪。"]'),
('yuding-35','寄舊山隱侶','薛瑩','唐','御定全唐诗','yuding','','[]','舊山諸隱淪，身在苦無身。莫鎖白雲路，白雲多誤人。',24,'御定全唐詩/json/542.json','["舊山諸隱淪，身在苦無身。莫鎖白雲路，白雲多誤人。"]'),
('yuding-36','羨僧','薛瑩','唐','御定全唐诗','yuding','','[]','處世曾無著，生前事盡非。一瓶兼一衲，南北去如歸。',24,'御定全唐詩/json/542.json','["處世曾無著，生前事盡非。一瓶兼一衲，南北去如歸。"]'),
('yuding-37','錦','薛瑩','唐','御定全唐诗','yuding','','[]','軋軋弄寒機，功多力漸微。惟憂機上錦，不稱舞人衣。',24,'御定全唐詩/json/542.json','["軋軋弄寒機，功多力漸微。惟憂機上錦，不稱舞人衣。"]'),
('yuding-38','中秋月','薛瑩','唐','御定全唐诗','yuding','','[]','三十六旬盈複缺，百年堪喜又堪傷。',32,'御定全唐詩/json/542.json','["三十六旬盈複缺，百年堪喜又堪傷。", "勸君莫惜登樓望，雲放嬋娟不久長。"]'),
('yuding-39','句','薛瑩','唐','御定全唐诗','yuding','','[]','單棹橫疏雨，江灘秋泊時。',24,'御定全唐詩/json/542.json','["單棹橫疏雨，江灘秋泊時。", "花留身住越，月遞夢還秦。"]'),
('yuding-40','贈毛仙翁','崔元略','唐','御定全唐诗','yuding','','[]','莫將凡聖比雲泥，椿菌之年本不齊。度世無勞大稻米，',40,'御定全唐詩/json/542.json','["莫將凡聖比雲泥，椿菌之年本不齊。度世無勞大稻米，", "旌節行中令引道，便從塵外踏丹梯。"]'),
('yuding-41','太學創置石經','馮涯','唐','御定全唐诗','yuding','','[]','聖唐復古制，德義功無替。奧旨悅詩書，遺文分篆隸。',72,'御定全唐詩/json/542.json','["聖唐復古制，德義功無替。奧旨悅詩書，遺文分篆隸。", "銀鉤互交映，石壁靡塵翳。永與乾坤期，不逐日月逝。", "儒林道益廣，學者心彌銳。從此理化成，恩光遍遐裔。"]'),
('yuding-0','贈李商隱','喻鳧','唐','御定全唐诗','yuding','','[]','羽翼恣摶扶，山河使筆驅。月疏吟夜桂，龍失詠春珠。',48,'御定全唐詩/json/543.json','["羽翼恣摶扶，山河使筆驅。月疏吟夜桂，龍失詠春珠。", "草細盤金勒，花繁倒玉壺。徒嗟好章句，無力致前途。"]'),
('yuding-1','元日即事','喻鳧','唐','御定全唐诗','yuding','','[]','斂板賀交親，稱觴詎有巡。年光悲擲舊，景色喜呈新。',48,'御定全唐詩/json/543.json','["斂板賀交親，稱觴詎有巡。年光悲擲舊，景色喜呈新。", "水柳煙中重，山梅雪後真。不知將白髮，何以度青春。"]'),
('yuding-2','送賈島往金州謁姚員外','喻鳧','唐','御定全唐诗','yuding','','[]','山光與水色，獨往此中深。溪瀝椒花氣，岩盤漆葉陰。',48,'御定全唐詩/json/543.json','["山光與水色，獨往此中深。溪瀝椒花氣，岩盤漆葉陰。", "瀟湘終共去，巫峽羨先尋。幾夕江樓月，玄暉伴靜吟。"]'),
('yuding-3','送友人罷舉歸蜀','喻鳧','唐','御定全唐诗','yuding','','[]','憔悴滿衣塵，風光豈屬身。賣琴紅粟貴，看鏡白髭新。',48,'御定全唐詩/json/543.json','["憔悴滿衣塵，風光豈屬身。賣琴紅粟貴，看鏡白髭新。", "棧畔誰高步，巴邊自問津。淒然莫滴血，杜宇正哀春。"]'),
('yuding-4','送衛尉之延陵','喻鳧','唐','御定全唐诗','yuding','','[]','草木正花時，交親觸雨辭。一官之任遠，盡室出城遲。',48,'御定全唐詩/json/543.json','["草木正花時，交親觸雨辭。一官之任遠，盡室出城遲。", "乳滴茅君洞，鴉鳴季子祠。想知佐理暇，日有詠懷詩。"]'),
('yuding-5','送越州高錄事','喻鳧','唐','御定全唐诗','yuding','','[]','官曹權紀綱，行李半舟航。浦漵潮來廣，川源鳥去長。',48,'御定全唐詩/json/543.json','["官曹權紀綱，行李半舟航。浦漵潮來廣，川源鳥去長。", "筍成稽嶺岸，蓮發鏡湖香。澤國還之任，鱸魚浪得嘗。"]'),
('yuding-6','送潘咸','喻鳧','唐','御定全唐诗','yuding','','[]','時時齎破囊，訪我息閑坊。煮雪問茶味，當風看雁行。',48,'御定全唐詩/json/543.json','["時時齎破囊，訪我息閑坊。煮雪問茶味，當風看雁行。", "心齊山鹿逸，句敵柳花狂。堅苦今如此，前程豈渺茫。"]'),
('yuding-7','送友人下第歸甯','喻鳧','唐','御定全唐诗','yuding','','[]','紫閣雪未盡，杏園花亦寒。灞西辭舊友，楚外憶新安。',48,'御定全唐詩/json/543.json','["紫閣雪未盡，杏園花亦寒。灞西辭舊友，楚外憶新安。", "細雨猿啼枿，微陽鷺起灘。旋應赴秋貢，詎得久承歡。"]'),
('yuding-8','遊北山寺','喻鳧','唐','御定全唐诗','yuding','','[]','煙岡影畔寺，游步此時孤。庭靜眾藥在，鶴閑雙檜枯。',48,'御定全唐詩/json/543.json','["煙岡影畔寺，游步此時孤。庭靜眾藥在，鶴閑雙檜枯。", "藍峰露秋院，灞水入春廚。便可棲心跡，如何返舊途。"]'),
('yuding-9','冬日題無可上人院','喻鳧','唐','御定全唐诗','yuding','','[]','入戶道心生，茶間踏葉行。瀉風瓶水澀，承露鶴巢輕。',48,'御定全唐詩/json/543.json','["入戶道心生，茶間踏葉行。瀉風瓶水澀，承露鶴巢輕。", "閣北長河氣，窗東一檜聲。詩言與禪味，語默此皆清。"]'),
('yuding-10','遊雲際寺','喻鳧','唐','御定全唐诗','yuding','','[]','澗壑吼風雷，香門絕頂開。閣寒僧不下，鐘定虎常來。',48,'御定全唐詩/json/543.json','["澗壑吼風雷，香門絕頂開。閣寒僧不下，鐘定虎常來。", "鳥啄林稍果，鼯跳竹裏苔。心源無一事，塵界擬休回。"]'),
('yuding-11','題翠微寺','喻鳧','唐','御定全唐诗','yuding','','[]','沿溪又涉巔，始喜入前軒。鐘度鳥沈壑，殿扃雲濕幡。',48,'御定全唐詩/json/543.json','["沿溪又涉巔，始喜入前軒。鐘度鳥沈壑，殿扃雲濕幡。", "涼泉墮眾石，古木徹疏猿。月上僧階近，斯游豈易言。"]'),
('yuding-12','廣德官舍二松','喻鳧','唐','御定全唐诗','yuding','','[]','楊公休簿領，二木日堅牢。直甚彰吾節，清終庇爾曹。',48,'御定全唐詩/json/543.json','["楊公休簿領，二木日堅牢。直甚彰吾節，清終庇爾曹。", "幽陰月裏細，冷樹雪中高。誰見幹霄後，枝飄白鶴毛。"]'),
('yuding-13','浴馬','喻鳧','唐','御定全唐诗','yuding','','[]','解控複收鞭，長津動細漣。空蹄沈綠玉，闊臆沒連錢。',48,'御定全唐詩/json/543.json','["解控複收鞭，長津動細漣。空蹄沈綠玉，闊臆沒連錢。", "沫漩橋聲下，嘶盤柳影邊。常聞稟龍性，固與白波便。"]'),
('yuding-14','和段學士南亭春日對雨','喻鳧','唐','御定全唐诗','yuding','','[]','晨飛晚未休，蘭閣客吟愁。蕭颯柳邊掛，縈紆花底流。',48,'御定全唐詩/json/543.json','["晨飛晚未休，蘭閣客吟愁。蕭颯柳邊掛，縈紆花底流。", "聲繁乍離籟，灑急不成漚。經夕江湖思，煙波一釣舟。"]'),
('yuding-15','書懷','喻鳧','唐','御定全唐诗','yuding','','[]','只是守琴書，僧中獨寓居。心唯務鶴靜，分合與名疏。',48,'御定全唐詩/json/543.json','["只是守琴書，僧中獨寓居。心唯務鶴靜，分合與名疏。", "暮雨啼螿次，涼風落木初。家山太湖淥，歸去複何如。"]'),
('yuding-16','一公房','喻鳧','唐','御定全唐诗','yuding','','[]','幽深誰掩關，清淨自多閑。一雨收眾木，孤雲生遠山。',48,'御定全唐詩/json/543.json','["幽深誰掩關，清淨自多閑。一雨收眾木，孤雲生遠山。", "花萎綠苔上，鴿乳翠樓間。嵐靄燃香夕，容聽半偈還。"]'),
('yuding-17','晚次臨涇','喻鳧','唐','御定全唐诗','yuding','','[]','路入犬羊群，城寒雉堞曛。居人只尚武，過客謾投文。',48,'御定全唐詩/json/543.json','["路入犬羊群，城寒雉堞曛。居人只尚武，過客謾投文。", "馬怯奔渾水，雕沈莽蒼雲。沙田積蒿艾，竟夕見燒焚。"]'),
('yuding-18','王母祠前寫望','喻鳧','唐','御定全唐诗','yuding','','[]','雲霞千古事，桃李舊花顏。芳信沈青鳥，空祠掩暮山。',48,'御定全唐詩/json/543.json','["雲霞千古事，桃李舊花顏。芳信沈青鳥，空祠掩暮山。", "香傳一座暗，柳匝萬家閑。那複傷神所，河昏落日間。"]'),
('yuding-19','遊暖泉精舍','喻鳧','唐','御定全唐诗','yuding','','[]','塢木殿前空，山河澤國同。鳥閑沙影上，泉落樹陰中。',48,'御定全唐詩/json/543.json','["塢木殿前空，山河澤國同。鳥閑沙影上，泉落樹陰中。", "纜舸蒲花水，縈幡柳絮風。翛然方寸地，何事更悲蓬。"]'),
('yuding-20','懷鄉','喻鳧','唐','御定全唐诗','yuding','','[]','秋風江上家，釣艇泊蘆花。斷岸綠楊蔭，疏籬紅槿遮。',48,'御定全唐詩/json/543.json','["秋風江上家，釣艇泊蘆花。斷岸綠楊蔭，疏籬紅槿遮。", "鼉鳴積雨窟，鶴步夕陽沙。抱疾僧窗夜，歸心過月斜。"]'),
('yuding-21','岫禪師南溪蘭若','喻鳧','唐','御定全唐诗','yuding','','[]','錫影配瓶光，孤溪照草堂。水懸青石磴，鐘動白雲床。',48,'御定全唐詩/json/543.json','["錫影配瓶光，孤溪照草堂。水懸青石磴，鐘動白雲床。", "樹色含殘雨，河流帶夕陽。唯應無月夜，瞑目見他方。"]'),
('yuding-22','龍翔寺寄李頻','喻鳧','唐','御定全唐诗','yuding','','[]','鐘聲南北寺，不道往來遙。人事因循過，時光荏苒銷。',48,'御定全唐詩/json/543.json','["鐘聲南北寺，不道往來遙。人事因循過，時光荏苒銷。", "懸燈灑砌雨，上閣繞雲雕。即是洲中柳，嘶蟬急暮條。"]'),
('yuding-23','送武瑴之邠甯','喻鳧','唐','御定全唐诗','yuding','','[]','戍路少人蹤，邊煙淡複濃。詩寧寫別恨，酒不上離容。',48,'御定全唐詩/json/543.json','["戍路少人蹤，邊煙淡複濃。詩寧寫別恨，酒不上離容。", "燕拂沙河柳，鴉高石窟鐘。悠然一暌阻，山疊虜雲重。"]'),
('yuding-24','夏日題岫禪師房','喻鳧','唐','御定全唐诗','yuding','','[]','朝朝聲磬罷，章子掃藤陰。花過少遊客，日長無事心。',48,'御定全唐詩/json/543.json','["朝朝聲磬罷，章子掃藤陰。花過少遊客，日長無事心。", "回山閉院直，落水下橋深。安得開方便，容身老此林。"]'),
('yuding-25','夏日因懷陽羨舊游寄裴書記','喻鳧','唐','御定全唐诗','yuding','','[]','落日太湖西，波涵萬象低。藕花熏浦漵，菱蔓匿鳧鷖。',48,'御定全唐詩/json/543.json','["落日太湖西，波涵萬象低。藕花熏浦漵，菱蔓匿鳧鷖。", "樹及長橋盡，灘回七裏迷。還應坐籌暇，時一夢荊溪。"]'),
('yuding-26','呈薛博士','喻鳧','唐','御定全唐诗','yuding','','[]','辛勤長在學，一室少曾開。時憶暮山寺，獨登衰草台。',48,'御定全唐詩/json/543.json','["辛勤長在學，一室少曾開。時憶暮山寺，獨登衰草台。", "名期五字立，跡愧九年來。此意今聊寫，還希君子哀。"]'),
('yuding-27','即事','喻鳧','唐','御定全唐诗','yuding','','[]','抱杖立溪口，迎秋看塞門。連山互蒼翠，二水各清渾。',48,'御定全唐詩/json/543.json','["抱杖立溪口，迎秋看塞門。連山互蒼翠，二水各清渾。", "笛發孤煙戍，鴉歸夕照村。萋萋芳草色，終是憶王孫。"]'),
('yuding-28','龍翔寺閣夜懷渭南張少府','喻鳧','唐','御定全唐诗','yuding','','[]','春城帶病別，秋塞見除書。況是神仙吏，仍非塵土居。',48,'御定全唐詩/json/543.json','["春城帶病別，秋塞見除書。況是神仙吏，仍非塵土居。", "河風吹鳥迥，嶽雨滴桐疏。坐閣馳思夕，沙東涼月虛。"]'),
('yuding-29','夏日龍翔寺居即事寄崔侍禦','喻鳧','唐','御定全唐诗','yuding','','[]','古刹一幡斜，吹門水過沙。數聲鐘裏飯，雙影樹間茶。',48,'御定全唐詩/json/543.json','["古刹一幡斜，吹門水過沙。數聲鐘裏飯，雙影樹間茶。", "落日窮荒雨，微風古塹花。何當戴豸客，複此問生涯。"]'),
('yuding-30','龍翔寺居喜胡權見訪因宿','喻鳧','唐','御定全唐诗','yuding','','[]','林棲無異歡，煮茗就花欄。雀啅北岡曉，僧開西閣寒。',48,'御定全唐詩/json/543.json','["林棲無異歡，煮茗就花欄。雀啅北岡曉，僧開西閣寒。", "沖橋二水急，扣月一鐘殘。明發還分手，徒悲行路難。"]'),
('yuding-31','宿石窟寺','喻鳧','唐','御定全唐诗','yuding','','[]','一刹古岡南，孤鐘撼夕嵐。客閑明月閣，僧閉白雲庵。',48,'御定全唐詩/json/543.json','["一刹古岡南，孤鐘撼夕嵐。客閑明月閣，僧閉白雲庵。", "野鶴立枯枿，天龍吟淨潭。因知不生理，合自此中探。"]'),
('yuding-32','夏日龍翔寺寄張侍禦','喻鳧','唐','御定全唐诗','yuding','','[]','沙西林杪寺，殿倚石棱開。曉月僧汲井，殘陽鐘殷台。',48,'御定全唐詩/json/543.json','["沙西林杪寺，殿倚石棱開。曉月僧汲井，殘陽鐘殷台。", "河沖綠野去，鳥背白雲來。日夕唯增思，京關未想回。"]'),
('yuding-33','秋日將歸長安留別王尚書','喻鳧','唐','御定全唐诗','yuding','','[]','朔漠正秋霖，西風傳夕砧。滄洲未歸跡，華髮受恩心。',48,'御定全唐詩/json/543.json','["朔漠正秋霖，西風傳夕砧。滄洲未歸跡，華髮受恩心。", "露色岡莎冷，蟬聲塢木深。清晨鈇鉞內，只獻白雲吟。"]'),
('yuding-34','龍翔寺言懷','喻鳧','唐','御定全唐诗','yuding','','[]','眠雲喜道存，讀易過朝昏。喬木青連郭，長河白瀉門。',48,'御定全唐詩/json/543.json','["眠雲喜道存，讀易過朝昏。喬木青連郭，長河白瀉門。", "鐘沈殘月塢，鳥去夕陽村。搜此成閑句，期逢作者論。"]'),
('yuding-35','龍翔寺居夏日寄獻王尚書','喻鳧','唐','御定全唐诗','yuding','','[]','那期高旆下，得遇重臣知。泉石容居止，風沙免路岐。',48,'御定全唐詩/json/543.json','["那期高旆下，得遇重臣知。泉石容居止，風沙免路岐。", "河兼落下望，句入大荒思。無複愁煩暑，回山翠閣危。"]'),
('yuding-36','題弘濟寺不出院僧','喻鳧','唐','御定全唐诗','yuding','','[]','楚鞋應此世，只繞砌苔休。色相栽花視，身心坐石修。',48,'御定全唐詩/json/543.json','["楚鞋應此世，只繞砌苔休。色相栽花視，身心坐石修。", "聲寒通節院，城黑見烽樓。欲取閑雲並，閑雲有去留。"]'),
('yuding-37','寄劉錄事','喻鳧','唐','御定全唐诗','yuding','','[]','城西青島寺，累夏漱寒泉。今在提綱所，應難掃石眠。',48,'御定全唐詩/json/543.json','["城西青島寺，累夏漱寒泉。今在提綱所，應難掃石眠。", "風沙榆塞迥，波浪橘洲偏。重整瀟湘棹，心期更幾年。"]'),
('yuding-38','酬王檀見寄','喻鳧','唐','御定全唐诗','yuding','','[]','馳心棲杳冥，何物比清泠。夜月照巫峽，秋風吹洞庭。',48,'御定全唐詩/json/543.json','["馳心棲杳冥，何物比清泠。夜月照巫峽，秋風吹洞庭。", "酬難塵鬢皓，坐久壁燈青。竟晚蒼山詠，喬枝有鶴聽。"]'),
('yuding-39','寺居秋日對雨有懷','喻鳧','唐','御定全唐诗','yuding','','[]','修修復雭雭，黃葉此時飛。隱幾客吟斷，鄰房僧話稀。',48,'御定全唐詩/json/543.json','["修修復雭雭，黃葉此時飛。隱幾客吟斷，鄰房僧話稀。", "鴿寒棲樹定，螢濕在窗微。即事瀟湘渚，漁翁披草衣。"]'),
('yuding-40','答劉錄事夜月懷湘西友人見寄','喻鳧','唐','御定全唐诗','yuding','','[]','相逢仍朔漠，相問即波濤。江思葦花折，笛聲關月高。',48,'御定全唐詩/json/543.json','["相逢仍朔漠，相問即波濤。江思葦花折，笛聲關月高。", "簿書君閱倦，章句我吟勞。竟夕空憑閣，長河漴石壕。"]'),
('yuding-41','上高侍禦','喻鳧','唐','御定全唐诗','yuding','','[]','舊隱白雲峰，生涯落葉同。關河一棲旅，楊柳十東風。',48,'御定全唐詩/json/543.json','["舊隱白雲峰，生涯落葉同。關河一棲旅，楊柳十東風。", "跡處龍鍾內，聲居汩沒中。酬恩若有地，寧止殺微躬。"]'),
('yuding-42','冬日寄友人','喻鳧','唐','御定全唐诗','yuding','','[]','空為梁甫吟，誰竟是知音。風雪坐閑夜，鄉園來舊心。',48,'御定全唐詩/json/543.json','["空為梁甫吟，誰竟是知音。風雪坐閑夜，鄉園來舊心。", "滄江孤棹迥，落日一鐘深。君子久忘我，此誠甘自沈。"]'),
('yuding-43','冬夜宿餘正字靜恭裏閒居','喻鳧','唐','御定全唐诗','yuding','','[]','每來多便宿，不負白雲言。古木朔風動，寒城疏雪翻。',48,'御定全唐詩/json/543.json','["每來多便宿，不負白雲言。古木朔風動，寒城疏雪翻。", "微燈懸刻漏，舊夢返湘沅。先是琴邊起，知為閣務繁。"]'),
('yuding-44','得子侄書','喻鳧','唐','御定全唐诗','yuding','','[]','遠書來阮巷，闕下見江東。不得經史力，枉拋耕稼功。',48,'御定全唐詩/json/543.json','["遠書來阮巷，闕下見江東。不得經史力，枉拋耕稼功。", "雁天霞腳雨，漁夜葦條風。無複琴杯興，開懷向爾同。"]'),
('yuding-45','獻知己','喻鳧','唐','御定全唐诗','yuding','','[]','亦忝受恩身，當殊投刺新。竟蒙分玉石，終不離埃塵。',48,'御定全唐詩/json/543.json','["亦忝受恩身，當殊投刺新。竟蒙分玉石，終不離埃塵。", "大穀非無暖，幽枝自未春。昏昏過朝夕，應念苦吟人。"]'),
('yuding-46','贈張濆處士','喻鳧','唐','御定全唐诗','yuding','','[]','露白覆棋宵，林青讀易朝。道高天子問，名重四方招。',48,'御定全唐詩/json/543.json','["露白覆棋宵，林青讀易朝。道高天子問，名重四方招。", "許鶴歸華頂，期僧過石橋。雖然在京國，心跡自逍遙。"]'),
('yuding-47','早秋寺居酬張侍禦六韻見寄','喻鳧','唐','御定全唐诗','yuding','','[]','六十上清冥，曉緘東越藤。山光紫衣陟，寺影白雲凝。',72,'御定全唐詩/json/543.json','["六十上清冥，曉緘東越藤。山光紫衣陟，寺影白雲凝。", "濕葉起寒鳥，深林驚古僧。微風窗靜展，細雨閣吟登。", "清韻嶽磬遠，佳音湖水澄。卻思前所獻，何以豸冠稱。"]'),
('yuding-48','和段學士對雪','喻鳧','唐','御定全唐诗','yuding','','[]','盈尺知豐稔，開窗對酒壺。飄當大野匝，灑到急流無。',72,'御定全唐詩/json/543.json','["盈尺知豐稔，開窗對酒壺。飄當大野匝，灑到急流無。", "密際西風盡，凝間朔氣扶。幹摧鳥棲枿，冷射夜殘壚。", "贊月登斜漢，兼沙攪北湖。慚於郢客坐，一此調巴歈。"]'),
('yuding-49','監試夜雨滴空階','喻鳧','唐','御定全唐诗','yuding','','[]','霎霎複淒淒，飄松又灑槐。氣蒙蛛網檻，聲疊蘚花階。',72,'御定全唐詩/json/543.json','["霎霎複淒淒，飄松又灑槐。氣蒙蛛網檻，聲疊蘚花階。", "古壁青燈動，深庭濕葉埋。徐垂舊鴛瓦，競曆小茅齋。", "冷與陰蟲間，清將玉漏諧。病身唯輾轉，誰見此時懷。"]'),
('yuding-50','春雨如膏','喻鳧','唐','御定全唐诗','yuding','','[]','冪冪斂輕塵，濛濛濕野春。細光添柳重，幽點濺花勻。',72,'御定全唐詩/json/543.json','["冪冪斂輕塵，濛濛濕野春。細光添柳重，幽點濺花勻。", "慘澹遊絲景，陰沈落絮辰。回低飛蝶翅，寒滴語禽身。", "灑嶽摧餘雪，吹江疊遠蘋。東城與西陌，晴後趣何新。"]'),
('yuding-51','送友人南中訪舊知','喻鳧','唐','御定全唐诗','yuding','','[]','春盡大方遊，思君便白頭。地蒸川有毒，天暖樹無秋。',48,'御定全唐詩/json/543.json','["春盡大方遊，思君便白頭。地蒸川有毒，天暖樹無秋。", "水急三巴險，猿分五嶺愁。為緣知己分，南國必淹留。"]'),
('yuding-52','玄都觀李尊師','喻鳧','唐','御定全唐诗','yuding','','[]','蘚幘翠髯公，存思古觀空。曉壇檉葉露，晴圃柳花風。',48,'御定全唐詩/json/543.json','["蘚幘翠髯公，存思古觀空。曉壇檉葉露，晴圃柳花風。", "壽已將椿並，棋難見局終。何當與高鶴，飛去海光中。"]'),
('yuding-53','送石賁歸吳興','喻鳧','唐','御定全唐诗','yuding','','[]','同志幸同年，高堂君獨還。齊榮恩未報，共隱事皆閑。',48,'御定全唐詩/json/543.json','["同志幸同年，高堂君獨還。齊榮恩未報，共隱事皆閑。", "訪寺臨河岸，開樓見海山。洛中推二陸，莫久戀鄉關。"]'),
('yuding-54','感遇','喻鳧','唐','御定全唐诗','yuding','','[]','江鄉十年別，京國累日同。在客幾多事，俱付酒杯中。',24,'御定全唐詩/json/543.json','["江鄉十年別，京國累日同。在客幾多事，俱付酒杯中。"]'),
('yuding-55','晚思','喻鳧','唐','御定全唐诗','yuding','','[]','鶴下紫閣雲，沉沉翠微雨。獨坐正無言，孤莊一聲杵。',24,'御定全唐詩/json/543.json','["鶴下紫閣雲，沉沉翠微雨。獨坐正無言，孤莊一聲杵。"]'),
('yuding-56','贈空禪師','喻鳧','唐','御定全唐诗','yuding','','[]','虎見修行久，松知夏臘高。寒堂坐風雨，瞑目尚波濤。',24,'御定全唐詩/json/543.json','["虎見修行久，松知夏臘高。寒堂坐風雨，瞑目尚波濤。"]'),
('yuding-57','西山寒日逢韋侍禦','喻鳧','唐','御定全唐诗','yuding','','[]','獬豸霜中貌，龍鍾病後顏。慘傷此身事，風雪動江山。',24,'御定全唐詩/json/543.json','["獬豸霜中貌，龍鍾病後顏。慘傷此身事，風雪動江山。"]'),
('yuding-58','題禪院','喻鳧','唐','御定全唐诗','yuding','','[]','無花地亦香，有鶴松多直。向此奚必孤，山僧盡相識。',24,'御定全唐詩/json/543.json','["無花地亦香，有鶴松多直。向此奚必孤，山僧盡相識。"]'),
('yuding-59','驚秋','喻鳧','唐','御定全唐诗','yuding','','[]','鶯囀才間關，蟬鳴旋蕭屑。如何兩鬢毛，不作千枝雪。',24,'御定全唐詩/json/543.json','["鶯囀才間關，蟬鳴旋蕭屑。如何兩鬢毛，不作千枝雪。"]'),
('yuding-60','經劉校書墓','喻鳧','唐','御定全唐诗','yuding','','[]','遠塚松回曲渚風，一官聞是校書終。',32,'御定全唐詩/json/543.json','["遠塚松回曲渚風，一官聞是校書終。", "霜情月思今何在，零落人間策子中。"]'),
('yuding-61','蔣處士宅喜閑公至','喻鳧','唐','御定全唐诗','yuding','','[]','絕杯夏別螺江渡，單缽春過處士齋。',32,'御定全唐詩/json/543.json','["絕杯夏別螺江渡，單缽春過處士齋。", "嘗茗議空經不夜，照花明月影侵階。"]'),
('yuding-62','絕句','喻鳧','唐','御定全唐诗','yuding','','[]','銀地無塵金菊開，紫梨紅棗墮莓苔。',32,'御定全唐詩/json/543.json','["銀地無塵金菊開，紫梨紅棗墮莓苔。", "一泓秋水一輪月，今夜故人來不來。"]'),
('yuding-63','句','喻鳧','唐','御定全唐诗','yuding','','[]','顏凋明鏡覺，思苦白雲知。',25,'御定全唐詩/json/543.json','["顏凋明鏡覺，思苦白雲知。", "滄洲迷釣隱，紫閣負僧期。。"]'),
('yuding-0','聽歌','劉得仁','唐','御定全唐诗','yuding','','[]','朱檻滿明月，美人歌落梅。忽驚塵起處，疑是有風來。',48,'御定全唐詩/json/544.json','["朱檻滿明月，美人歌落梅。忽驚塵起處，疑是有風來。", "一曲聽初徹，幾年愁暫開。東南正雲雨，不得見陽臺。"]'),
('yuding-1','青龍寺僧院','劉得仁','唐','御定全唐诗','yuding','','[]','常多簪組客，非獨看高松。此地堪終日，開門見數峰。',48,'御定全唐詩/json/544.json','["常多簪組客，非獨看高松。此地堪終日，開門見數峰。", "苔新禽跡少，泉冷樹陰重。師意如山裏，空房曉暮鐘。"]'),
('yuding-2','夏夜會同人','劉得仁','唐','御定全唐诗','yuding','','[]','沉沉清暑夕，星斗儼虛空。岸幘棲禽下，烹茶玉漏中。',48,'御定全唐詩/json/544.json','["沉沉清暑夕，星斗儼虛空。岸幘棲禽下，烹茶玉漏中。", "形骸忘已久，偃仰趣無窮。日汲泉來漱，微開密筱風。"]'),
('yuding-3','游崔監丞城南別業','劉得仁','唐','御定全唐诗','yuding','','[]','門與青山近，青山複幾重。雪融皇子岸，春浥翠微峰。',48,'御定全唐詩/json/544.json','["門與青山近，青山複幾重。雪融皇子岸，春浥翠微峰。", "地有經冬草，林無未老松。竹寒溪隔寺，晴日直聞鐘。"]'),
('yuding-4','答韋先輩春雨後見寄','劉得仁','唐','御定全唐诗','yuding','','[]','風散五更雨，鳥啼三月春。軒窗透初日，硯席絕纖塵。',48,'御定全唐詩/json/544.json','["風散五更雨，鳥啼三月春。軒窗透初日，硯席絕纖塵。", "帝裏峰頭出，鄰家樹色新。憐君高且靜，有句寄閒人。"]'),
('yuding-5','題吳先生山居','劉得仁','唐','御定全唐诗','yuding','','[]','先生此幽隱，便可謝人群。潭底見秋石，樹間飛霽雲。',48,'御定全唐詩/json/544.json','["先生此幽隱，便可謝人群。潭底見秋石，樹間飛霽雲。", "山居心已慣，俗事耳憎聞。念我要多疾，開爐藥許分。"]'),
('yuding-6','晚遊慈恩寺','劉得仁','唐','御定全唐诗','yuding','','[]','寺去幽居近，每來因采薇。伴僧行不困，臨水語忘歸。',48,'御定全唐詩/json/544.json','["寺去幽居近，每來因采薇。伴僧行不困，臨水語忘歸。", "磬動青林晚，人驚白鷺飛。堪嗟浮俗事，皆與道相違。"]'),
('yuding-7','題王處士山居','劉得仁','唐','御定全唐诗','yuding','','[]','茅堂入谷遠，林暗絕其鄰。終日有流水，經年無到人。',48,'御定全唐詩/json/544.json','["茅堂入谷遠，林暗絕其鄰。終日有流水，經年無到人。", "溪雲常欲雨，山洞別開春。自得仙家術，栽松獨養真。"]'),
('yuding-8','宿僧院','劉得仁','唐','御定全唐诗','yuding','','[]','禪地無塵夜，焚香話所歸。樹搖幽鳥夢，螢入定僧衣。',48,'御定全唐詩/json/544.json','["禪地無塵夜，焚香話所歸。樹搖幽鳥夢，螢入定僧衣。", "破月斜天半，高河下露微。翻令嫌白日，動即與心違。"]'),
('yuding-9','曉別呂山人','劉得仁','唐','御定全唐诗','yuding','','[]','疏鐘兼漏盡，曙色照青氛。棲鶴出高樹，山人歸白雲。',48,'御定全唐詩/json/544.json','["疏鐘兼漏盡，曙色照青氛。棲鶴出高樹，山人歸白雲。", "月盈期重宿，丹熟約相分。羨入秋風洞，幽泉仔細聞。"]'),
('yuding-10','送知全禪師南游','劉得仁','唐','御定全唐诗','yuding','','[]','師譽振京城，談空萬乘聽。北行山已雪，南去木猶青。',48,'御定全唐詩/json/544.json','["師譽振京城，談空萬乘聽。北行山已雪，南去木猶青。", "夜嶽禪銷月，秋潭汲動星。回期不可定，孤鶴在高冥。"]'),
('yuding-11','上張水部','劉得仁','唐','御定全唐诗','yuding','','[]','出入門闌久，兒童亦有情。不須將姓字，長說向公卿。',48,'御定全唐詩/json/544.json','["出入門闌久，兒童亦有情。不須將姓字，長說向公卿。", "每許連床坐，時容並馬行。恩深轉無語，懷抱自分明。"]'),
('yuding-12','塞上行作','劉得仁','唐','御定全唐诗','yuding','','[]','鄉井從離別，窮邊觸目愁。生人居外地，塞雪下中秋。',48,'御定全唐詩/json/544.json','["鄉井從離別，窮邊觸目愁。生人居外地，塞雪下中秋。", "雁舉之衡翅，河穿入虜流。將軍心莫苦，向此取封侯。"]'),
('yuding-13','贈江夏盧使君','劉得仁','唐','御定全唐诗','yuding','','[]','詩人中最屈，無與使君儔。白髮雖求退，明時合見收。',48,'御定全唐詩/json/544.json','["詩人中最屈，無與使君儔。白髮雖求退，明時合見收。", "登山猶自健，縱酒可多愁。好是能騎馬，相逢見鄂州。"]'),
('yuding-14','冬夜寄白閣僧','劉得仁','唐','御定全唐诗','yuding','','[]','營營不自息，暌闊數年情。林下期難遂，人間事旋生。',48,'御定全唐詩/json/544.json','["營營不自息，暌闊數年情。林下期難遂，人間事旋生。", "鳥棲寒水迥，月映積冰清。石室焚香坐，懸知不為名。"]'),
('yuding-15','送姚合郎中任杭州','劉得仁','唐','御定全唐诗','yuding','','[]','水陸中分程，看花一月行。會稽山隔浪，天竺樹連城。',48,'御定全唐詩/json/544.json','["水陸中分程，看花一月行。會稽山隔浪，天竺樹連城。", "候吏齎魚印，迎船載旆旌。渡江春始半，列嶼草初生。"]'),
('yuding-16','西園','劉得仁','唐','御定全唐诗','yuding','','[]','夏圃秋涼入，樹低逢幘欹。水聲翻敗堰，山翠濕疏籬。',48,'御定全唐詩/json/544.json','["夏圃秋涼入，樹低逢幘欹。水聲翻敗堰，山翠濕疏籬。", "綠滑莎藏徑，紅連果壓枝。幽人更何事，旦夕與僧期。"]'),
('yuding-17','昊天觀新栽竹','劉得仁','唐','御定全唐诗','yuding','','[]','清風枝葉上，山鳥已棲來。根別古溝岸，影生秋觀苔。',48,'御定全唐詩/json/544.json','["清風枝葉上，山鳥已棲來。根別古溝岸，影生秋觀苔。", "遍思諸草木，惟此出塵埃。恨為移君晚，空庭更擬栽。"]'),
('yuding-18','晚步曲江因謁慈恩寺恭上人','劉得仁','唐','御定全唐诗','yuding','','[]','豈曰趣名者，年年待命通。坐令青嶂上，興起白雲中。',48,'御定全唐詩/json/544.json','["豈曰趣名者，年年待命通。坐令青嶂上，興起白雲中。", "岸浸如天水，林含似雨風。南宗猶有礙，西寺問恭公。"]'),
('yuding-19','送姚處士歸亳州','劉得仁','唐','御定全唐诗','yuding','','[]','白發麻衣破，還譙別弟回。首垂聽樂淚，花落待歌杯。',48,'御定全唐詩/json/544.json','["白發麻衣破，還譙別弟回。首垂聽樂淚，花落待歌杯。", "石路尋芝熟，柴門有鹿來。明王下征詔，應就碧峰開。"]'),
('yuding-20','寄樓子山雲棲上人','劉得仁','唐','御定全唐诗','yuding','','[]','一室鑿崔嵬，危梯疊蘚苔。永無塵事到，時有至人來。',48,'御定全唐詩/json/544.json','["一室鑿崔嵬，危梯疊蘚苔。永無塵事到，時有至人來。", "澗穀冬深靜，煙嵐日午開。修身知得地，京寺未言回。"]'),
('yuding-21','秋夜喜友人宿','劉得仁','唐','御定全唐诗','yuding','','[]','莫說春闈事，清宵且共吟。頻年遺我輩，何日遇知音。',48,'御定全唐詩/json/544.json','["莫說春闈事，清宵且共吟。頻年遺我輩，何日遇知音。", "逼曙天傾鬥，將寒葉墜林。無將簪紱意，只損壯夫心。"]'),
('yuding-22','秋日同僧宿西池','劉得仁','唐','御定全唐诗','yuding','','[]','菡萏遍秋水，隔林香似焚。僧同池上宿，霞向月邊分。',48,'御定全唐詩/json/544.json','["菡萏遍秋水，隔林香似焚。僧同池上宿，霞向月邊分。", "渚鳥棲蒲立，城砧接曙聞。來宵莫他約，重此話孤雲。"]'),
('yuding-23','宿韋津山居','劉得仁','唐','御定全唐诗','yuding','','[]','永夕見招宿，詩書盈草堂。靜吟傾美酒，高論出名場。',48,'御定全唐詩/json/544.json','["永夕見招宿，詩書盈草堂。靜吟傾美酒，高論出名場。", "窗颯松篁韻，庭兼雪月光。心期身未老，一去泛瀟湘。"]'),
('yuding-24','夜攜酒訪崔正字','劉得仁','唐','御定全唐诗','yuding','','[]','只應芸閣吏，知我僻兼愚。吟興忘饑凍，生涯任有無。',48,'御定全唐詩/json/544.json','["只應芸閣吏，知我僻兼愚。吟興忘饑凍，生涯任有無。", "慘雲埋遠岫，陰吹吼寒株。忽起圍爐思，招攜酒滿壺。"]'),
('yuding-25','送蔡京東歸迎侍','劉得仁','唐','御定全唐诗','yuding','','[]','高堂惟兩別，此別是榮歸。薄俸迎親遠，平時知己稀。',48,'御定全唐詩/json/544.json','["高堂惟兩別，此別是榮歸。薄俸迎親遠，平時知己稀。", "鄆郊秋木見，魯寺夜鐘微。近臘西來日，多逢霰雪飛。"]'),
('yuding-26','中秋','劉得仁','唐','御定全唐诗','yuding','','[]','塵裏兼塵外，咸期此夕明。一年惟一度，長恐有雲生。',48,'御定全唐詩/json/544.json','["塵裏兼塵外，咸期此夕明。一年惟一度，長恐有雲生。", "露洗微埃盡，光濡是物清。朗吟看正好，惆悵又西傾。"]'),
('yuding-27','池上宿','劉得仁','唐','御定全唐诗','yuding','','[]','事事不求奢，長吟省歎嗟。無才堪世棄，有句向誰誇。',48,'御定全唐詩/json/544.json','["事事不求奢，長吟省歎嗟。無才堪世棄，有句向誰誇。", "老樹呈秋色，空池浸月華。涼風白露夕，此境屬詩家。"]'),
('yuding-28','秋夕即事','劉得仁','唐','御定全唐诗','yuding','','[]','永夕坐暝久，蕭蕭猿狖啼。漏微砧韻隔，月落鬥杓低。',48,'御定全唐詩/json/544.json','["永夕坐暝久，蕭蕭猿狖啼。漏微砧韻隔，月落鬥杓低。", "危葉無風墜，幽禽並樹棲。自憐在岐路，不醉亦沉迷。"]'),
('yuding-29','晚夏','劉得仁','唐','御定全唐诗','yuding','','[]','日夕是西風，流光半已空。山光漸凝碧，樹葉即翻紅。',48,'御定全唐詩/json/544.json','["日夕是西風，流光半已空。山光漸凝碧，樹葉即翻紅。", "學淺慚多士，秋成羨老農。誰憐信公道，不泣路岐中。"]'),
('yuding-30','夏日即事','劉得仁','唐','御定全唐诗','yuding','','[]','到曉改詩句，四鄰嫌苦吟。中宵橫北斗，夏木隱棲禽。',48,'御定全唐詩/json/544.json','["到曉改詩句，四鄰嫌苦吟。中宵橫北斗，夏木隱棲禽。", "天地先秋肅，軒窗映月深。幽庭多此景，惟恐曙光侵。"]'),
('yuding-31','夏日通濟裏居酬諸先輩見訪','劉得仁','唐','御定全唐诗','yuding','','[]','君子遠相尋，聯鑣到敝林。有詩誰索和，無酒可賒斟。',48,'御定全唐詩/json/544.json','["君子遠相尋，聯鑣到敝林。有詩誰索和，無酒可賒斟。", "門列晴峰色，堂開古木陰。何因駐清聽，惟恐日西沉。"]'),
('yuding-32','寄姚諫議','劉得仁','唐','御定全唐诗','yuding','','[]','鳴鞭靜路塵，籍籍諫垣臣。函疏封還密，爐香侍立親。',48,'御定全唐詩/json/544.json','["鳴鞭靜路塵，籍籍諫垣臣。函疏封還密，爐香侍立親。", "篋多臨水作，窗宿臥雲人。危坐開寒紙，燈前起草頻。"]'),
('yuding-33','和厲玄侍禦題戶部相公廬山草堂','劉得仁','唐','御定全唐诗','yuding','','[]','白雲居創畢，詔入鳳池年。林長雙峰樹，潭分並寺泉。',48,'御定全唐詩/json/544.json','["白雲居創畢，詔入鳳池年。林長雙峰樹，潭分並寺泉。", "石溪盤鶴外，嶽室閉猿前。柱史題詩後，松前更肅然。"]'),
('yuding-34','題山中故靜禪師','劉得仁','唐','御定全唐诗','yuding','','[]','寂滅身何在，門人隔此生。影懸塵已厚，塔種柏初成。',48,'御定全唐詩/json/544.json','["寂滅身何在，門人隔此生。影懸塵已厚，塔種柏初成。", "溪院秋先雪，山堂古有精。當時掛錫處，樹老幾枝傾。"]'),
('yuding-35','夏日遊慈恩寺','劉得仁','唐','御定全唐诗','yuding','','[]','何處消長日，慈恩精舍頻。僧高容野客，樹密絕囂塵。',48,'御定全唐詩/json/544.json','["何處消長日，慈恩精舍頻。僧高容野客，樹密絕囂塵。", "閑上淩虛塔，相逢避暑人。卻愁歸去路，馬跡並車輪。"]'),
('yuding-36','題終南麻先生寂禪師石室','劉得仁','唐','御定全唐诗','yuding','','[]','因居石室貧，五十二回春。擁褐冥心客，窮經暮齒人。',48,'御定全唐詩/json/544.json','["因居石室貧，五十二回春。擁褐冥心客，窮經暮齒人。", "翠沉空水定，雨絕片雲新。危細秋峰徑，相隨到頂頻。"]'),
('yuding-37','送靈武朱書記','劉得仁','唐','御定全唐诗','yuding','','[]','靈帥與誰善，得君賓幕中。從容應盡禮，贊畫致元功。',48,'御定全唐詩/json/544.json','["靈帥與誰善，得君賓幕中。從容應盡禮，贊畫致元功。", "連塞雲長慘，才秋樹半空。相如偏自愜，掌記複乘驄。"]'),
('yuding-38','吊草堂禪師','劉得仁','唐','御定全唐诗','yuding','','[]','杖履疑師在，房關四壁蛩。貯瓶經臘水，響塔隔山鐘。',48,'御定全唐詩/json/544.json','["杖履疑師在，房關四壁蛩。貯瓶經臘水，響塔隔山鐘。", "乳鴿沿苔井，齋猿散雪峰。如何不相見，倚遍寺前松。"]'),
('yuding-39','早春送湘潭李少府之任','劉得仁','唐','御定全唐诗','yuding','','[]','柳新春水湄，春岸草離離。祖席觴雲盡，離人淚各垂。',48,'御定全唐詩/json/544.json','["柳新春水湄，春岸草離離。祖席觴雲盡，離人淚各垂。", "業文傳不朽，作尉豈多時。公退琴堂上，風吹斑竹枝。"]'),
('yuding-40','送越客歸','劉得仁','唐','御定全唐诗','yuding','','[]','霜薄東南地，江楓落未齊。眾山離楚上，孤棹宿吳西。',48,'御定全唐詩/json/544.json','["霜薄東南地，江楓落未齊。眾山離楚上，孤棹宿吳西。", "渚客留僧語，籠猿失子啼。到家冬即是，荷盡若耶溪。"]'),
('yuding-41','送周鉞往江夏','劉得仁','唐','御定全唐诗','yuding','','[]','東西南北郡，自說遍曾遊。人世終多故，皇都不少留。',48,'御定全唐詩/json/544.json','["東西南北郡，自說遍曾遊。人世終多故，皇都不少留。", "郢城帆過夜，漢水月方秋。此謁親知去，聞猿豈解愁。"]'),
('yuding-42','送河池李明府之任','劉得仁','唐','御定全唐诗','yuding','','[]','河池安所理，種柳與彈琴。自合清時化，仍資白首吟。',48,'御定全唐詩/json/544.json','["河池安所理，種柳與彈琴。自合清時化，仍資白首吟。", "程餘行片月，公退入遙林。想得詢民瘼，方稱單父心。"]'),
('yuding-43','送蔡京侍禦赴大樑幕','劉得仁','唐','御定全唐诗','yuding','','[]','同城各多故，會面亦稀疏。及道須相別，臨岐恨有餘。',48,'御定全唐詩/json/544.json','["同城各多故，會面亦稀疏。及道須相別，臨岐恨有餘。", "梁園飛楚鳥，汴水走淮魚。眾說裁軍檄，陳琳遠不如。"]'),
('yuding-44','哭鮑溶有感','劉得仁','唐','御定全唐诗','yuding','','[]','寥落故人宅，今來身已亡。古苔封墨沼，深竹映書堂。',48,'御定全唐詩/json/544.json','["寥落故人宅，今來身已亡。古苔封墨沼，深竹映書堂。", "秋色池館靜，雨聲雲水涼。無因展交道，日暮剖心腸。"]'),
('yuding-45','送僧歸玉泉寺','劉得仁','唐','御定全唐诗','yuding','','[]','玉泉歸故刹，便老是僧期。亂木孤蟬後，寒山絕鳥時。',48,'御定全唐詩/json/544.json','["玉泉歸故刹，便老是僧期。亂木孤蟬後，寒山絕鳥時。", "若尋流水去，轉出白雲遲。見說千峰路，溪深複頂危。"]'),
('yuding-46','宣義池上','劉得仁','唐','御定全唐诗','yuding','','[]','修篁夾綠池，幽絮此中飛。何必青山遠，仍將白髮歸。',48,'御定全唐詩/json/544.json','["修篁夾綠池，幽絮此中飛。何必青山遠，仍將白髮歸。", "鳥啼亦有恨，鷗習總無機。樹起秋風細，西林磬入微。"]'),
('yuding-47','回中夜訪獨孤從事','劉得仁','唐','御定全唐诗','yuding','','[]','滿庭霜月魄，風靜絕纖聞。邊境時無事，州城夜訪君。',48,'御定全唐詩/json/544.json','["滿庭霜月魄，風靜絕纖聞。邊境時無事，州城夜訪君。", "擁裘聽塞角，酌醴話湘雲。贊佐元戎美，恩齊十萬軍。"]'),
('yuding-48','宿宣義池亭','劉得仁','唐','御定全唐诗','yuding','','[]','暮色繞柯亭，南山幽竹青。夜深斜舫月，風定一池星。',48,'御定全唐詩/json/544.json','["暮色繞柯亭，南山幽竹青。夜深斜舫月，風定一池星。", "島嶼無人跡，菰蒲有鶴翎。此中足吟眺，何用泛滄溟。"]'),
('yuding-49','送智玄首座歸蜀中舊山','劉得仁','唐','御定全唐诗','yuding','','[]','像教得重興，因師說大乘。從來悟明主，今去證高僧。',48,'御定全唐詩/json/544.json','["像教得重興，因師說大乘。從來悟明主，今去證高僧。", "蜀國煙霞異，靈山水月澄。鄉閭諸善友，喜似見南能。"]'),
('yuding-50','賀顧非熊及第其年內索文章','劉得仁','唐','御定全唐诗','yuding','','[]','愚為童稚時，已解念君詩。及得高科晚，須逢聖主知。',48,'御定全唐詩/json/544.json','["愚為童稚時，已解念君詩。及得高科晚，須逢聖主知。", "花前翻有淚，鬢上卻無絲。從此東歸去，休為墜葉期。"]'),
('yuding-51','冬日駱家亭子','劉得仁','唐','御定全唐诗','yuding','','[]','亭台臘月時，松竹見貞姿。林積煙藏日，風吹水合池。',48,'御定全唐詩/json/544.json','["亭台臘月時，松竹見貞姿。林積煙藏日，風吹水合池。", "恨無人此住，靜有鶴相窺。是景吟詩遍，真於野客宜。"]'),
('yuding-52','題邵公禪院','劉得仁','唐','御定全唐诗','yuding','','[]','無事門多掩，陰階竹掃苔。勁風吹雪聚，渴鳥啄冰開。',48,'御定全唐詩/json/544.json','["無事門多掩，陰階竹掃苔。勁風吹雪聚，渴鳥啄冰開。", "樹向寒山得，人從瀑布來。終期天目老，擎錫逐雲回。"]'),
('yuding-53','憶鶴','劉得仁','唐','御定全唐诗','yuding','','[]','自爾歸仙後，經秋又過春。白雲尋不得，紫府去無因。',48,'御定全唐詩/json/544.json','["自爾歸仙後，經秋又過春。白雲尋不得，紫府去無因。", "此地空明月，何山伴羽人。終期華表上，重見令威身。"]'),
('yuding-54','聽夜泉','劉得仁','唐','御定全唐诗','yuding','','[]','靜裏層層石，潺湲到鶴林。流回出幾洞，源遠曆千岑。',48,'御定全唐詩/json/544.json','["靜裏層層石，潺湲到鶴林。流回出幾洞，源遠曆千岑。", "寒助空山月，清兼此夜心。幽人聽達曙，相和蘚床吟。"]'),
('yuding-55','樂游原春望','劉得仁','唐','御定全唐诗','yuding','','[]','樂游原上望，望盡帝都春。始覺繁華地，應無不醉人。',48,'御定全唐詩/json/544.json','["樂游原上望，望盡帝都春。始覺繁華地，應無不醉人。", "雲開雙闕麗，柳映九衢新。愛此頻來往，多閑逐此身。"]'),
('yuding-56','贈雍陶博士','劉得仁','唐','御定全唐诗','yuding','','[]','腹是群書笥，官為六義師。情高少塵事，朝下足閒時。',48,'御定全唐詩/json/544.json','["腹是群書笥，官為六義師。情高少塵事，朝下足閒時。", "有句同人伏，無私胄子知。漢庭公議在，正與觸邪宜。"]'),
('yuding-57','夏日感懷寄所知','劉得仁','唐','御定全唐诗','yuding','','[]','了了見岐路，欲行難負心。趨時不圓轉，自古易湮沉。',48,'御定全唐詩/json/544.json','["了了見岐路，欲行難負心。趨時不圓轉，自古易湮沉。", "日正林方合，蜩鳴夏已深。中郎今遠在，誰識爨桐音。"]'),
('yuding-58','陳情上知己','劉得仁','唐','御定全唐诗','yuding','','[]','性與才俱拙，名場跡甚微。久居顏亦厚，獨立事多非。',48,'御定全唐詩/json/544.json','["性與才俱拙，名場跡甚微。久居顏亦厚，獨立事多非。", "刻骨搜新句，無人憫白衣。明時自堪戀，不是不知機。"]'),
('yuding-59','秋夜寄友人二首','劉得仁','唐','御定全唐诗','yuding','','[]','永夜無他慮，長吟畢二更。暗燈搖碧影，滯雨滴階聲。',96,'御定全唐詩/json/544.json','["永夜無他慮，長吟畢二更。暗燈搖碧影，滯雨滴階聲。", "道進愁還淺，年加睡自輕。如何得深術，相與舍浮名。", "所思同海岱，所夢亦煙波。默坐看山久，閑行值寺過。", "獨吟黃葉亂，相去碧峰多。我有歸心在，君行竟若何。"]'),
('yuding-60','寄春坊顧校書','劉得仁','唐','御定全唐诗','yuding','','[]','甯因不得志，寂寞本相宜。冥目冥心坐，花開花落時。',48,'御定全唐詩/json/544.json','["甯因不得志，寂寞本相宜。冥目冥心坐，花開花落時。", "數畦蔬甲出，半夢鳥聲移。只恐龍樓吏，歸山又見違。"]'),
('yuding-61','寄雍陶先輩','劉得仁','唐','御定全唐诗','yuding','','[]','久別青雲士，幽人分固然。愁心不易去，蹇步卒難前。',48,'御定全唐詩/json/544.json','["久別青雲士，幽人分固然。愁心不易去，蹇步卒難前。", "盡落經霜葉，頻陰欲雪天。歸山自有限，豈待白頭年。"]'),
('yuding-62','對月寄雍陶','劉得仁','唐','御定全唐诗','yuding','','[]','圓明寒魄上，天地一光中。臨水通宵坐，知君此興同。',48,'御定全唐詩/json/544.json','["圓明寒魄上，天地一光中。臨水通宵坐，知君此興同。", "華凝衣有露，靜極樹無風。若向湘江見，湘江徹底空。"]'),
('yuding-63','寄謝觀','劉得仁','唐','御定全唐诗','yuding','','[]','十五年餘苦，今朝始遇君。無慚于白日，不枉別孤雲。',48,'御定全唐詩/json/544.json','["十五年餘苦，今朝始遇君。無慚于白日，不枉別孤雲。", "得失天難問，稱揚鬼亦聞。此恩銷鏤骨，吟坐葉紛紛。"]'),
('yuding-64','送鄂州崔大夫赴鎮','劉得仁','唐','御定全唐诗','yuding','','[]','廉問帝難人，朝廷輟重臣。入山初有雪，登路正無塵。',48,'御定全唐詩/json/544.json','["廉問帝難人，朝廷輟重臣。入山初有雪，登路正無塵。", "去國鳴騶緩，經雲住旆頻。千峰與萬木，清聽雨情新。"]'),
('yuding-65','送錢給事赴虢州','劉得仁','唐','御定全唐诗','yuding','','[]','帝心憂虢俗，暫輟掖垣臣。疲瘵初承制，鄉閭似得春。',48,'御定全唐詩/json/544.json','["帝心憂虢俗，暫輟掖垣臣。疲瘵初承制，鄉閭似得春。", "化成應有瑞，位重轉聞貧。用作鹽梅日，爭回臥轍人。"]'),
('yuding-66','送雍陶侍禦赴兗州裴尚書命','劉得仁','唐','御定全唐诗','yuding','','[]','綸閣知孤直，翻論北巷賢。且縻蓮幕裏，會致玉階前。',48,'御定全唐詩/json/544.json','["綸閣知孤直，翻論北巷賢。且縻蓮幕裏，會致玉階前。", "洙泗秋微動，龜蒙月正圓。元戎軍務息，清句待君聯。"]'),
('yuding-67','送新羅人歸本國','劉得仁','唐','御定全唐诗','yuding','','[]','雞林隔巨浸，一住一年行。日近國先曙，風吹海不平。',48,'御定全唐詩/json/544.json','["雞林隔巨浸，一住一年行。日近國先曙，風吹海不平。", "眼穿鄉井樹，頭白渺彌程。到彼星霜換，唐家語卻生。"]'),
('yuding-68','送車濤罷舉歸山','劉得仁','唐','御定全唐诗','yuding','','[]','朝是暮還非，人情冷暖移。浮生只如此，強進欲何為。',48,'御定全唐詩/json/544.json','["朝是暮還非，人情冷暖移。浮生只如此，強進欲何為。", "要路知無援，深山必遇師。憐君明此理，休去不遲疑。"]'),
('yuding-69','送王書記歸邠州','劉得仁','唐','御定全唐诗','yuding','','[]','陳琳輕一別，馬上意超然。來日行煩暑，歸時聽早蟬。',48,'御定全唐詩/json/544.json','["陳琳輕一別，馬上意超然。來日行煩暑，歸時聽早蟬。", "陰雲翳城郭，細雨紊山川。從事公劉地，元戎舊禮賢。"]'),
('yuding-70','送謝觀之劍南從事','劉得仁','唐','御定全唐诗','yuding','','[]','迢遞從知己，他人敢更言。離京雖未臘，到府已應暄。',48,'御定全唐詩/json/544.json','["迢遞從知己，他人敢更言。離京雖未臘，到府已應暄。", "飛急奔行雁，啼酸憶子猿。江山無限思，君擬共誰論。"]'),
('yuding-71','送顧非熊作尉盱眙','劉得仁','唐','御定全唐诗','yuding','','[]','一名兼一尉，未足是君伸。歷數為詩者，多來作諫臣。',48,'御定全唐詩/json/544.json','["一名兼一尉，未足是君伸。歷數為詩者，多來作諫臣。", "路翻平楚闊，草帶古淮新。天下雖雲大，同聲有幾人。"]'),
('yuding-72','送高湘及第後東歸覲叔','劉得仁','唐','御定全唐诗','yuding','','[]','此去幾般榮，登科鼎足名。無慚入南巷，高價聳東京。',48,'御定全唐詩/json/544.json','["此去幾般榮，登科鼎足名。無慚入南巷，高價聳東京。", "窗對嵩山碧，庭來洛水聲。門前桃李樹，一徑已陰成。"]'),
('yuding-73','送友人下第歸覲','劉得仁','唐','御定全唐诗','yuding','','[]','君此蔔行日，高堂應夢歸。莫將和氏淚，滴著老萊衣。',48,'御定全唐詩/json/544.json','["君此蔔行日，高堂應夢歸。莫將和氏淚，滴著老萊衣。", "岳雨連河細，田禽出麥飛。到家調膳後，吟苦落蟬暉。"]'),
('yuding-74','送友人下第歸揚州覲省','劉得仁','唐','御定全唐诗','yuding','','[]','新柳間花垂，東西京路岐。園林知自到，寢食計相思。',48,'御定全唐詩/json/544.json','["新柳間花垂，東西京路岐。園林知自到，寢食計相思。", "雨斷淮山出，帆揚楚樹移。晨昏心已泰，蟬發是回時。"]'),
('yuding-75','早行','劉得仁','唐','御定全唐诗','yuding','','[]','萬類半已動，此心甯自安。月沉平野盡，星隱曙空殘。',48,'御定全唐詩/json/544.json','["萬類半已動，此心甯自安。月沉平野盡，星隱曙空殘。", "馬渡橫流廣，人行湛露寒。還思猶夢者，不信早行難。"]'),
('yuding-76','通濟裏居酬盧肇見尋不遇','劉得仁','唐','御定全唐诗','yuding','','[]','衡門掩綠苔，樹下絕塵埃。偶赴高僧約，旋知長者來。',48,'御定全唐詩/json/544.json','["衡門掩綠苔，樹下絕塵埃。偶赴高僧約，旋知長者來。", "雲山堪眺望，車馬必裴回。問以何為待，慚無酒一杯。"]'),
('yuding-77','贈王尊師','劉得仁','唐','御定全唐诗','yuding','','[]','為道常日損，尊師修此心。掛肩黃布被，穿發白蒿簪。',48,'御定全唐詩/json/544.json','["為道常日損，尊師修此心。掛肩黃布被，穿發白蒿簪。", "符劄靈砂字，弦彈古素琴。囊中曾有藥，點土亦成金。"]'),
('yuding-78','冬夜與蔡校書宿無可上人院','劉得仁','唐','御定全唐诗','yuding','','[]','儒釋偶同宿，夜窗寒更清。忘機於世久，晤語到天明。',48,'御定全唐詩/json/544.json','["儒釋偶同宿，夜窗寒更清。忘機於世久，晤語到天明。", "月倒高松影，風旋一磬聲。真門猶是幻，不用覺浮生。"]'),
('yuding-79','冬日喜同志宿','劉得仁','唐','御定全唐诗','yuding','','[]','相逢話清夜，言實轉相知。共道名雖切，唯論命不疑。',48,'御定全唐詩/json/544.json','["相逢話清夜，言實轉相知。共道名雖切，唯論命不疑。", "吟身坐霜石，眠鳥握風枝。別憶天臺客，煙霞昔有期。"]'),
('yuding-80','逢呂上山人','劉得仁','唐','御定全唐诗','yuding','','[]','塵裏正愁老，相逢眼益明。從前枉多病，此後鮮疏名。',48,'御定全唐詩/json/544.json','["塵裏正愁老，相逢眼益明。從前枉多病，此後鮮疏名。", "古柏今收子，深山許事兄。長生如有分，願逐到蓬瀛。"]'),
('yuding-81','春暮對雨','劉得仁','唐','御定全唐诗','yuding','','[]','春暮雨微微，翻疑墜葉時。氣蒙楊柳重，寒勒牡丹遲。',48,'御定全唐詩/json/544.json','["春暮雨微微，翻疑墜葉時。氣蒙楊柳重，寒勒牡丹遲。", "未夕鳥先宿，望晴人有期。何當廓陰閉，新暑竹風吹。"]'),
('yuding-82','長信宮','劉得仁','唐','御定全唐诗','yuding','','[]','簟涼秋氣初，長信恨何如。拂黛月生指，解鬟雲滿梳。',48,'御定全唐詩/json/544.json','["簟涼秋氣初，長信恨何如。拂黛月生指，解鬟雲滿梳。", "一從悲畫扇，幾度泣前魚。坐聽南宮樂，清風搖翠裾。"]'),
('yuding-83','初夏題段郎中修竹裏南園','劉得仁','唐','御定全唐诗','yuding','','[]','高人遊息處，與此曲池連。密樹才春後，深山在目前。',48,'御定全唐詩/json/544.json','["高人遊息處，與此曲池連。密樹才春後，深山在目前。", "遠峰初絕雨，片石欲生煙。數有僧來宿，應緣靜好禪。"]'),
('yuding-84','題景玄禪師院','劉得仁','唐','御定全唐诗','yuding','','[]','古僧精進者，師複是誰流。道貴行無我，禪難說到頭。',48,'御定全唐詩/json/544.json','["古僧精進者，師複是誰流。道貴行無我，禪難說到頭。", "汲泉羸鶴立，擁褐老猿愁。曾住深山院，何如此院幽。"]'),
('yuding-85','夏日樊川別業即事','劉得仁','唐','御定全唐诗','yuding','','[]','無事稱無才，柴門亦罕開。脫巾吟永日，著屐步荒台。',48,'御定全唐詩/json/544.json','["無事稱無才，柴門亦罕開。脫巾吟永日，著屐步荒台。", "風卷微塵上，霆將暴雨來。終南雲漸合，咫尺失崔嵬。"]'),
('yuding-86','寄無可上人','劉得仁','唐','御定全唐诗','yuding','','[]','省學為詩日，宵吟每達晨。十年期是夢，一事未成身。',48,'御定全唐詩/json/544.json','["省學為詩日，宵吟每達晨。十年期是夢，一事未成身。", "枉別山中客，殊非世上人。今來已如此，須得桂榮新。"]'),
('yuding-87','和範校書贈造微上人','劉得仁','唐','御定全唐诗','yuding','','[]','得性見微公，何曾執著空。修心將佛並，吐論與儒通。',48,'御定全唐詩/json/544.json','["得性見微公，何曾執著空。修心將佛並，吐論與儒通。", "曉漱松杉下，宵禪雪月中。他生有緣會，君子亦應同。"]'),
('yuding-88','訪曲江胡處士','劉得仁','唐','御定全唐诗','yuding','','[]','何況歸山后，而今已似仙。卜居天苑畔，閒步禁樓前。',48,'御定全唐詩/json/544.json','["何況歸山后，而今已似仙。卜居天苑畔，閒步禁樓前。", "落日明沙岸，微風上紙鳶。靜還林石下，坐讀養生篇。"]'),
('yuding-89','慈恩寺塔下避暑','劉得仁','唐','御定全唐诗','yuding','','[]','古松淩巨塔，修竹映空廊。竟日聞虛籟，深山只此涼。',48,'御定全唐詩/json/544.json','["古松淩巨塔，修竹映空廊。竟日聞虛籟，深山只此涼。", "僧真生我靜，水淡發茶香。坐久東樓望，鐘聲振夕陽。"]'),
('yuding-90','秋晚與友人游青龍寺','劉得仁','唐','御定全唐诗','yuding','','[]','高視終南秀，西風度閣涼。一生同隙影，幾處好山光。',48,'御定全唐詩/json/544.json','["高視終南秀，西風度閣涼。一生同隙影，幾處好山光。", "暮鳥投嬴木，寒鐘送夕陽。因居話心地，川冥宿僧房。"]'),
('yuding-91','春日雨後作','劉得仁','唐','御定全唐诗','yuding','','[]','朝來微有雨，天地爽無塵。北闕明如畫，南山碧動人。',48,'御定全唐詩/json/544.json','["朝來微有雨，天地爽無塵。北闕明如畫，南山碧動人。", "車輿終日別，草樹一城新。枉是吾君戚，何門謁紫宸。"]'),
('yuding-92','別王山人','劉得仁','唐','御定全唐诗','yuding','','[]','旨甘雖自足，未是祿榮親。尚逐趨時伴，多離有道人。',48,'御定全唐詩/json/544.json','["旨甘雖自足，未是祿榮親。尚逐趨時伴，多離有道人。", "山居衣以草，生寄藥隨身。不食長無疾，年知出十旬。"]'),
('yuding-93','贈陶山人','劉得仁','唐','御定全唐诗','yuding','','[]','處士例營營，惟君縱此生。閑能資壽考，健不換公卿。',48,'御定全唐詩/json/544.json','["處士例營營，惟君縱此生。閑能資壽考，健不換公卿。", "藥圃妻同耨，山田子共耕。定知丹熟後，無姓亦無名。"]'),
('yuding-0','禁署早春晴望','劉得仁','唐','御定全唐诗','yuding','','[]','禦林聞有早鶯聲，玉檻春香九陌晴。寒著霽雲歸紫閣，',40,'御定全唐詩/json/545.json','["禦林聞有早鶯聲，玉檻春香九陌晴。寒著霽雲歸紫閣，", "鴛侶此時皆賦詠，商山雪在思尤清。"]'),
('yuding-1','山中尋道人不遇','劉得仁','唐','御定全唐诗','yuding','','[]','年過弱冠風塵裏，常擬隨師學煉形。石路特來尋道者，',40,'御定全唐詩/json/545.json','["年過弱冠風塵裏，常擬隨師學煉形。石路特來尋道者，", "便欲此居閑到老，先生何日下青冥。"]'),
('yuding-2','贈敬晊助教二首','劉得仁','唐','御定全唐诗','yuding','','[]','到來常聽說清虛，手把玄元七字書。仙籍不知名姓有，',80,'御定全唐詩/json/545.json','["到來常聽說清虛，手把玄元七字書。仙籍不知名姓有，", "便欲去隨為弟子，片雲孤鶴可相於。", "街西靜觀求居處，不到權門到寺頻。禁掖人知連狀薦，", "自顧無成年漸長，報恩惟願殺微身。"]'),
('yuding-3','送祖山人歸山','劉得仁','唐','御定全唐诗','yuding','','[]','獨來朝市笑浮雲，卻憶煙霞出帝城。不說金丹能點化，',40,'御定全唐詩/json/545.json','["獨來朝市笑浮雲，卻憶煙霞出帝城。不說金丹能點化，", "料得仙家玉牌上，已鐫白日上升名。"]'),
('yuding-4','監試蓮花峰','劉得仁','唐','御定全唐诗','yuding','','[]','太華萬餘重，岧嶢只此峰。當秋倚寥泬，入望似芙蓉。',72,'御定全唐詩/json/545.json','["太華萬餘重，岧嶢只此峰。當秋倚寥泬，入望似芙蓉。", "翠拔千尋直，青危一朵穠。氣分毛女秀，靈有羽人蹤。", "倒影侵官路，流香激廟松。塵埃終不及，車馬自憧憧。"]'),
('yuding-5','京兆府試目極千里','劉得仁','唐','御定全唐诗','yuding','','[]','獻賦多年客，低眉恨不前。此心常鬱矣，縱目忽超然。',72,'御定全唐詩/json/545.json','["獻賦多年客，低眉恨不前。此心常鬱矣，縱目忽超然。", "送驥登長路，看鴻入遠天。古墟煙冪冪，窮野草綿綿。", "樹與金城接，山疑桂水連。何當開霽日，無物翳平川。"]'),
('yuding-6','尋陳處士山堂','劉得仁','唐','御定全唐诗','yuding','','[]','步溪凡幾轉，始得見幽蹤。路隱千根樹，門開萬仞峰。',96,'御定全唐詩/json/545.json','["步溪凡幾轉，始得見幽蹤。路隱千根樹，門開萬仞峰。", "片雲生石竇，淺水臥枯松。窮谷風光冷，深山翠碧濃。", "鶴看空裏過，仙向坐中逢。底露秋潭水，聲微暮觀鐘。", "他年來此定，異日願相容。且喜今歸去，人間事更慵。"]'),
('yuding-7','題從伯舍人道正裏南園','劉得仁','唐','御定全唐诗','yuding','','[]','帝裏餘新第，朱門面碧岑。曙堂增爽氣，喬木動清陰。',120,'御定全唐詩/json/545.json','["帝裏餘新第，朱門面碧岑。曙堂增爽氣，喬木動清陰。", "直去親瑤陛，朝回在竹林。風流才子調，好尚古人心。", "薜荔遮窗暗，莓苔近井深。禮無青草隔，詩共白衣吟。", "軒靜留孤鶴，庭虛到遠砧。掩關裁鳳詔，開鏡理瓊簪。", "種植今如此，塵埃永不侵。雲奔投刺者，日日待為霖。"]'),
('yuding-8','賦得聽松聲','劉得仁','唐','御定全唐诗','yuding','','[]','庭際微風動，高松韻自生。聽時無物亂，盡日覺神清。',72,'御定全唐詩/json/545.json','["庭際微風動，高松韻自生。聽時無物亂，盡日覺神清。", "強與幽泉並，翻嫌細雨並。拂空增鶴唳，過牖合琴聲。", "況複當秋暮，偏宜在月明。不知深澗底，蕭瑟有誰聽。"]'),
('yuding-9','宿普濟寺','劉得仁','唐','御定全唐诗','yuding','','[]','京寺數何窮，清幽此不同。曲江臨閣北，御苑自牆東。',120,'御定全唐詩/json/545.json','["京寺數何窮，清幽此不同。曲江臨閣北，御苑自牆東。", "廣陌車音急，危樓夕景通。亂峰沉暝野，毒暑過秋空。", "幡颺虛無裏，星生杳靄中。月光籠月殿，蓮氣入蓮宮。", "綴草涼天露，吹人古木風。飲茶除假寐，聞磬釋塵蒙。", "童子眠苔淨，高僧話漏終。待鳴曉鐘後，萬井複朣朧。"]'),
('yuding-10','和鄭校書夏日游鄭泉','劉得仁','唐','御定全唐诗','yuding','','[]','太虛懸畏景，古木蔽清陰。爰有泉堪挹，閑思日可尋。',120,'御定全唐詩/json/545.json','["太虛懸畏景，古木蔽清陰。爰有泉堪挹，閑思日可尋。", "來聞鳴滴滴，照竦碧沉沉。幾脈成溪壑，何人測淺深。", "澄時無一物，分處曆千林。淨溉靈根藥，涼浮玉翅禽。", "飲疑蠲宿疾，見自失煩襟。僧共雲前瀨，龍和月下吟。", "疊光輕吹動，徹底曉霞侵。不用頻遊去，令君少進心。"]'),
('yuding-11','和段校書冬夕寄題廬山','劉得仁','唐','御定全唐诗','yuding','','[]','名高身未到，此恨蓄多時。是夕吟因話，他年必去隨。',240,'御定全唐詩/json/545.json','["名高身未到，此恨蓄多時。是夕吟因話，他年必去隨。", "嘗聞廬嶽頂，半入楚江湄。幾處懸崖上，千尋瀑布垂。", "爐峰松淅瀝，湓浦柳參差。日色連湖白，鐘聲拂浪遲。", "煙梯緣薜荔，岳寺步欹危。地本饒靈草，林曾出祖師。", "石樓霞耀壁，猿樹鶴分枝。細徑縈岩末，高窗見海涯。", "嵌空寒更極，寂寞夜尤思。陰穀冰埋術，仙田雪覆芝。", "亂泉禪客瀨，異跡逸人知。蘚室新開灶，檉潭未了棋。", "如何遂閑放，長得在希夷。空務漁樵事，方無道路悲。", "謝公台尚在，陶令柳潛衰。塵外難相許，人間貴跡遺。", "雖懷丹桂影，不忘白雲期。仁者終攜手，今朝預賦詩。"]'),
('yuding-12','書事寄萬年厲員外','劉得仁','唐','御定全唐诗','yuding','','[]','帝城皆劇縣，令尹美居東。遂拜趙張下，暫離星象中。',168,'御定全唐詩/json/545.json','["帝城皆劇縣，令尹美居東。遂拜趙張下，暫離星象中。", "擁歸從北闕，送上動南宮。紫禁黃山繞，滄溟素滻通。", "封疆親日月，邑裏出王公。賦稅充天府，歌謠入聖聰。", "土膏寒麥覆，人海晝塵蒙。廨宇松連翠，朝街火散紅。", "文場新桂茂，粉署舊蘭崇。留客揮盈爵，抽毫詠早鴻。", "前騶潘嶽貴，故里邵平窮。勸隱蓮峰久，期耕樹穀同。", "鳧飛將去葉，劍氣尚埋豐。何必華陰土，方垂拂拭功。"]'),
('yuding-13','上姚諫議','劉得仁','唐','御定全唐诗','yuding','','[]','高文與盛德，皆謂古無倫。聖代生才子，明庭有諫臣。',96,'御定全唐詩/json/545.json','["高文與盛德，皆謂古無倫。聖代生才子，明庭有諫臣。", "已瞻龍袞近，漸向鳳池新。卻憶波濤郡，來時島嶼春。", "名因詩句大，家似布衣貧。曾暗投新軸，頻聞獎滯身。", "照吟清夕月，送藥紫霞人。終計依門館，何疑不化鱗。"]'),
('yuding-14','上翰林丁學士','劉得仁','唐','御定全唐诗','yuding','','[]','今代如堯代，征賢察眾情。久聆推行實，然後佐聰明。',120,'御定全唐詩/json/545.json','["今代如堯代，征賢察眾情。久聆推行實，然後佐聰明。", "官自文華重，恩因顧問生。詞人求作稱，天子許和羹。", "禦柳凋霜晚，宮泉滴月清。直廬寒漏近，秋燭白麻成。", "玉殿移時對，金輿數侍行。賜衣香未散，借馬色難名。", "時輩何偏羨，儒流此最榮。終當聞燮理，寰宇永升平。"]'),
('yuding-15','二','劉得仁','唐','御定全唐诗','yuding','','[]','何處訪岐路，青雲但憶歸。風塵數年限，門館一生依。',48,'御定全唐詩/json/545.json','["何處訪岐路，青雲但憶歸。風塵數年限，門館一生依。", "外族帝王是，中朝親舊稀。翻令浮議者，不許九霄飛。"]'),
('yuding-16','山中舒懷寄上丁學士','劉得仁','唐','御定全唐诗','yuding','','[]','五字投精鑒，慚非大雅詞。本求閑賜覽，豈料便蒙知。',72,'御定全唐詩/json/545.json','["五字投精鑒，慚非大雅詞。本求閑賜覽，豈料便蒙知。", "幽拙欣殊幸，提攜更不疑。弱苗須雨長，懶翼在風吹。", "礪鏃端楊葉，光門待桂枝。計聞塵裏譽，因和禁中詩。"]'),
('yuding-17','鶯出谷','劉得仁','唐','御定全唐诗','yuding','','[]','東風潛啟物，動息意皆新。此鳥從幽谷，依林報早春。',72,'御定全唐詩/json/545.json','["東風潛啟物，動息意皆新。此鳥從幽谷，依林報早春。", "出寒雖未及，振羽漸能頻。稍類沖天鶴，多隨折桂人。", "尊前喧有語，花裏晝藏身。若向穠華處，餘禽不見親。"]'),
('yuding-18','哭翰林丁侍郎','劉得仁','唐','御定全唐诗','yuding','','[]','相知出肺腑，非舊亦非親。每見雲霄侶，多揚鄙拙身。',96,'御定全唐詩/json/545.json','["相知出肺腑，非舊亦非親。每見雲霄侶，多揚鄙拙身。", "即期扶泰運，豈料哭賢人。應是隨先帝，依前作近臣。", "平生任公直，愛弟尚風塵。宅閉青松古，墳臨赤水新。", "官清仍齒壯，兒小複家貧。惆悵天難問，空流淚滿巾。"]'),
('yuding-19','陳情上李景讓大夫','劉得仁','唐','御定全唐诗','yuding','','[]','一被浮名誤，旋遭白髮侵。裴回戀明主，夢寐在秋岑。',168,'御定全唐詩/json/545.json','["一被浮名誤，旋遭白髮侵。裴回戀明主，夢寐在秋岑。", "遇物唯多感，居常只是吟。待時鉗定口，經事壓低心。", "辛苦文場久，因緣戚裏深。老迷新道路，貧賣舊園林。", "晴賞行聞水，宵棋坐見參。龜留閑去問，僧約偶來尋。", "望喜潛憑鵲，娛情願有琴。此生如遂意，誓死報知音。", "上德憐孤直，唯公拔陸沉。丘山恩忽被，螻蟻力難任。", "作鑒明同日，聽言重若金。從茲更無限，翹足俟為霖。"]'),
('yuding-20','和鄭先輩謝秩閒居寓書所懷','劉得仁','唐','御定全唐诗','yuding','','[]','西風日夜吹，萬木共離披。近甸新晴後，高人得意時。',120,'御定全唐詩/json/545.json','["西風日夜吹，萬木共離披。近甸新晴後，高人得意時。", "暫閒心亦泰，論道面難欺。把筆還詩債，將琴當酒資。", "藍衫懸竹桁，烏帽掛松枝。名占文章重，官歸諫憲遲。", "生涯貧帝裏，公議到台司。室冷沾苔蘚，門清絕路岐。", "莫言鄰白屋，即賀立丹墀。豈慮塵埃久，雲霄故有期。"]'),
('yuding-21','病中晨起即事寄場中往還','劉得仁','唐','御定全唐诗','yuding','','[]','昨日離塵裏，今朝懶已成。豈能為久隱，更欲泥浮名。',96,'御定全唐詩/json/545.json','["昨日離塵裏，今朝懶已成。豈能為久隱，更欲泥浮名。", "虛牖晨光白，幽園曉氣清。戴沙尋水去，披霧入林行。", "疊葉孤禽在，初陽半樹明。桑麻新雨潤，蘆荻古波聲。", "易向田家熟，元于世路生。病多三徑塞，吟苦四鄰驚。"]'),
('yuding-22','悲老宮人','劉得仁','唐','御定全唐诗','yuding','','[]','白髮宮娃不解悲，滿頭猶自插花枝。',32,'御定全唐詩/json/545.json','["白髮宮娃不解悲，滿頭猶自插花枝。", "曾緣玉貌君王寵，准擬人看似舊時。"]'),
('yuding-23','村中閒步','劉得仁','唐','御定全唐诗','yuding','','[]','閑共野人臨野水，新秋高樹掛清暉。',32,'御定全唐詩/json/545.json','["閑共野人臨野水，新秋高樹掛清暉。", "不知塵裏無窮事，白鳥雙飛入翠微。"]'),
('yuding-24','上巳日','劉得仁','唐','御定全唐诗','yuding','','[]','未敢分明賞物華，十年如見夢中花。',32,'御定全唐詩/json/545.json','["未敢分明賞物華，十年如見夢中花。", "遊人過盡衡門掩，獨自憑欄到日斜。"]'),
('yuding-25','省試日上崔侍郎四首','劉得仁','唐','御定全唐诗','yuding','','[]','衣上年年淚血痕，只將懷抱訴乾坤。',128,'御定全唐詩/json/545.json','["衣上年年淚血痕，只將懷抱訴乾坤。", "如今主聖臣賢日，豈致人間一物冤。", "如病如癡二十秋，求名難得又難休。", "回看骨肉須堪恥，一著麻衣便白頭。", "戚裏稱儒愧小才，禮闈公道此時開。", "他人何事虛相指，明主無私不是媒。", "方寸終朝似火然，為求白日上青天。", "自嗟辜負平生眼，不識春光二十年。"]'),
('yuding-26','秋夜','劉得仁','唐','御定全唐诗','yuding','','[]','秋氣滿堂孤燭冷，清宵無寐憶山歸。',32,'御定全唐詩/json/545.json','["秋氣滿堂孤燭冷，清宵無寐憶山歸。", "窗前月過三更後，細竹吟風似雨微。"]'),
('yuding-27','長門怨','劉得仁','唐','御定全唐诗','yuding','','[]','爭得一人聞此怨，長門深夜有妍姝。',32,'御定全唐詩/json/545.json','["爭得一人聞此怨，長門深夜有妍姝。", "早知雨露翻相誤，只插荊釵嫁匹夫。"]'),
('yuding-28','賈婦怨','劉得仁','唐','御定全唐诗','yuding','','[]','嫁與商人頭欲白，未曾一日得雙行。',32,'御定全唐詩/json/545.json','["嫁與商人頭欲白，未曾一日得雙行。", "任君逐利輕江海，莫把風濤似妾輕。"]'),
('yuding-29','寄友人','劉得仁','唐','御定全唐诗','yuding','','[]','風颯沉思眼忽開，塵埃汙得是庸才。',32,'御定全唐詩/json/545.json','["風颯沉思眼忽開，塵埃汙得是庸才。", "那堪更見巢松鶴，飛入青雲不下來。"]'),
('yuding-30','晏起','劉得仁','唐','御定全唐诗','yuding','','[]','日過辰時猶在夢，客來應笑也求名。',32,'御定全唐詩/json/545.json','["日過辰時猶在夢，客來應笑也求名。", "浮生自得長高枕，不向人間與命爭。"]'),
('yuding-31','馬上別單于劉評事','劉得仁','唐','御定全唐诗','yuding','','[]','廟謀宏遠人難測，公主生還帝感深。',32,'御定全唐詩/json/545.json','["廟謀宏遠人難測，公主生還帝感深。", "天下底平須共喜，一時閒事莫驚心。"]'),
('yuding-32','贈從弟谷','劉得仁','唐','御定全唐诗','yuding','','[]','此世榮枯豈足驚，相逢惟要眼長青。',32,'御定全唐詩/json/545.json','["此世榮枯豈足驚，相逢惟要眼長青。", "從來不愛三閭死，今日憑君莫獨醒。"]'),
('yuding-33','別山居','劉得仁','唐','御定全唐诗','yuding','','[]','萬壑千岩景象開，登臨未足又須回。',32,'御定全唐詩/json/545.json','["萬壑千岩景象開，登臨未足又須回。", "憑師莫斷松間路，秋月圓時弟子來。"]'),
('yuding-34','贈道人','劉得仁','唐','御定全唐诗','yuding','','[]','長在城中無定業，賣丹磨鏡兩途貧。',32,'御定全唐詩/json/545.json','["長在城中無定業，賣丹磨鏡兩途貧。", "三山來往尋常事，不省曾驚市井人。"]'),
('yuding-35','對月寄同志','劉得仁','唐','御定全唐诗','yuding','','[]','霜滿中庭月在林，塞鴻頻過又更深。',32,'御定全唐詩/json/545.json','["霜滿中庭月在林，塞鴻頻過又更深。", "支頤不語相思坐，料得君心似我心。"]'),
('yuding-36','憶鶴','劉得仁','唐','御定全唐诗','yuding','','[]','白絲翎羽丹砂頂，曉度秋煙出翠微。',32,'御定全唐詩/json/545.json','["白絲翎羽丹砂頂，曉度秋煙出翠微。", "來向孤松枝上立，見人吟苦卻高飛。"]'),
('yuding-37','雲門寺','劉得仁','唐','御定全唐诗','yuding','','[]','上方僧又起，清磬出林初。吟苦曉燈暗，露零秋草疏。',48,'御定全唐詩/json/545.json','["上方僧又起，清磬出林初。吟苦曉燈暗，露零秋草疏。", "舊山多夢到，流水送愁餘。寄寺欲經歲，慚無親故書。"]'),
('yuding-38','中秋宿鄧逸人居','劉得仁','唐','御定全唐诗','yuding','','[]','偶與山僧宿，吟詩坐到明。夜涼耽月色，秋渴漱泉聲。',48,'御定全唐詩/json/545.json','["偶與山僧宿，吟詩坐到明。夜涼耽月色，秋渴漱泉聲。", "澗木如竿聳，窗雲作片生。白衣閑自貴，不揖漢公卿。"]'),
('yuding-39','句','劉得仁','唐','御定全唐诗','yuding','','[]','外家雖是帝，當路且無親。',76,'御定全唐詩/json/545.json','["外家雖是帝，當路且無親。", "白日只如哭，黃泉免恨無。", "身閑甘旨下，白髮太平人。", "同遊芳草寺，見示白雲詩。", "猶祈啟金口，一為動文權。", "深山寺路千層石，竹杖棕鞋便可登。"]'),
('yuding-0','題山院','權審','唐','御定全唐诗','yuding','','[]','萬葉風聲利，一山秋氣寒。曉霜浮碧瓦，落日度朱欄。',24,'御定全唐詩/json/546.json','["萬葉風聲利，一山秋氣寒。曉霜浮碧瓦，落日度朱欄。"]'),
('yuding-1','絕句','權審','唐','御定全唐诗','yuding','','[]','得即高歌失即休，多悲多恨謾悠悠。',32,'御定全唐詩/json/546.json','["得即高歌失即休，多悲多恨謾悠悠。", "今朝有酒今朝醉，明日愁來明日愁。"]'),
('yuding-2','郡中有懷寄上睦州員外杜十三兄','邢群','唐','御定全唐诗','yuding','','[]','城枕溪流更淺斜，麗譙連帶邑人家。經冬野菜青青色，',40,'御定全唐詩/json/546.json','["城枕溪流更淺斜，麗譙連帶邑人家。經冬野菜青青色，", "如今歲晏從羈滯，心喜彈冠事不賒。"]'),
('yuding-3','早發靈芝望九華寄杜員外使君','曹汾','唐','御定全唐诗','yuding','','[]','戴月早辭三秀館，遲明初識九華峰。嵯嵯玉劍寒鋩利，',40,'御定全唐詩/json/546.json','["戴月早辭三秀館，遲明初識九華峰。嵯嵯玉劍寒鋩利，", "行春若到五溪上，此處褰帷正面逢。"]'),
('yuding-4','落花','嚴惲','唐','御定全唐诗','yuding','','[]','春光冉冉歸何處，更向花前把一杯。',32,'御定全唐詩/json/546.json','["春光冉冉歸何處，更向花前把一杯。", "盡日問花花不語，為誰零落為誰開。"]'),
('yuding-5','題籌筆驛','殷潛之','唐','御定全唐诗','yuding','','[]','江東矜割據，鄴下奪孤嫠。霸略非匡漢，宏圖欲佐誰。',168,'御定全唐詩/json/546.json','["江東矜割據，鄴下奪孤嫠。霸略非匡漢，宏圖欲佐誰。", "奏書辭後主，仗劍出全師。重襲褒斜路，懸開反正旗。", "欲將苞有截，必使舉無遺。沈慮經謀際，揮毫決勝時。", "圜觚當分畫，前箸此操持。山秀扶英氣，川流入妙思。", "算成功在彀，運去事終虧。命屈天方厭，人亡國自隨。", "艱難推舊姓，開創極初基。總歎曾過地，寧探作教資。", "若歸新歷數，誰複顧衰危。報德兼明道，長留識者知。"]'),
('yuding-6','送高遂赴舉','祝元膺','唐','御定全唐诗','yuding','','[]','句曲舊宅真，自產日月英。既涵岳瀆氣，安無神仙名。',36,'御定全唐詩/json/546.json','["句曲舊宅真，自產日月英。既涵岳瀆氣，安無神仙名。", "松桂邐迤色，與君相送情。"]'),
('yuding-7','寄道友','祝元膺','唐','御定全唐诗','yuding','','[]','兩頷凝清霜，玉爐焚天香。為我延歲華，得入不死鄉。',24,'御定全唐詩/json/546.json','["兩頷凝清霜，玉爐焚天香。為我延歲華，得入不死鄉。"]'),
('yuding-8','夢仙謠','祝元膺','唐','御定全唐诗','yuding','','[]','蟾蜍夜作青冥燭，螮蝀晴為碧落梯。',32,'御定全唐詩/json/546.json','["蟾蜍夜作青冥燭，螮蝀晴為碧落梯。", "好個分明天上路，誰教深入武陵溪。"]'),
('yuding-9','句','祝元膺','唐','御定全唐诗','yuding','','[]','霧紋斑似豹，水力健如龍。',12,'御定全唐詩/json/546.json','["霧紋斑似豹，水力健如龍。"]'),
('yuding-10','賀鄧璠使君正拜袁州','彭蟾','唐','御定全唐诗','yuding','','[]','六年惠愛及黎甿，大府論功俟陟明。尺一詔書天上降，',40,'御定全唐詩/json/546.json','["六年惠愛及黎甿，大府論功俟陟明。尺一詔書天上降，", "更待皇恩醒善政，碧油幢到郡齋迎。"]'),
('yuding-11','和嚴惲落花詩','王樞','唐','御定全唐诗','yuding','','[]','花落花開人世夢，衰榮閒事且持杯。',32,'御定全唐詩/json/546.json','["花落花開人世夢，衰榮閒事且持杯。", "春風底事輕搖落，何似從來不要開。"]'),
('yuding-12','詠宣律和尚袈裟','張希複','唐','御定全唐诗','yuding','','[]','共覆三衣中夜寒，披時不鎮尼師壇。',32,'御定全唐詩/json/546.json','["共覆三衣中夜寒，披時不鎮尼師壇。", "無因蓋得龍宮地，畦裏塵飛葉相殘。"]'),
('yuding-13','鶯出谷','錢可複','唐','御定全唐诗','yuding','','[]','玉律陽和變，時禽羽翮新。載飛初出穀，一囀已驚人。',72,'御定全唐詩/json/546.json','["玉律陽和變，時禽羽翮新。載飛初出穀，一囀已驚人。", "拂柳宜煙暖，沖花覺露春。摶風翻翰疾，向日弄吭頻。", "求友心何切，遷喬幸有因。華林高玉樹，棲托及芳晨。"]'),
('yuding-14','鶯出谷','張鷺','唐','御定全唐诗','yuding','','[]','弱柳隨儔匹，遷鶯正及春。乘風音響遠，映日羽毛新。',72,'御定全唐詩/json/546.json','["弱柳隨儔匹，遷鶯正及春。乘風音響遠，映日羽毛新。", "已得辭幽谷，還將脫俗塵。鴛鸞方可慕，燕雀迥無鄰。", "游止知難屈，翻飛在此伸。一枝如借便，終冀托深仁。"]'),
('yuding-15','鶯出谷','劉莊物','唐','御定全唐诗','yuding','','[]','幸因辭舊穀，從此及芳晨。欲語如調舌，初飛似畏人。',72,'御定全唐詩/json/546.json','["幸因辭舊穀，從此及芳晨。欲語如調舌，初飛似畏人。", "風調歸影便，日暖吐聲頻。翔集知無阻，聯綿貴有因。", "喜遷喬木近，寧厭對花新。堪念微禽意，關關也愛春。"]'),
('yuding-0','題呂食新水閣兼寄南商州郎中','朱景玄','唐','御定全唐诗','yuding','','[]','丹檻初結構，孤高冠清川。庭臨穀中樹，簷落山上泉。',48,'御定全唐詩/json/547.json','["丹檻初結構，孤高冠清川。庭臨穀中樹，簷落山上泉。", "曉色掛殘月，夜聲雜繁弦。青春去如水，康樂歸何年。"]'),
('yuding-1','華山南望春','朱景玄','唐','御定全唐诗','yuding','','[]','靈嶽多異狀，巉巉出虛空。閑雲戀岩壑，起滅蒼翠中。',72,'御定全唐詩/json/547.json','["靈嶽多異狀，巉巉出虛空。閑雲戀岩壑，起滅蒼翠中。", "皓氣澄野水，神光秘瓊宮。鶴巢前林雪，瀑落滿澗風。", "春盡花未發，川回路難窮。何因著山屐，鹿跡尋羊公。"]'),
('yuding-2','水閣','朱景玄','唐','御定全唐诗','yuding','','[]','樓居半池上，澄影共相空。謝守題詩處，蓮開淨碧中。',24,'御定全唐詩/json/547.json','["樓居半池上，澄影共相空。謝守題詩處，蓮開淨碧中。"]'),
('yuding-3','迎風亭','朱景玄','唐','御定全唐诗','yuding','','[]','山雨留清氣，溪飆送早涼。時回石門步，階下碧雲光。',24,'御定全唐詩/json/547.json','["山雨留清氣，溪飆送早涼。時回石門步，階下碧雲光。"]'),
('yuding-4','雙櫧亭','朱景玄','唐','御定全唐诗','yuding','','[]','連簷對雙樹，冬翠夏無塵。未肯慚桃李，成陰不待春。',24,'御定全唐詩/json/547.json','["連簷對雙樹，冬翠夏無塵。未肯慚桃李，成陰不待春。"]'),
('yuding-5','蓮亭','朱景玄','唐','御定全唐诗','yuding','','[]','回塘最幽處，拍水小亭開。莫怪闌幹濕，鵁鶄夜宿來。',24,'御定全唐詩/json/547.json','["回塘最幽處，拍水小亭開。莫怪闌幹濕，鵁鶄夜宿來。"]'),
('yuding-6','中峰亭','朱景玄','唐','御定全唐诗','yuding','','[]','中峰上翠微，窗曉早霞飛。幾引登山屐，春風踏雪歸。',24,'御定全唐詩/json/547.json','["中峰上翠微，窗曉早霞飛。幾引登山屐，春風踏雪歸。"]'),
('yuding-7','飛雲亭','朱景玄','唐','御定全唐诗','yuding','','[]','上結孤圓頂，飛軒出泰清。有時迷處所，梁棟曉雲生。',24,'御定全唐詩/json/547.json','["上結孤圓頂，飛軒出泰清。有時迷處所，梁棟曉雲生。"]'),
('yuding-8','四望亭','朱景玄','唐','御定全唐诗','yuding','','[]','高亭群峰首，四面俯晴川。每見晨光曉，階前萬井煙。',24,'御定全唐詩/json/547.json','["高亭群峰首，四面俯晴川。每見晨光曉，階前萬井煙。"]'),
('yuding-9','望蓮台','朱景玄','唐','御定全唐诗','yuding','','[]','秋台好登望，菡萏發清池。半似紅顏醉，淩波欲暮時。',24,'御定全唐詩/json/547.json','["秋台好登望，菡萏發清池。半似紅顏醉，淩波欲暮時。"]'),
('yuding-10','茶亭','朱景玄','唐','御定全唐诗','yuding','','[]','靜得塵埃外，茶芳小華山。此亭真寂寞，世路少人閑。',24,'御定全唐詩/json/547.json','["靜得塵埃外，茶芳小華山。此亭真寂寞，世路少人閑。"]'),
('yuding-11','宿新安村步','朱景玄','唐','御定全唐诗','yuding','','[]','淅淅寒流漲淺沙，月明空渚遍蘆花。',32,'御定全唐詩/json/547.json','["淅淅寒流漲淺沙，月明空渚遍蘆花。", "離人偶宿孤村下，永夜聞砧一兩家。"]'),
('yuding-12','遠聞本郡行春到舊山二首','朱景玄','唐','御定全唐诗','yuding','','[]','一身從宦留京邑，五馬遙聞到舊山。',64,'御定全唐詩/json/547.json','["一身從宦留京邑，五馬遙聞到舊山。", "已領煙霞光野徑，深慚老幼候柴關。", "清風借響松筠外，畫隼停暉水石間。", "定掩溪名在圖傳，共知軒蓋此登攀。"]'),
('yuding-13','和崔使君臨發不得觀積雪','朱景玄','唐','御定全唐诗','yuding','','[]','貧居稍與池塘近，旬日軒車不降來。',32,'御定全唐詩/json/547.json','["貧居稍與池塘近，旬日軒車不降來。", "一樹瓊花空有待，曉風看落滿青苔。"]'),
('yuding-14','句','朱景玄','唐','御定全唐诗','yuding','','[]','塞鴻先秋去，邊草入夏生。',12,'御定全唐詩/json/547.json','["塞鴻先秋去，邊草入夏生。"]'),
('yuding-15','別青州妓段東美','薛宜僚','唐','御定全唐诗','yuding','','[]','經年郵驛許安棲，一會他鄉別恨迷。',64,'御定全唐詩/json/547.json','["經年郵驛許安棲，一會他鄉別恨迷。", "今日海帆飄萬里，不堪腸斷對含啼。", "阿母桃花方似錦，王孫草色正如煙。", "不須更向滄溟望，惆悵歡情恰一年。"]'),
('yuding-16','詠韋皋','郭圓','唐','御定全唐诗','yuding','','[]','宣父從周又適秦，昔賢誰少出風塵。',32,'御定全唐詩/json/547.json','["宣父從周又適秦，昔賢誰少出風塵。", "當時甚訝張延賞，不識韋皋是貴人。"]'),
('yuding-17','進宣宗收復河湟詩','崔鉉','唐','御定全唐诗','yuding','','[]','邊陲萬里注恩波，宇宙群芳洽凱歌。右地名王爭解辮，',40,'御定全唐詩/json/547.json','["邊陲萬里注恩波，宇宙群芳洽凱歌。右地名王爭解辮，", "共遇聖明千載運，更觀俗阜與時和。"]'),
('yuding-18','詠架上鷹','崔鉉','唐','御定全唐诗','yuding','','[]','天邊心膽架頭身，欲擬飛騰未有因。',32,'御定全唐詩/json/547.json','["天邊心膽架頭身，欲擬飛騰未有因。", "萬里碧霄終一去，不知誰是解絛人。"]'),
('yuding-19','越亭二十韻','元晦','唐','御定全唐诗','yuding','','[]','乏才叨八使，徇祿非三顧。南服頒詔條，東林證迷誤。',240,'御定全唐詩/json/547.json','["乏才叨八使，徇祿非三顧。南服頒詔條，東林證迷誤。", "未聞述職效，偶脫囂煩趣。激水浚坳塘，緣崖欹磴步。", "西岩煥朝旭，深壑囊宿霧。影氣爽衣巾，涼颸輕杖履。", "臨高神慮寂，遠眺川原布。孤帆逗汀煙，翻鴉集江樹。", "獨探洞府靜，恍若偓佺遇。一瞬契真宗，百年成妄故。", "孱顏石戶啟，杳靄溪雲度。松籟韻宮商，鴛甍勢翔溯。", "津梁危彴架，濟物虛舟渡。環流馳羽觴，金英妒妝嫭。", "笳吟寒壘迥，鳥噪空山暮。悵望麋鹿心，低回車馬路。", "懸冠謝陶令，褫佩懷疏傅。遐想蛻纓緌，徒慚恤襦袴。", "福盈禍之倚，權勝道所惡。何必棲禪關，無言自冥悟。"]'),
('yuding-20','除浙東留題桂郡林亭','元晦','唐','御定全唐诗','yuding','','[]','紫泥遠自金鑾降，朱旆翻馳鏡水頭。陶令風光偏畏夜，',40,'御定全唐詩/json/547.json','["紫泥遠自金鑾降，朱旆翻馳鏡水頭。陶令風光偏畏夜，", "莫遣豔歌催客醉，不堪回首翠蛾愁。"]'),
('yuding-21','句','元晦','唐','御定全唐诗','yuding','','[]','石靜如開鏡，山高若聳蓮。筍竿抽玉管，花蔓綴金鈿。',25,'御定全唐詩/json/547.json','["石靜如開鏡，山高若聳蓮。筍竿抽玉管，花蔓綴金鈿。", "。"]'),
('yuding-22','和元常侍除浙東留題','路貫','唐','御定全唐诗','yuding','','[]','謝安致理逾三載，黃霸清聲徹九重。猶輟佩環歸鳳闕，',40,'御定全唐詩/json/547.json','["謝安致理逾三載，黃霸清聲徹九重。猶輟佩環歸鳳闕，", "共喜甘棠有新詠，獨慚霜鬢又攀龍。"]'),
('yuding-23','贈鞏疇','鄭熏','唐','御定全唐诗','yuding','','[]','密雪松桂寒，書窗導餘清。風撼冰玉碎，階前琴磬聲。',240,'御定全唐詩/json/547.json','["密雪松桂寒，書窗導餘清。風撼冰玉碎，階前琴磬聲。", "榻靜幾硯潔，帙散縑緗明。高論展僧肇，精言資鞏生。", "立意加玄虛，析理分縱橫。萬化悉在我，一物安能驚。", "江海何所動，丘山常自平。遲速不相閡，後先徒起爭。", "鏡照分妍醜，秤稱分重輕。顏容寧入鑒，銖兩豈關衡。", "蘊微道超忽，剖鐙音泠泠。紙上掣牢鍵，舌端搖利兵。", "圓澈保直性，客塵排妄情。有住即非住，無行即是行。", "疏越舍朱弦，哇淫鄙秦箏。淡薄貴無味，羊斟慚大羹。", "洪遠包乾坤，幽窅潛沈冥。罔煩跬步舉，頓達萬里程。", "廬遠尚莫曉，隱留曾誤聽。直須持妙說，共詣毗耶城。"]'),
('yuding-24','句','鄭熏','唐','御定全唐诗','yuding','','[]','項斯逢水部，誰道不關情。',12,'御定全唐詩/json/547.json','["項斯逢水部，誰道不關情。"]'),
('yuding-0','鑷白曲','薛逢','唐','御定全唐诗','yuding','','[]','去年鑷白鬢，鏡裏猶堪認年少。今年鑷白髮，',140,'御定全唐詩/json/548.json','["去年鑷白鬢，鏡裏猶堪認年少。今年鑷白髮，", "少年曾讀古人書，本期獨善安有餘。雖蓋長安一片瓦，", "妻兒骨肉愁欲來，偏梁閣道歸得否？長安六月塵亙天，", "到官只是推誠信，終日兢兢幸無吝。丞相知憐為小心，", "山妻稚女悉迎到，時列綠樽酣酒歌。醉來便向樽前倒，", "五年老，知奈何？來日少，去日多。金錘錘碎黃金鑷，"]'),
('yuding-1','君不見','薛逢','唐','御定全唐诗','yuding','','[]','君不見，馬侍中，氣吞河朔稱英雄；君不見，韋太尉，',96,'御定全唐詩/json/548.json','["君不見，馬侍中，氣吞河朔稱英雄；君不見，韋太尉，", "奉誠園裏蒿棘生，長興街南沙路平。當時帶礪在何處，", "清明縱便天使來，一把紙錢風樹杪。碑文半缺碑堂摧，", "馬侍中，韋太尉，盛去衰來片時事。人生倏忽一夢中，"]'),
('yuding-2','老去也','薛逢','唐','御定全唐诗','yuding','','[]','惆悵人生不滿百，一事無成頭雪白。回看幼累與老妻，',72,'御定全唐詩/json/548.json','["惆悵人生不滿百，一事無成頭雪白。回看幼累與老妻，", "朝巾暮櫛不自省，老皮皴皺文縱橫。合掌髻子蒜許大，", "老去也，爭奈何？敲酒盞，唱短歌。短歌未竟日已沒，"]'),
('yuding-3','追昔行','薛逢','唐','御定全唐诗','yuding','','[]','朝光如飛猶尚可，暮更如箭不容臥。犍為穿城更漏頻，',144,'御定全唐詩/json/548.json','["朝光如飛猶尚可，暮更如箭不容臥。犍為穿城更漏頻，", "青春枉向鏡中老，白髮虛從愁裏生。曾窺帝裏東鄰女，", "去時只作旦暮期，別後生死俱不知。風驚粉色入蟬鬢，", "日中扶杖憩樹陰，仿佛形容認相識。向予籲嗟還獨語，", "花開葉落何推遷，屈指數當三十年。眉頭薤葉同枯葉，", "夢裏長嗟離別多，愁中不覺顏容改。歎息人生能幾何，"]'),
('yuding-4','醉春風','薛逢','唐','御定全唐诗','yuding','','[]','去年春似今年春，依舊野花愁殺人。犍為縣裏古城上，',120,'御定全唐詩/json/548.json','["去年春似今年春，依舊野花愁殺人。犍為縣裏古城上，", "時節先從暖處開，北枝未發南枝晚。江城太守須髯蒼，", "頃年曾作東周掾，同舍尋春屢開宴。斗門亭上柳如絲，", "坐客爭吟雲碧句，美人醉贈珊瑚釵。日往月來何草草，", "為報時人知不知，看花對酒定無疑。君看野外孤墳下，"]'),
('yuding-5','鄰相反行','薛逢','唐','御定全唐诗','yuding','','[]','東家有兒年十五，只向田園獨辛苦。夜開溝水繞稻田，',168,'御定全唐詩/json/548.json','["東家有兒年十五，只向田園獨辛苦。夜開溝水繞稻田，", "涉書獵史無早暮，坐期朱紫如拾青。東家西家兩相誚，", "東家自雲雖苦辛，躬耕早暮及所親。男舂女爨二十載，", "春秋伏臘長在家，不許妻奴暫違禮。爾今二十方讀書，", "縱令得官身須老，銜恤終天向誰道？百年骨肉歸下泉，", "面上笑添今日喜，肩頭薪續廚中煙。縱使此身頭雪白，", "為報西家知不知，何須謾笑東家兒。生前不得供甘滑，"]'),
('yuding-6','靈台家兄古鏡歌','薛逢','唐','御定全唐诗','yuding','','[]','一尺圓潭深黑色，篆文如絲人不識。耕夫雲住赫連城，',120,'御定全唐詩/json/548.json','["一尺圓潭深黑色，篆文如絲人不識。耕夫雲住赫連城，", "金膏洗拭鉎澀盡，黑雲吐出新蟾蜍。人言此是千年物，", "有時霹靂半夜驚，窗中飛電如晦明。盤龍鱗脹玉匣溢，", "十千賣與靈台兄，百丈靈湫坐中至。溢匣水色如玉傾，", "吾兄吾兄須愛惜，將來慎勿虛拋擲。興雲致雨會有時，"]'),
('yuding-7','觀競渡','薛逢','唐','御定全唐诗','yuding','','[]','三月三日天清明，楊花繞江啼曉鶯。使君未出郡齋內，',120,'御定全唐詩/json/548.json','["三月三日天清明，楊花繞江啼曉鶯。使君未出郡齋內，", "兩岸羅衣破鼻香，銀釵照日如霜刃。鼓聲三下紅旗開，", "雷聲沖急波相近，兩龍望標目如瞬。江上人呼霹靂聲，", "瘡眉血首爭不定，輸岸一朋心似燒。只將標示輸贏賞，", "吾今細觀競渡兒，何殊當路權相持。不思得所各休去，"]'),
('yuding-8','酬牛秀才登樓見示','薛逢','唐','御定全唐诗','yuding','','[]','旅館再經秋，心煩懶上樓。年光同過隙，人事且隨流。',48,'御定全唐詩/json/548.json','["旅館再經秋，心煩懶上樓。年光同過隙，人事且隨流。", "骨肉憑書問，鄉關托夢遊。所嗟山郡酒，傾盡只添憂。"]'),
('yuding-9','夏夜宴明月湖','薛逢','唐','御定全唐诗','yuding','','[]','夏夜宴南湖，琴觴興不孤。月搖天上桂，星泛浦中珠。',48,'御定全唐詩/json/548.json','["夏夜宴南湖，琴觴興不孤。月搖天上桂，星泛浦中珠。", "助照螢隨舫，添盤筍迸廚。聖朝思靜默，堪守穀中愚。"]'),
('yuding-10','大水','薛逢','唐','御定全唐诗','yuding','','[]','暴雨逐驚雷，從風忽驟來。浪驅三島至，江拆二儀開。',48,'御定全唐詩/json/548.json','["暴雨逐驚雷，從風忽驟來。浪驅三島至，江拆二儀開。", "勢恐圓樞折，聲疑厚軸摧。冥心問元化，天眼幾時回。"]'),
('yuding-11','席上酬東川嚴中丞敘舊見贈','薛逢','唐','御定全唐诗','yuding','','[]','昔記披雲日，今逾二十年。聲名俱是夢，恩舊半歸泉。',48,'御定全唐詩/json/548.json','["昔記披雲日，今逾二十年。聲名俱是夢，恩舊半歸泉。", "朱紱慚衰齒，紅妝慘別筵。離歌正淒切，休更促危弦。"]'),
('yuding-12','禁火','薛逢','唐','御定全唐诗','yuding','','[]','日日冒煙塵，忽忽禁火辰。塞榆關水濕，邊草賊回春。',48,'御定全唐詩/json/548.json','["日日冒煙塵，忽忽禁火辰。塞榆關水濕，邊草賊回春。", "歲月傷風邁，瘡痍念苦辛。沙中看白骨，腸斷故鄉人。"]'),
('yuding-13','詠柳','薛逢','唐','御定全唐诗','yuding','','[]','弱植驚風急自傷，暮來翻遣思悠揚。曾飄紫陌隨高下，',40,'御定全唐詩/json/548.json','["弱植驚風急自傷，暮來翻遣思悠揚。曾飄紫陌隨高下，", "莫令岐路頻攀折，漸擬垂陰到畫堂。"]'),
('yuding-14','宮詞','薛逢','唐','御定全唐诗','yuding','','[]','十二樓中盡曉妝，望仙樓上望君王。鎖銜金獸連環冷，',40,'御定全唐詩/json/548.json','["十二樓中盡曉妝，望仙樓上望君王。鎖銜金獸連環冷，", "遙窺正殿簾開處，袍袴宮人掃禦床。"]'),
('yuding-15','長安春日','薛逢','唐','御定全唐诗','yuding','','[]','窮途日日困泥沙，上苑年年好物華。荊棘不當車馬道，',40,'御定全唐詩/json/548.json','["窮途日日困泥沙，上苑年年好物華。荊棘不當車馬道，", "懶出任從遊子笑，入門還是舊生涯。"]'),
('yuding-16','韋壽博書齋','薛逢','唐','御定全唐诗','yuding','','[]','玄晏先生已白頭，不隨鵷鷺狎群鷗。元卿謝免開三徑，',40,'御定全唐詩/json/548.json','["玄晏先生已白頭，不隨鵷鷺狎群鷗。元卿謝免開三徑，", "塵纓未濯今如此，野水無情處處流。"]'),
('yuding-17','潼關河亭','薛逢','唐','御定全唐诗','yuding','','[]','重岡如抱嶽如蹲，屈曲秦川勢自尊。天地並功開帝宅，',40,'御定全唐詩/json/548.json','["重岡如抱嶽如蹲，屈曲秦川勢自尊。天地並功開帝宅，", "滿眼波濤終古事，年來惆悵與誰論。"]'),
('yuding-18','送衢州崔員外','薛逢','唐','御定全唐诗','yuding','','[]','笑分銅虎別京師，嶺下山川想到時。紅樹暗藏殷浩宅，',40,'御定全唐詩/json/548.json','["笑分銅虎別京師，嶺下山川想到時。紅樹暗藏殷浩宅，", "休指岩西數歸日，知君已負白雲期。"]'),
('yuding-19','開元後樂','薛逢','唐','御定全唐诗','yuding','','[]','莫奏開元舊樂章，樂中歌曲斷人腸。邠王玉笛三更咽，',40,'御定全唐詩/json/548.json','["莫奏開元舊樂章，樂中歌曲斷人腸。邠王玉笛三更咽，", "中原駿馬搜求盡，沙苑年來草又芳。"]'),
('yuding-20','漢武宮辭','薛逢','唐','御定全唐诗','yuding','','[]','漢武清齋夜築壇，自斟明水醮仙官。殿前玉女移香案，',40,'御定全唐詩/json/548.json','["漢武清齋夜築壇，自斟明水醮仙官。殿前玉女移香案，", "茂陵煙雨埋弓劍，石馬無聲蔓草寒。"]'),
('yuding-21','潼關驛亭','薛逢','唐','御定全唐诗','yuding','','[]','河上關門日日開，古今名利旋堪哀。終軍壯節埋黃土，',40,'御定全唐詩/json/548.json','["河上關門日日開，古今名利旋堪哀。終軍壯節埋黃土，", "猶驚往歲同袍者，尚逐江東計吏來。"]'),
('yuding-22','五峰隱者','薛逢','唐','御定全唐诗','yuding','','[]','煙霞壁立水溶溶，路轉崖回旦暮中。鸂鶒畏人沈澗月，',40,'御定全唐詩/json/548.json','["煙霞壁立水溶溶，路轉崖回旦暮中。鸂鶒畏人沈澗月，", "今日見君嘉遁處，悔將名利役疏慵。"]'),
('yuding-23','上吏部崔相公','薛逢','唐','御定全唐诗','yuding','','[]','龍門曾共戰驚瀾，雷電浮雲出浚湍。紫府有名同羽化，',40,'御定全唐詩/json/548.json','["龍門曾共戰驚瀾，雷電浮雲出浚湍。紫府有名同羽化，", "今日壚錘任真宰，暫回風水不應難。"]'),
('yuding-24','送劉郎中牧杭州','薛逢','唐','御定全唐诗','yuding','','[]','一州橫制浙江灣，台榭參差積翠間。樓下潮回滄海浪，',40,'御定全唐詩/json/548.json','["一州橫制浙江灣，台榭參差積翠間。樓下潮回滄海浪，", "聖代牧人無遠近，好將能事濟清閒。"]'),
('yuding-25','貧女吟','薛逢','唐','御定全唐诗','yuding','','[]','殘妝滿面淚闌幹，幾許幽情欲話難。雲髻懶梳愁拆鳳，',40,'御定全唐詩/json/548.json','["殘妝滿面淚闌幹，幾許幽情欲話難。雲髻懶梳愁拆鳳，", "惟有深閨憔悴質，年年長憑繡床看。"]'),
('yuding-26','夜宴觀妓','薛逢','唐','御定全唐诗','yuding','','[]','燈火熒煌醉客豪，捲簾羅綺豔仙桃。纖腰怕束金蟬斷，',40,'御定全唐詩/json/548.json','["燈火熒煌醉客豪，捲簾羅綺豔仙桃。纖腰怕束金蟬斷，", "無因得薦陽臺夢，願拂餘香到縕袍。"]'),
('yuding-27','送西川杜司空赴鎮','薛逢','唐','御定全唐诗','yuding','','[]','黑眉玄發尚依然，紫綬金章五十年。三入鳳池操國柄，',40,'御定全唐詩/json/548.json','["黑眉玄發尚依然，紫綬金章五十年。三入鳳池操國柄，", "莫遣洪壚曠真宰，九流人物待陶甄。"]'),
('yuding-28','長安夜雨','薛逢','唐','御定全唐诗','yuding','','[]','滯雨通宵又徹明，百憂如草雨中生。心關桂玉天難曉，',40,'御定全唐詩/json/548.json','["滯雨通宵又徹明，百憂如草雨中生。心關桂玉天難曉，", "當年志氣俱消盡，白髮新添四五莖。"]'),
('yuding-29','獵騎','薛逢','唐','御定全唐诗','yuding','','[]','兵印長封入衛稀，碧空雲盡早霜微。滻川桑落雕初下，',40,'御定全唐詩/json/548.json','["兵印長封入衛稀，碧空雲盡早霜微。滻川桑落雕初下，", "豈知萬里黃雲戍，血迸金瘡臥鐵衣。"]'),
('yuding-30','金城宮','薛逢','唐','御定全唐诗','yuding','','[]','憶昔明皇初禦天，玉輿頻此駐神仙。龍盤藻井噴紅豔，',40,'御定全唐詩/json/548.json','["憶昔明皇初禦天，玉輿頻此駐神仙。龍盤藻井噴紅豔，", "自從戎馬生河雒，深鎖蓬萊一百年。"]'),
('yuding-31','驚秋','薛逢','唐','御定全唐诗','yuding','','[]','露竹風蟬昨夜秋，百年心事付東流。明霜義分成虛話，',40,'御定全唐詩/json/548.json','["露竹風蟬昨夜秋，百年心事付東流。明霜義分成虛話，", "五湖煙水盈歸夢，蘆荻花中一釣舟。"]'),
('yuding-32','六街塵','薛逢','唐','御定全唐诗','yuding','','[]','六街塵起鼓冬冬，馬足車輪在處通。百役並驅衣食內，',40,'御定全唐詩/json/548.json','["六街塵起鼓冬冬，馬足車輪在處通。百役並驅衣食內，", "名利到身無了日，不知今古旋成空。"]'),
('yuding-33','悼古','薛逢','唐','御定全唐诗','yuding','','[]','細推今古事堪愁，貴賤同歸土一丘。漢武玉堂人豈在，',40,'御定全唐詩/json/548.json','["細推今古事堪愁，貴賤同歸土一丘。漢武玉堂人豈在，", "閒事與時俱不了，且將身暫醉鄉遊。"]'),
('yuding-34','九華觀廢月池','薛逢','唐','御定全唐诗','yuding','','[]','曾發簫聲水檻前，夜蟾寒沼兩嬋娟。微波有恨終歸海，',40,'御定全唐詩/json/548.json','["曾發簫聲水檻前，夜蟾寒沼兩嬋娟。微波有恨終歸海，", "榮華不肯人間住，須讀莊生第一篇。"]'),
('yuding-35','社日遊開元觀','薛逢','唐','御定全唐诗','yuding','','[]','松柏當軒蔓桂籬，古壇衰草暮風吹。荒涼院宇無人到，',40,'御定全唐詩/json/548.json','["松柏當軒蔓桂籬，古壇衰草暮風吹。荒涼院宇無人到，", "因求天寶年中夢，故事分明載折碑。"]'),
('yuding-36','九日曲池游眺','薛逢','唐','御定全唐诗','yuding','','[]','陌上秋風動酒旗，江頭絲竹競相追。正當海晏河清日，',40,'御定全唐詩/json/548.json','["陌上秋風動酒旗，江頭絲竹競相追。正當海晏河清日，", "微臣幸忝頒堯曆，一望郊原愜所思。"]'),
('yuding-37','九日郡齋有感','薛逢','唐','御定全唐诗','yuding','','[]','白日貪長夜更長，百般無意更思量。三冬不見秦中雪，',40,'御定全唐詩/json/548.json','["白日貪長夜更長，百般無意更思量。三冬不見秦中雪，", "樓前野菊無多少，一雨重開一番黃。"]'),
('yuding-38','九日嘉州發軍亭即事','薛逢','唐','御定全唐诗','yuding','','[]','三江分注界平沙，何處雲山是我家。舞鶴洲中翻白浪，',40,'御定全唐詩/json/548.json','["三江分注界平沙，何處雲山是我家。舞鶴洲中翻白浪，", "向暮酒酣賓客散，水天狼藉變餘霞。"]'),
('yuding-39','九日雨中言懷','薛逢','唐','御定全唐诗','yuding','','[]','糕果盈前益自愁，那堪風雨滯刀州。單床冷席他鄉夢，',40,'御定全唐詩/json/548.json','["糕果盈前益自愁，那堪風雨滯刀州。單床冷席他鄉夢，", "潛將滿眼思家淚，灑寄長江東北流。"]'),
('yuding-40','題劍門先寄上西蜀杜司徒','薛逢','唐','御定全唐诗','yuding','','[]','峭壁橫空限一隅，劃開元氣建洪樞。梯航百貨通邦計，',40,'御定全唐詩/json/548.json','["峭壁橫空限一隅，劃開元氣建洪樞。梯航百貨通邦計，", "千年管鑰誰熔範，只自先天造化爐。"]'),
('yuding-41','八月初一駕幸延喜樓看冠帶降戎','薛逢','唐','御定全唐诗','yuding','','[]','城頭旭日照闌幹，城下降戎彩仗攢。九陌塵埃千騎合，',40,'御定全唐詩/json/548.json','["城頭旭日照闌幹，城下降戎彩仗攢。九陌塵埃千騎合，", "清水莫教波浪濁，從今赤嶺屬長安。"]'),
('yuding-42','送司徒相公赴闕','薛逢','唐','御定全唐诗','yuding','','[]','丞相銜恩赴闕時，錦城寒菊始離披。龍媒舊識朝天路，',40,'御定全唐詩/json/548.json','["丞相銜恩赴闕時，錦城寒菊始離披。龍媒舊識朝天路，", "莫愁中土無人識，自有明明聖主知。"]'),
('yuding-43','送靈州田尚書','薛逢','唐','御定全唐诗','yuding','','[]','陰風獵獵滿旗竿，白草颼颼劍氣攢。九姓羌渾隨漢節，',40,'御定全唐詩/json/548.json','["陰風獵獵滿旗竿，白草颼颼劍氣攢。九姓羌渾隨漢節，", "今日路傍誰不指，穰苴門戶慣登壇。"]'),
('yuding-44','座中走筆送前蕭使君','薛逢','唐','御定全唐诗','yuding','','[]','笙歌慘慘咽離筵，槐柳陰陰五月天。未學蘇秦榮佩印，',40,'御定全唐詩/json/548.json','["笙歌慘慘咽離筵，槐柳陰陰五月天。未學蘇秦榮佩印，", "自笑無成今老大，送君垂淚郭門前。"]'),
('yuding-45','重送徐州李從事商隱','薛逢','唐','御定全唐诗','yuding','','[]','曉乘征騎帶犀渠，醉別都門慘袂初。蓮府望高秦禦史，',40,'御定全唐詩/json/548.json','["曉乘征騎帶犀渠，醉別都門慘袂初。蓮府望高秦禦史，", "尺組掛身何用處，古來名利盡丘墟。"]'),
('yuding-46','醉中聞甘州','薛逢','唐','御定全唐诗','yuding','','[]','老聽笙歌亦解愁，醉中因遣合甘州。行追赤嶺千山外，',40,'御定全唐詩/json/548.json','["老聽笙歌亦解愁，醉中因遣合甘州。行追赤嶺千山外，", "左綿刺史心先死，淚滿朱弦催白頭。"]'),
('yuding-47','北亭醉後敘舊贈東川陳書記','薛逢','唐','御定全唐诗','yuding','','[]','二十年前事盡空，半隨波浪半隨風。謀身喜斷韓雞尾，',40,'御定全唐詩/json/548.json','["二十年前事盡空，半隨波浪半隨風。謀身喜斷韓雞尾，", "臨岐莫怪朱弦絕，曾是君家入爨桐。"]'),
('yuding-48','宣政殿前陪位觀冊順宗憲宗皇帝尊號','薛逢','唐','御定全唐诗','yuding','','[]','樓頭鐘鼓遞相催，曙色當衙曉仗開。孔雀扇分香案出，',40,'御定全唐詩/json/548.json','["樓頭鐘鼓遞相催，曙色當衙曉仗開。孔雀扇分香案出，", "盛禮永尊徽號畢，聖慈南面不勝哀。"]'),
('yuding-49','元日樓前觀仗','薛逢','唐','御定全唐诗','yuding','','[]','千門曙色鎖寒梅，五夜疏鐘曉箭催。寶馬占堤朝闕去，',80,'御定全唐詩/json/548.json','["千門曙色鎖寒梅，五夜疏鐘曉箭催。寶馬占堤朝闕去，", "更傍紫微瞻北斗，上林佳氣滿樓臺。", "曈曈初日照樓臺，漠漠祥雲雉扇開。星駐冕旒三殿曉，", "欲識普恩無遠近，萬方歡忭一聲雷。"]'),
('yuding-50','醉中看花因思去歲之任','薛逢','唐','御定全唐诗','yuding','','[]','去歲乘軺出上京，軍機旦暮促前程。狂花野草途中恨，',40,'御定全唐詩/json/548.json','["去歲乘軺出上京，軍機旦暮促前程。狂花野草途中恨，", "不辭醉伴諸年少，羞對紅妝白髮生。"]'),
('yuding-51','題白馬驛','薛逢','唐','御定全唐诗','yuding','','[]','晚麥芒幹風似秋，旅人方作蜀門遊。家林漸隔梁山遠，',40,'御定全唐詩/json/548.json','["晚麥芒幹風似秋，旅人方作蜀門遊。家林漸隔梁山遠，", "胸中憤氣文難遣，強指豐碑哭武侯。"]'),
('yuding-52','題籌筆驛','薛逢','唐','御定全唐诗','yuding','','[]','天地三分魏蜀吳，武侯倔起贊籲謨。身依豪傑傾心術，',40,'御定全唐詩/json/548.json','["天地三分魏蜀吳，武侯倔起贊籲謨。身依豪傑傾心術，", "出師表上留遺懇，猶自千年激壯夫。"]'),
('yuding-53','賀楊收作相','薛逢','唐','御定全唐诗','yuding','','[]','闕下憧憧車馬塵，沈浮相次宦遊身。須知金印朝天客，',40,'御定全唐詩/json/548.json','["闕下憧憧車馬塵，沈浮相次宦遊身。須知金印朝天客，", "立門不是趨時客，始向窮途學問津。"]'),
('yuding-54','元日田家','薛逢','唐','御定全唐诗','yuding','','[]','南村晴雪北村梅，樹裏茅簷曉盡開。蠻榼出門兒婦去，',40,'御定全唐詩/json/548.json','["南村晴雪北村梅，樹裏茅簷曉盡開。蠻榼出門兒婦去，", "長笑士林因宦別，一官輕是十年回。"]'),
('yuding-55','送慶上人歸湖州因寄道儒座主','薛逢','唐','御定全唐诗','yuding','','[]','上人今去白蘋洲，霅水苕溪我舊遊。夜雨暗江漁火出，',40,'御定全唐詩/json/548.json','["上人今去白蘋洲，霅水苕溪我舊遊。夜雨暗江漁火出，", "若見儒公憑寄語，數莖霜鬢已驚秋。"]'),
('yuding-56','早發剡山','薛逢','唐','御定全唐诗','yuding','','[]','正懷何謝俯長流，更覽餘封識嵊州。樹色老依官舍晚，',40,'御定全唐詩/json/548.json','["正懷何謝俯長流，更覽餘封識嵊州。樹色老依官舍晚，", "日暮不堪還上馬，蓼花風起路悠悠。"]');
